import { CommonModule } from '@angular/common';
import { HttpClient } from '@angular/common/http';
import { Component, ElementRef, HostListener, OnDestroy, OnInit, ViewChild } from '@angular/core';
import { FormsModule } from '@angular/forms';
import { MatButtonModule } from '@angular/material/button';
import { MatCardModule } from '@angular/material/card';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatIconModule } from '@angular/material/icon';
import { MatProgressSpinnerModule } from '@angular/material/progress-spinner';
import { MatSelectModule } from '@angular/material/select';
import { MatSlideToggleModule } from '@angular/material/slide-toggle';
import { MatSnackBar } from '@angular/material/snack-bar';
import { MatTooltipModule } from '@angular/material/tooltip';
import { interval, Observable, Subject } from 'rxjs';
import { switchMap, takeUntil } from 'rxjs/operators';

// UnityLoader 鎺ュ彛瀹氫箟
interface UnityLoaderStatic {
  instantiate(
    element: HTMLElement,
    buildUrl: string,
    options?: {
      onProgress?: (instance: UnityInstance, progress: number) => void;
      onError?: (error: Error) => void;
      onSuccess?: () => void;
      [key: string]: unknown;
    }
  ): UnityInstance;
}

// 澹版槑鍏ㄥ眬 Unity 鍙橀噺
declare const UnityLoader: UnityLoaderStatic;

// Unity瀹炰緥鎺ュ彛
interface UnityInstance {
  Quit(): void;
  SendMessage(gameObject: string, methodName: string, parameter?: string): void;
}

// 浼犳劅鍣ㄦ暟鎹帴鍙ninterface SensorData {
  [key: string]: unknown;
}

// 瀹為獙鏁版嵁鎺ュ彛
interface ExperimentData {
  id?: string;
  name?: string;
  status?: string;
  [key: string]: unknown;
}

/**
 * AR瀹為獙瀹ょ粍浠禱n * 璐熻矗鍔犺浇鍜岀鐞哢nity WebGL AR瀹為獙瀹ゅ簲鐢╘n */
@Component({
  selector: 'app-ar-lab',
  standalone: true,
  imports: [
    CommonModule,
    FormsModule,
    MatCardModule,
    MatButtonModule,
    MatIconModule,
    MatTooltipModule,
    MatProgressSpinnerModule,
    MatSelectModule,
    MatSlideToggleModule,
    MatFormFieldModule,
  ],
  templateUrl: './ar-lab.component.html',
  styleUrls: ['./ar-lab.component.scss'],
})
export class ARLabComponent implements OnInit, OnDestroy {
  @ViewChild('unityContainer') unityContainer!: ElementRef;

  // Unity瀹炰緥绠＄悊
  unityInstance: UnityInstance | null = null;
  isUnityLoaded = false;
  isLoading = true;
  errorMessage = '';

  // AR鐘舵€佹帶鍒禱n  isARSupported = false;
  isTracking = false;
  arStatusMessage = '';
  gpuAccelerationLevel: 'webgl2' | 'webgl1' | 'none' = 'none';
  gpuRendererInfo = '';

  // 纭欢杩炴帴鐘舵€乗n  hardwareConnected = false;
  connectionStatus = '鏈繛鎺?;
  availablePorts: string[] = [];
  selectedPort: string = '';

  // 瀹為獙鏁版嵁
  experimentData: ExperimentData[] = [];
  currentExperiment: ExperimentData | null = null;
  isExperimentRunning = false;

  // 浼犳劅鍣ㄦ暟鎹甛n  sensorData: SensorData = {};
  lastUpdateTime = Date.now();

  // 鍏ㄥ睆鐘舵€乗n  isFullscreen = false;

  // 缁勪欢鐢熷懡鍛ㄦ湡绠＄悊
  private destroy$ = new Subject<void>();

  constructor(
    private http: HttpClient,
    private snackBar: MatSnackBar
  ) {}

  ngOnInit(): void {
    this.checkARSupport();
    this.loadUnityApplication();
    this.startSensorDataPolling();
    this.setupFullscreenListener();
  }

  ngOnDestroy(): void {
    this.destroy$.next();
    this.destroy$.complete();

    // 娓呯悊 Unity瀹炰緥
    if (this.unityInstance) {
      this.unityInstance.Quit();
      this.unityInstance = null;
    }
  }

  /**
   * 妫€鏌R鏀寔鎯呭喌锛堝惈 GPU 鍔犻€熸娴嬪拰 WebGL2 闄嶇骇绛栫暐锛塡n   * PRD F-08 妗岄潰绔€傞厤锛欸PU 鍔犻€焅n   */
  private checkARSupport(): void {
    // 浼樺厛妫€娴?WebGL2锛圙PU 鍔犻€熸覆鏌擄級锛岄檷绾у埌 WebGL1
    const canvas = document.createElement('canvas');
    let gl: WebGL2RenderingContext | WebGLRenderingContext | null = canvas.getContext('webgl2');

    if (gl) {
      // WebGL2 鍙敤锛孏PU 鍔犻€熸敮鎸佹渶浣砛n      this.isARSupported = true;
      this.gpuAccelerationLevel = 'webgl2';
    } else {
      // 闄嶇骇鍒?WebGL1
      gl =
        canvas.getContext('webgl') ??
        (canvas.getContext('experimental-webgl') as WebGLRenderingContext | null);
      if (gl) {
        this.isARSupported = true;
        this.gpuAccelerationLevel = 'webgl1';
      } else {
        this.isARSupported = false;
        this.arStatusMessage = '鎮ㄧ殑娴忚鍣ㄤ笉鏀寔WebGL';
        return;
      }
    }

    // 妫€鏌?GPU 娓叉煋鍣ㄤ俊鎭紙璋冭瘯鐢級
    if (gl) {
      const debugInfo = gl.getExtension('WEBGL_debug_renderer_info');
      if (debugInfo) {
        const renderer = gl.getParameter(debugInfo.UNMASKED_RENDERER_WEBGL) as string;
        this.gpuRendererInfo = String(renderer);
      }
    }

    // 妫€鏌ユ憚鍍忓ご鏉冮檺
    if (navigator.mediaDevices?.getUserMedia) {
      navigator.mediaDevices
        .getUserMedia({ video: true })
        .then((stream) => {
          stream.getTracks().forEach((track) => track.stop());
          this.isARSupported = true;
          this.arStatusMessage = 'AR鍔熻兘鍙敤';
        })
        .catch(() => {
          this.isARSupported = false;
          this.arStatusMessage = '闇€瑕佹憚鍍忓ご鏉冮檺鎵嶈兘浣跨敤AR鍔熻兘';
        });
    } else {
      this.isARSupported = false;
      this.arStatusMessage = '鎮ㄧ殑娴忚鍣ㄤ笉鏀寔濯掍綋璁惧API';
    }
  }

  /**
   * 鍔犺浇 Unity WebGL 搴旂敤绋嬪簭
   */
  loadUnityApplication(): void {
    try {
      // 妫€鏌?UnityLoader 鏄惁鍙敤
      if (typeof UnityLoader === 'undefined') {
        this.errorMessage =
          'Unity WebGL 杩愯鏃舵湭鍔犺浇銆傝纭 Unity 鏋勫缓宸查儴缃插埌 /ar-lab/build/ 鐩綍銆?;
        this.isLoading = false;
        this.snackBar.open(this.errorMessage, '鍏抽棴', { duration: 5000 });
        return;
      }

      // Unity 鏋勫缓鏂囦欢璺緞
      const buildUrl = '/ar-lab/build/ARLabMain.json';

      // 鍒涘缓Unity瀹炰緥
      // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment, @typescript-eslint/no-unsafe-call, @typescript-eslint/no-unsafe-member-access
      this.unityInstance = UnityLoader.instantiate(
        this.unityContainer.nativeElement as HTMLElement,
        buildUrl,
        {
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          onProgress: (_instance: any, progress: number) => {
            this.handleUnityProgress(progress);
          },
          onError: (error: Error) => {
            this.handleUnityError(error);
          },
          onSuccess: () => {
            this.handleUnitySuccess();
          },
        }
      );
    } catch (error) {
      this.handleUnityError(error);
    }
  }

  /**
   * 澶勭悊Unity鍔犺浇杩涘害
   */
  private handleUnityProgress(progress: number): void {
    if (progress >= 1) {
      this.isLoading = false;
    }
  }

  /**
   * 澶勭悊Unity鍔犺浇鎴愬姛
   */
  private handleUnitySuccess(): void {
    this.isUnityLoaded = true;
    this.isLoading = false;
    this.snackBar.open('AR瀹為獙瀹ゅ姞杞芥垚鍔?, '鍏抽棴', { duration: 3000 });
  }

  /**
   * 澶勭悊 Unity 鍔犺浇閿欒
   */
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  private handleUnityError(error: any): void {
    // eslint-disable-next-line @typescript-eslint/no-unsafe-member-access
    this.errorMessage = `Unity 鍔犺浇澶辫触锛?{error.message ?? error}`;
    this.isLoading = false;
    this.snackBar.open(this.errorMessage, '鍏抽棴', { duration: 5000 });
  }

  /**
   * 寮€濮嬩紶鎰熷櫒鏁版嵁杞
   */
  private startSensorDataPolling(): void {
    interval(1000) // 姣忕鏇存柊涓€娆n      .pipe(
        takeUntil(this.destroy$),
        switchMap(() => this.fetchSensorData())
      )
      .subscribe({
        next: (data) => {
          // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment
          this.sensorData = data;
          this.lastUpdateTime = Date.now();
        },
        error: (_error) => {},
      });
  }

  /**
   * 鑾峰彇浼犳劅鍣ㄦ暟鎹甛n   */
  private fetchSensorData(): Observable<SensorData> {
    return this.http.get<SensorData>('/api/v1/sensor-data/latest');
  }

  /**
   * 鎼滅储鍙敤鐨勪覆鍙ｈ澶嘰n   */
  searchHardwareDevices(): void {
    this.http.get<string[]>('/api/v1/hardware/ports').subscribe({
      next: (ports) => {
        this.availablePorts = ports;
        this.snackBar.open(`鍙戠幇 ${ports.length} 涓彲鐢ㄨ澶嘸, '鍏抽棴', { duration: 2000 });
      },
      error: (_error) => {
        this.snackBar.open('璁惧鎼滅储澶辫触', '鍏抽棴', { duration: 3000 });
      },
    });
  }

  /**
   * 杩炴帴纭欢璁惧
   */
  connectHardware(port: string): void {
    this.http
      .post<{ connected: boolean; message?: string }>('/api/v1/hardware/connect', { port })
      .subscribe({
        next: (response) => {
          if (response && typeof response.connected === 'boolean') {
            this.hardwareConnected = response.connected;
            this.connectionStatus = response.connected ? '宸茶繛鎺? : '杩炴帴澶辫触';
            this.snackBar.open(response.connected ? '纭欢杩炴帴鎴愬姛' : '纭欢杩炴帴澶辫触', '鍏抽棴', {
              duration: 3000,
            });
          }
        },
        error: (_error) => {
          this.connectionStatus = '杩炴帴閿欒';
          this.snackBar.open('杩炴帴杩囩▼涓彂鐢熼敊璇?, '鍏抽棴', { duration: 3000 });
        },
      });
  }

  /**
   * 鏂紑纭欢杩炴帴
   */
  disconnectHardware(): void {
    this.http.post('/api/v1/hardware/disconnect', {}).subscribe({
      next: () => {
        this.hardwareConnected = false;
        this.connectionStatus = '鏈繛鎺?;
        this.snackBar.open('纭欢宸叉柇寮€杩炴帴', '鍏抽棴', { duration: 2000 });
      },
      error: (_error) => {},
    });
  }

  /**
   * 寮€濮嬪疄楠孿n   */
  startExperiment(): void {
    if (!this.hardwareConnected) {
      this.snackBar.open('璇峰厛杩炴帴纭欢璁惧', '鍏抽棴', { duration: 3000 });
      return;
    }

    this.http.post('/api/v1/experiments/start', {}).subscribe({
      // eslint-disable-next-line @typescript-eslint/no-explicit-any, @typescript-eslint/no-unsafe-assignment
      next: (experiment: any) => {
        // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment
        this.currentExperiment = experiment;
        this.isExperimentRunning = true;
        this.snackBar.open('瀹為獙寮€濮?, '鍏抽棴', { duration: 2000 });
      },
      error: (_error) => {
        this.snackBar.open('瀹為獙鍚姩澶辫触', '鍏抽棴', { duration: 3000 });
      },
    });
  }

  /**
   * 鍋滄瀹為獙
   */
  stopExperiment(): void {
    this.http.post('/api/v1/experiments/stop', {}).subscribe({
      next: () => {
        this.isExperimentRunning = false;
        this.currentExperiment = null;
        this.snackBar.open('瀹為獙宸插仠姝?, '鍏抽棴', { duration: 2000 });
      },
      error: (_error) => {},
    });
  }

  /**
   * 閲嶇疆 AR 鍦烘櫙
   */
  resetARScene(): void {
    if (this.unityInstance) {
      // eslint-disable-next-line @typescript-eslint/no-unsafe-member-access, @typescript-eslint/no-unsafe-call
      this.unityInstance.SendMessage('ARManager', 'ResetScene');
      this.snackBar.open('AR 鍦烘櫙宸查噸缃?, '鍏抽棴', { duration: 2000 });
    }
  }

  /**
   * 鍒囨崲AR璺熻釜妯″紡
   */
  toggleARTracking(): void {
    this.isTracking = !this.isTracking;
    if (this.unityInstance) {
      // eslint-disable-next-line @typescript-eslint/no-unsafe-member-access, @typescript-eslint/no-unsafe-call
      this.unityInstance.SendMessage('ARManager', 'ToggleTracking', this.isTracking.toString());
    }
    this.snackBar.open(this.isTracking ? 'AR 璺熻釜宸插惎鐢? : 'AR 璺熻釜宸茬鐢?, '鍏抽棴', {
      duration: 2000,
    });
  }

  /**
   * 鐩戝惉鍏ㄥ睆鍙樺寲浜嬩欢锛屽悓姝ョ姸鎬乗n   */
  private setupFullscreenListener(): void {
    document.addEventListener('fullscreenchange', () => {
      this.isFullscreen = !!document.fullscreenElement;
    });
  }

  /**
   * 閿洏蹇嵎閿鐞嗭紙F11 / F / Esc锛塡n   */
  @HostListener('document:keydown', ['$event'])
  handleKeyboardShortcut(event: KeyboardEvent): void {
    // F11 鈫?鍒囨崲鍏ㄥ睆
    if (event.key === 'F11') {
      event.preventDefault();
      this.toggleFullscreen();
      return;
    }

    // F 閿紙闈炶緭鍏ユ涓級鈫?鍒囨崲鍏ㄥ睆
    if (
      (event.key === 'f' || event.key === 'F') &&
      !(event.target instanceof HTMLInputElement || event.target instanceof HTMLTextAreaElement)
    ) {
      event.preventDefault();
      this.toggleFullscreen();
      return;
    }

    // Esc 閫€鍑哄叏灞忔椂鎻愮ず
    if (event.key === 'Escape' && document.fullscreenElement) {
      this.snackBar.open('宸查€€鍑哄叏灞忔ā寮?, '鍏抽棴', { duration: 1000 });
    }

    // Ctrl+Shift+R 閲嶇疆 AR 鍦烘櫙
    if (event.key === 'R' && event.ctrlKey && event.shiftKey) {
      event.preventDefault();
      this.resetARScene();
    }
  }

  /**
   * 鑾峰彇鐘舵€佷俊鎭痋n   */
  getStatusInfo(): {
    unityLoaded: boolean;
    arSupported: boolean;
    arTracking: boolean;
    hardwareConnected: boolean;
    experimentRunning: boolean;
    lastUpdate: number;
  } {
    return {
      unityLoaded: this.isUnityLoaded,
      arSupported: this.isARSupported,
      arTracking: this.isTracking,
      hardwareConnected: this.hardwareConnected,
      experimentRunning: this.isExperimentRunning,
      lastUpdate: this.lastUpdateTime,
    };
  }

  /**
   * 鑾峰彇浼犳劅鍣ㄦ暟鍊硷紙鐢ㄤ簬妯℃澘鏄剧ず锛塡n   */
  getSensorValue(key: string): number | null {
    const value = this.sensorData[key];
    return typeof value === 'number' ? value : null;
  }

  /**
   * 鑾峰彇瀹為獙寮€濮嬫椂闂达紙鐢ㄤ簬妯℃澘鏄剧ず锛塡n   */
  getExperimentStartTime(): number | null {
    if (!this.currentExperiment) return null;
    const startTime = this.currentExperiment['startTime'];
    return typeof startTime === 'number' ? startTime : null;
  }

  /**
   * 鍒囨崲鍏ㄥ睆妯″紡锛圓R瀹為獙瀹ゅぇ灞忛€傞厤锛塡n   */
  toggleFullscreen(): void {
    const container = document.querySelector('.ar-lab-container') as HTMLElement;
    if (!container) return;

    if (!document.fullscreenElement) {
      void container
        .requestFullscreen()
        .then(() => {
          this.isFullscreen = true;
          // AR浣撻獙閿佸畾妯睆
          if ((screen.orientation as unknown as { lock?: (o: string) => Promise<void> })?.lock) {
            void (screen.orientation as unknown as { lock: (o: string) => Promise<void> })
              .lock('landscape')
              .catch(() => {});
          }
          this.snackBar.open('鍏ㄥ睆妯″紡宸插惎鐢?(Esc 閫€鍑?', '鍏抽棴', { duration: 2000 });
        })
        .catch((err) => {
          console.warn('[AR Lab] 鍏ㄥ睆璇锋眰澶辫触:', err);
        });
    } else {
      void document.exitFullscreen().then(() => {
        this.isFullscreen = false;
        if ((screen.orientation as unknown as { unlock?: () => void })?.unlock) {
          (screen.orientation as unknown as { unlock: () => void }).unlock();
        }
      });
    }
  }
}

import { CommonModule } from '@angular/common';
import { Component, OnInit } from '@angular/core';
import { ActivatedRoute, Router, RouterModule } from '@angular/router';
import { catchError, finalize, of, switchMap } from 'rxjs';

import { AuthService } from '../../core/services/auth.service';

/** OAuth 鐘舵€佷俊鎭?*/
interface OAuthState {
  state: string;
  provider: string;
  redirectUrl?: string;
}

/**
 * OAuth 鍥炶皟澶勭悊缁勪欢
 *
 * 澶勭悊绗笁鏂圭櫥褰曠殑鍥炶皟锛歕n * 1. 浠?URL 鍙傛暟涓彁鍙?code 鍜?state
 * 2. 璋冪敤鍚庣 OAuth 鍥炶皟 API 瀹屾垚鐧诲綍
 * 3. 鏍规嵁缁撴灉璺宠浆鍒板搴旈〉闈n */
@Component({
  selector: 'app-oauth-callback',
  standalone: true,
  imports: [CommonModule, RouterModule],
  template: `
    <div class="oauth-callback-container">
      <div class="callback-card">
        <div *ngIf="loading" class="loading-state">
          <div class="spinner"></div>
          <h2>姝ｅ湪澶勭悊鐧诲綍...</h2>
          <p>璇风◢鍊欙紝姝ｅ湪瀹屾垚绗笁鏂硅处鍙风櫥褰?/p>
        </div>

        <div *ngIf="!loading && success" class="success-state">
          <div class="success-icon">&#10003;</div>
          <h2>鐧诲綍鎴愬姛锛?/h2>
          <p>鍗冲皢璺宠浆鍒伴椤?..</p>
        </div>

        <div *ngIf="!loading && error" class="error-state">
          <div class="error-icon">&#10007;</div>
          <h2>鐧诲綍澶辫触</h2>
          <p class="error-message">{{ errorMessage }}</p>
          <button class="retry-button" (click)="retry()">閲嶆柊灏濊瘯</button>
          <a class="back-link" routerLink="/auth/login">杩斿洖鐧诲綍椤?/a>
        </div>
      </div>
    </div>
  `,
  styles: [
    `
      .oauth-callback-container {
        min-height: 100vh;
        display: flex;
        align-items: center;
        justify-content: center;
        background: linear-gradient(135deg, #3b82f6 0%, #2563eb 100%);
        padding: 16px;
      }

      .callback-card {
        background: white;
        border-radius: 16px;
        padding: 48px;
        width: 100%;
        max-width: 400px;
        text-align: center;
        box-shadow: 0 20px 60px rgba(0, 0, 0, 0.15);
      }

      .spinner {
        width: 48px;
        height: 48px;
        border: 4px solid #e0e0e0;
        border-top-color: #3b82f6;
        border-radius: 50%;
        animation: spin 0.8s linear infinite;
        margin: 0 auto 24px;
      }

      @keyframes spin {
        to {
          transform: rotate(360deg);
        }
      }

      .loading-state h2,
      .success-state h2,
      .error-state h2 {
        font-size: 22px;
        margin-bottom: 8px;
        color: #1d1d1f;
      }

      .loading-state p,
      .success-state p {
        color: #86868b;
        font-size: 14px;
      }

      .success-icon {
        width: 56px;
        height: 56px;
        background: #34c759;
        color: white;
        border-radius: 50%;
        display: flex;
        align-items: center;
        justify-content: center;
        font-size: 28px;
        margin: 0 auto 20px;
      }

      .error-icon {
        width: 56px;
        height: 56px;
        background: #ff3b30;
        color: white;
        border-radius: 50%;
        display: flex;
        align-items: center;
        justify-content: center;
        font-size: 28px;
