export class OAuthCallbackComponent implements OnInit {
  loading = true;
  success = false;
  error = false;
  errorMessage = '';

  constructor(
    private route: ActivatedRoute,
    private router: Router,
    private authService: AuthService
  ) {}

  ngOnInit(): void {
    this.processCallback();
  }

  private processCallback(): void {
    // 浠?URL 鍙傛暟涓彁鍙?code 鍜?state
    const code = this.route.snapshot.queryParamMap.get('code');
    const state = this.route.snapshot.queryParamMap.get('state');

    if (!code || !state) {
      this.loading = false;
      this.error = true;
      this.errorMessage = '缂哄皯鎺堟潈鍙傛暟锛坈ode 鎴?state锛?;
      return;
    }

    // 浠?sessionStorage 鑾峰彇瀛樺偍鐨?OAuth state 淇℃伅
    const storedState = sessionStorage.getItem('oauth_state');
    if (!storedState) {
      this.loading = false;
      this.error = true;
      this.errorMessage = 'OAuth 鐘舵€佸凡杩囨湡锛岃閲嶆柊鐧诲綍';
      return;
    }

    const oauthState = JSON.parse(storedState) as OAuthState;

    // 楠岃瘉 state 鍙傛暟锛堥槻 CSRF锛塡n    if (oauthState.state !== state) {
      this.loading = false;
      this.error = true;
      this.errorMessage = '瀹夊叏楠岃瘉澶辫触锛坰tate 涓嶅尮閰嶏級锛岃閲嶆柊鐧诲綍';
      sessionStorage.removeItem('oauth_state');
      return;
    }

    const provider = oauthState.provider;
    const redirectUri = `${window.location.origin}/auth/callback`;

    // 璋冪敤鍚庣 OAuth 鍥炶皟 API
    this.authService
      .handleOAuthCallback(provider, code, state, redirectUri)
      .pipe(
        switchMap(() => {
          // 娓呴櫎瀛樺偍鐨?OAuth 鐘舵€乗n          sessionStorage.removeItem('oauth_state');
          this.success = true;
          this.loading = false;
          // 寤惰繜鍚庤烦杞琝n          return of(null);
        }),
        catchError((err: Error) => {
          this.loading = false;
          this.error = true;
          this.errorMessage = err.message || 'OAuth 鐧诲綍澶辫触锛岃閲嶈瘯';
          return of(null);
        }),
        finalize(() => {
          // 3 绉掑悗璺宠浆
          setTimeout(() => {
            if (this.success) {
              const returnUrl = oauthState.redirectUrl ?? '/ai-edu';
              void this.router.navigateByUrl(returnUrl);
            }
          }, 3000);
        })
      )
      .subscribe();
  }

  retry(): void {
    window.location.href = '/auth/login';
  }
}

