    this.http
      .post<LearningPath>(`${this.apiBaseUrl}/generate`, requestData)
      .pipe(takeUntil(this.destroy$))
      .subscribe({
        next: (response) => {
          this.learningPath = response;
          this.updateChart(response);
          this.isLoading = false;
        },
        error: (error) => {
          console.error('鐢熸垚璺緞澶辫触:', error);
