import { CommonModule } from '@angular/common';
import {
  Component,
  ElementRef,
  Input,
  OnChanges,
  OnInit,
  SimpleChanges,
  ViewChild,
} from '@angular/core';
import { MatIconModule } from '@angular/material/icon';
import { MatProgressSpinnerModule } from '@angular/material/progress-spinner';
import * as echarts from 'echarts';

import { TokenService } from '../../core/services/token.service';
import { TokenTimeStats } from '../../models/token.models';

// ECharts 绫诲瀷瀹氫箟锛堝師鐢熷簱鏃犲畬鏁寸被鍨嬪０鏄庯級
interface ChartInstance {
  setOption(option: unknown): void;
  resize(): void;
  dispose(): void;
}

interface GradientStop {
  offset: number;
  color: string;
}

type LinearGradientConstructor = new (
  x: number,
  y: number,
  x2: number,
  y2: number,
  colorStops: GradientStop[]
) => unknown;

function createGradient(startColor: string, endColor: string): unknown {
  const graphic = echarts as { graphic?: Record<string, unknown> }['graphic'];
  const GradientCtor = (graphic as Record<string, unknown>)[
    'LinearGradient'
  ] as LinearGradientConstructor;
  return new GradientCtor(0, 0, 0, 1, [
    { offset: 0, color: startColor },
    { offset: 1, color: endColor },
  ]);
}

function initChartInstance(element: HTMLElement): ChartInstance {
  return (echarts as { init: (el: HTMLElement) => ChartInstance }).init(element);
}

@Component({
  selector: 'app-token-stats-chart',
  standalone: true,
  imports: [CommonModule, MatIconModule, MatProgressSpinnerModule],
  templateUrl: './token-stats-chart.component.html',
  styleUrls: ['./token-stats-chart.component.scss'],
})
export class TokenStatsChartComponent implements OnInit, OnChanges {
  @ViewChild('chart', { static: true }) chartElement!: ElementRef;

  /**
   * 寮€濮嬫棩鏈焅n   */
  @Input() startDate?: string;

  /**
   * 缁撴潫鏃ユ湡
   */
  @Input() endDate?: string;

  /**
   * 鍥捐〃绫诲瀷
   */
  @Input() chartType: 'line' | 'bar' = 'line';

  chartInstance: ChartInstance | null = null;
  loading = false;
  error: string | null = null;
  statsData: TokenTimeStats[] = [];

  constructor(private tokenService: TokenService) {}

  ngOnInit(): void {
    this.initChart();
    this.loadStats();
  }

  ngOnChanges(changes: SimpleChanges): void {
    if (
      (changes['startDate'] || changes['endDate'] || changes['chartType']) &&
      !changes['startDate'].firstChange
    ) {
      this.loadStats();
    }
  }

  /**
   * 鍒濆鍖栧浘琛╘n   */
  initChart(): void {
    this.chartInstance = initChartInstance(this.chartElement.nativeElement as HTMLElement);

    // 鍝嶅簲绐楀彛澶у皬鍙樺寲
    window.addEventListener('resize', () => {
      if (this.chartInstance) {
        this.chartInstance.resize();
      }
    });
  }

  /**
   * 鍔犺浇缁熻鏁版嵁
   */
  loadStats(): void {
    this.loading = true;
    this.error = null;

    const start = this.startDate ?? this.getDaysAgo(7);
    const end = this.endDate ?? new Date().toISOString().split('T')[0];

    this.tokenService.getTimeStats(start, end).subscribe({
      next: (data) => {
        this.statsData = data;
        this.updateChart();
        this.loading = false;
      },
      error: (error: Error) => {
        console.error('鍔犺浇缁熻鏁版嵁澶辫触:', error);
        this.error = error.message || '鍔犺浇鏁版嵁澶辫触';
        this.loading = false;
      },
    });
  }

  /**
   * 鏇存柊鍥捐〃
   */
  updateChart(): void {
    if (!this.chartInstance) return;

    const dates = this.statsData.map((item) => item.date);
    const consumedTokens = this.statsData.map((item) => item.consumed);
    const purchasedTokens = this.statsData.map((item) => item.purchased);

    const option = {
      tooltip: {
        trigger: 'axis',
        axisPointer: {
          type: 'shadow',
        },
      },
      legend: {
        data: ['娑堣垂', '鍏呭€?],
        top: 10,
      },
      grid: {
        left: '3%',
        right: '4%',
        bottom: '3%',
        containLabel: true,
      },
      xAxis: {
        type: 'category',
        data: dates,
        axisLabel: {
          rotate: 45,
          interval: 'auto',
        },
      },
      yAxis: {
        type: 'value',
        name: 'Token 鏁伴噺',
        axisLabel: {
          formatter: '{value}',
        },
      },
      series: [
        {
          name: '娑堣垂',
          type: this.chartType,
          data: consumedTokens,
          smooth: true,
          itemStyle: {
            color: '#ef4444',
          },
          areaStyle: {
            color: createGradient('rgba(239, 68, 68, 0.3)', 'rgba(239, 68, 68, 0.1)'),
          },
        },
        {
          name: '鍏呭€?,
          type: this.chartType,
          data: purchasedTokens,
          smooth: true,
          itemStyle: {
            color: '#10b981',
          },
          areaStyle: {
            color: createGradient('rgba(16, 185, 129, 0.3)', 'rgba(16, 185, 129, 0.1)'),
          },
        },
      ],
    };

    this.chartInstance.setOption(option);
  }

  /**
   * 鑾峰彇 N 澶╁墠鐨勬棩鏈焅n   */
  private getDaysAgo(days: number): string {
    const date = new Date();
    date.setDate(date.getDate() - days);
    return date.toISOString().split('T')[0];
  }

  /**
   * 鍒锋柊鍥捐〃
   */
  refresh(): void {
    this.loadStats();
  }

  /**
   * 鍒囨崲鍥捐〃绫诲瀷
   */
  toggleChartType(): void {
    this.chartType = this.chartType === 'line' ? 'bar' : 'line';
    this.updateChart();
  }

  ngOnDestroy(): void {
    if (this.chartInstance) {
      this.chartInstance.dispose();
    }
    window.removeEventListener('resize', () => {});
  }
}

import { HttpErrorResponse } from '@angular/common/http';
import { HttpClient } from '@angular/common/http';
import { ErrorHandler, Injectable, Injector } from '@angular/core';
import { Router } from '@angular/router';
import { BehaviorSubject } from 'rxjs';

import { AuthService } from '../auth.service';

/**
 * 閿欒绫诲瀷鏋氫妇
 */
export enum ErrorType {
  NETWORK = 'NETWORK', // 缃戠粶閿欒
  HTTP = 'HTTP', // HTTP 閿欒
  VALIDATION = 'VALIDATION', // 楠岃瘉閿欒
  AUTH = 'AUTH', // 璁よ瘉閿欒
  PERMISSION = 'PERMISSION', // 鏉冮檺閿欒
  NOT_FOUND = 'NOT_FOUND', // 璧勬簮涓嶅瓨鍦╘n  SERVER = 'SERVER', // 鏈嶅姟鍣ㄩ敊璇痋n  UNKNOWN = 'UNKNOWN', // 鏈煡閿欒
}

/**
 * 閿欒淇℃伅鎺ュ彛
 */
export interface AppError {
  type: ErrorType;
  message: string;
  code?: string;
  status?: number;
  url?: string;
  timestamp: number;
  details?: unknown;
}

/**
 * 閿欒鎻愮ず閰嶇疆
 */
export interface ErrorToastConfig {
  duration?: number; // 鏄剧ず鏃堕暱 (姣)
  position?: 'top' | 'bottom';
  dismissible?: boolean; // 鏄惁鍙墜鍔ㄥ叧闂璡n}

/**
 * 鍙В鏋愮殑閿欒瀵硅薄缁撴瀯
 */
interface ErrorPayload {
  error?: {
    type?: string;
    message?: string;
    code?: string;
    details?: unknown;
  };
  message?: string;
  code?: string;
  url?: string;
}

/**
 * AI-Edu 閿欒澶勭悊鏈嶅姟
 */
@Injectable({
  providedIn: 'root',
})
export class AIEduErrorHandlerService implements ErrorHandler {
  private router?: Router;
  private http?: HttpClient;

  // 褰撳墠閿欒鎻愮ず
  private currentToast: HTMLElement | null = null;

  // 閿欒鍘嗗彶
  private errorHistory: AppError[] = [];
  private readonly MAX_HISTORY = 50;

  // 閿欒閫氱煡涓婚
  private errorSubject = new BehaviorSubject<AppError | null>(null);
  public error$ = this.errorSubject.asObservable();

  // 鍏ㄥ眬閿欒寮€鍏砛n  private globalErrorEnabled = true;

  // 閿欒鏃ュ織鎵归噺涓婃姤閰嶇疆
  private readonly LOG_BATCH_SIZE = 10; // 鎵归噺涓婃姤闃堝€糪n  private readonly LOG_FLUSH_INTERVAL = 30000; // 30 绉掑畾鏃朵笂鎶n  private pendingLogs: AppError[] = [];
  private flushTimer?: ReturnType<typeof setInterval>;

  constructor(private injector: Injector) {
    setTimeout(() => {
      this.router = this.injector.get(Router);
      this.http = this.injector.get(HttpClient);
    }, 0);

    // 鍚姩瀹氭椂涓婃姤
    this.startFlushTimer();
  }

  /**
   * Angular 鍏ㄥ眬閿欒澶勭悊鍣╘n   */
  handleError(error: unknown): void {
    const appError = this.parseError(error);

    // 璁板綍閿欒鍘嗗彶
    this.recordError(appError);

    // 鍙戝竷閿欒閫氱煡
    this.errorSubject.next(appError);

    // 鏄剧ず閿欒鎻愮ず
    if (this.globalErrorEnabled) {
      this.showToast(appError);
    }

    // 鐗规畩閿欒澶勭悊
    this.handleSpecialCases(appError);
  }

  /**
   * 瑙ｆ瀽閿欒瀵硅薄
   */
  private parseError(error: unknown): AppError {
    const baseError: AppError = {
      type: ErrorType.UNKNOWN,
      message: '鍙戠敓鏈煡閿欒锛岃绋嶅悗閲嶈瘯',
      timestamp: Date.now(),
    };

    // 闈炲璞＄被鍨嬬洿鎺ヨ繑鍥瀄n    if (error === null || error === undefined || typeof error !== 'object') {
      return baseError;
    }

    const err = error as ErrorPayload;

    // HTTP 閿欒
    if (error instanceof HttpErrorResponse) {
      return this.parseHttpError(error);
    }

    // 宸茬煡鐨勯敊璇被鍨媆n    if (err.error?.type) {
      baseError.type = err.error.type as ErrorType;
    }

    if (err.error?.message) {
      baseError.message = err.error.message;
    } else if (err.message) {
      baseError.message = err.message;
    }

    if (err.code ?? err.error?.code) {
      baseError.code = err.code ?? err.error?.code;
    }

    if (err.url) {
      baseError.url = err.url;
    }

    if (err.error?.details) {
      baseError.details = err.error.details;
    }

    return baseError;
  }

  /**
   * 瑙ｆ瀽 HTTP 閿欒
   */
  private parseHttpError(error: HttpErrorResponse): AppError {
    const httpError: AppError = {
      type: ErrorType.HTTP,
      message: '',
      status: error.status,
      url: error.url ?? undefined,
      timestamp: Date.now(),
    };

    const errBody = error.error as { message?: string } | null | undefined;

    switch (error.status) {
      case 0:
        httpError.type = ErrorType.NETWORK;
        httpError.message = '缃戠粶杩炴帴澶辫触锛岃妫€鏌ョ綉缁滆缃?;
        break;

      case 400:
        httpError.type = ErrorType.VALIDATION;
        httpError.message = errBody?.message ?? '璇锋眰鍙傛暟閿欒';
        break;

      case 401:
        httpError.type = ErrorType.AUTH;
        httpError.message = '鏈巿鏉冿紝璇风櫥褰?;
        break;

      case 403:
        httpError.type = ErrorType.PERMISSION;
        httpError.message = '鏃犳潈璁块棶姝よ祫婧?;
        break;

      case 404:
        httpError.type = ErrorType.NOT_FOUND;
        httpError.message = '璇锋眰鐨勮祫婧愪笉瀛樺湪';
        break;

      case 500:
        httpError.type = ErrorType.SERVER;
        httpError.message = '鏈嶅姟鍣ㄥ唴閮ㄩ敊璇?;
        break;

      case 502:
      case 503:
      case 504:
        httpError.type = ErrorType.SERVER;
        httpError.message = '鏈嶅姟鏆傛椂涓嶅彲鐢紝璇风◢鍚庨噸璇?;
        break;

      default:
        httpError.message = errBody?.message ?? `HTTP 閿欒锛?{error.status}`;
    }

    return httpError;
  }

  /**
   * 璁板綍閿欒鍒板巻鍙瞈n   */
  private recordError(error: AppError): void {
    this.errorHistory.unshift(error);

    if (this.errorHistory.length > this.MAX_HISTORY) {
      this.errorHistory.pop();
    }

    // 鉁?鏂板锛氭坊鍔犲埌寰呬笂鎶ラ槦鍒梊n    this.queueLog(error);
  }

  /**
   * 灏嗛敊璇姞鍏ュ緟涓婃姤闃熷垪
   */
  private queueLog(error: AppError): void {
    this.pendingLogs.push(error);

    // 杈惧埌鎵归噺闃堝€兼椂绔嬪嵆涓婃姤
    if (this.pendingLogs.length >= this.LOG_BATCH_SIZE) {
      this.flushLogs();
    }
  }

  /**
   * 鍚姩瀹氭椂涓婃姤璁℃椂鍣╘n   */
  private startFlushTimer(): void {
    if (this.flushTimer) {
      clearInterval(this.flushTimer);
    }

    this.flushTimer = setInterval(() => {
      if (this.pendingLogs.length > 0) {
        this.flushLogs();
      }
    }, this.LOG_FLUSH_INTERVAL);
  }

  /**
   * 鎵归噺涓婃姤閿欒鏃ュ織
   */
  private flushLogs(): void {
    if (!this.http || this.pendingLogs.length === 0) {
      return;
    }

    const logsToSend = [...this.pendingLogs];
    this.pendingLogs = [];

    const API_BASE = 'http://localhost:8000/api/v1/org/1/logs';

    const currentUser = this.injector.get(AuthService).getCurrentUser();
    const userId = currentUser?.id ? Number(currentUser.id) : 1;
    const orgId = (currentUser as unknown as { org_id?: number })?.org_id ?? 1;

    this.http
      .post(`${API_BASE}/error`, {
        errors: logsToSend.map((err) => ({
          type: err.type,
          message: err.message,
          code: err.code,
          status: err.status,
          url: err.url,
          timestamp: new Date(err.timestamp).toISOString(),
          details: err.details as Record<string, unknown> | undefined,
        })),
        user_id: userId,
        org_id: orgId,
      })
      .subscribe({
        next: () => {
          console.warn(`鎴愬姛涓婃姤 ${logsToSend.length} 鏉￠敊璇棩蹇梎);
        },
        error: (error) => {
          console.error('鉂?閿欒鏃ュ織涓婃姤澶辫触:', error);
          // 涓婃姤澶辫触鏃跺皢鏃ュ織閲嶆柊鍔犲叆闃熷垪
          this.pendingLogs.unshift(...logsToSend);
        },
      });
  }

  /**
   * 鑾峰彇閿欒鍘嗗彶
   */
  getErrorHistory(): AppError[] {
    return [...this.errorHistory];
  }

  /**
   * 娓呴櫎閿欒鍘嗗彶
   */
  clearHistory(): void {
    this.errorHistory = [];
  }

  /**
   * 鏄剧ず閿欒鎻愮ず Toast
   */
  showToast(error: AppError | string, config: ErrorToastConfig = {}): void {
    const defaultConfig: Required<ErrorToastConfig> = {
      duration: 5000,
      position: 'top',
      dismissible: true,
    };

    const finalConfig = { ...defaultConfig, ...config };

    // 绉婚櫎鏃х殑鎻愮ず
    if (this.currentToast) {
      this.currentToast.remove();
    }

    const message = typeof error === 'string' ? error : error.message;
    const type = typeof error === 'string' ? ErrorType.UNKNOWN : error.type;

    // 鍒涘缓 Toast 鍏冪礌
    const toast = document.createElement('div');
    toast.className = `ai-edu-toast ai-edu-toast-${type}`;
    toast.innerHTML = `
      <div class="toast-content">
        <span class="toast-icon">${this.getErrorIcon(type)}</span>
        <span class="toast-message">${message}</span>
        ${finalConfig.dismissible ? '<button class="toast-close">脳</button>' : ''}
      </div>
      <div class="toast-progress"></div>
    `;

    // 娣诲姞鏍峰紡
    this.injectStyles();

    // 璁剧疆浣嶇疆
    toast.style.cssText = `
      position: fixed;
      ${finalConfig.position === 'top' ? 'top: 20px' : 'bottom: 20px'};
      left: 50%;
      transform: translateX(-50%);
      z-index: 10000;
      min-width: 300px;
      max-width: 600px;
      animation: slideIn 0.3s ease-out;
    `;

    // 鍏抽棴鎸夐挳浜嬩欢
    const closeBtn = toast.querySelector('.toast-close');
    if (closeBtn) {
      closeBtn.addEventListener('click', () => this.removeToast(toast));
    }

    // 娣诲姞鍒伴〉闈n    document.body.appendChild(toast);
    this.currentToast = toast;

    // 鑷姩鍏抽棴
    if (finalConfig.duration > 0) {
      setTimeout(() => this.removeToast(toast), finalConfig.duration);
    }
  }

  /**
   * 绉婚櫎 Toast
   */
  removeToast(toast: HTMLElement): void {
    if (!toast) return;

    toast.style.animation = 'slideOut 0.3s ease-out';
    setTimeout(() => {
      toast.remove();
      if (this.currentToast === toast) {
        this.currentToast = null;
      }
    }, 300);
  }

  /**
   * 娉ㄥ叆 CSS 鏍峰紡
   */
  private injectStyles(): void {
    const styleId = 'ai-edu-toast-styles';
    if (document.getElementById(styleId)) return;

    const style = document.createElement('style');
    style.id = styleId;
    style.textContent = `
      @keyframes slideIn {
        from {
          transform: translateX(-50%) translateY(-100%);
          opacity: 0;
        }
        to {
          transform: translateX(-50%) translateY(0);
          opacity: 1;
        }
      }

      @keyframes slideOut {
        from {
          transform: translateX(-50%) translateY(0);
          opacity: 1;
        }
        to {
          transform: translateX(-50%) translateY(-100%);
          opacity: 0;
        }
      }

      .ai-edu-toast {
        background: white;
        border-radius: 8px;
        box-shadow: 0 4px 20px rgba(0, 0, 0, 0.2);
        overflow: hidden;
      }

      .ai-edu-toast-NETWORK {
        border-left: 4px solid #ef4444;
      }

      .ai-edu-toast-HTTP {
        border-left: 4px solid #f59e0b;
      }

      .ai-edu-toast-VALIDATION {
        border-left: 4px solid #f59e0b;
      }

      .ai-edu-toast-AUTH {
        border-left: 4px solid #ef4444;
      }

      .ai-edu-toast-PERMISSION {
        border-left: 4px solid #f59e0b;
      }

      .ai-edu-toast-NOT_FOUND {
        border-left: 4px solid #3b82f6;
      }

      .ai-edu-toast-SERVER {
        border-left: 4px solid #ef4444;
      }

      .ai-edu-toast-UNKNOWN {
        border-left: 4px solid #94a3b8;
      }

      .toast-content {
        display: flex;
        align-items: center;
        padding: 15px 20px;
        gap: 12px;
      }

      .toast-icon {
        font-size: 20px;
      }

      .toast-message {
        flex: 1;
        font-size: 15px;
        color: #333;
      }

      .toast-close {
        background: none;
        border: none;
        font-size: 20px;
        cursor: pointer;
        color: #999;
        padding: 0;
        width: 24px;
        height: 24px;
        display: flex;
        align-items: center;
        justify-content: center;
        border-radius: 4px;
        transition: background 0.2s;
      }

      .toast-close:hover {
        background: #f5f5f5;
      }

      .toast-progress {
        height: 3px;
        background: linear-gradient(90deg, #3b82f6 0%, #2563eb 100%);
        animation: progress 5s linear;
      }
    `;

    document.head.appendChild(style);
  }

  /**
   * 鑾峰彇閿欒鍥炬爣
   */
  private getErrorIcon(type: ErrorType): string {
    const icons: { [key: string]: string } = {
      [ErrorType.NETWORK]: '馃寪',
      [ErrorType.HTTP]: '鈿狅笍',
      [ErrorType.VALIDATION]: '鉂?,
      [ErrorType.AUTH]: '馃敀',
      [ErrorType.PERMISSION]: '馃毇',
      [ErrorType.NOT_FOUND]: '馃攳',
      [ErrorType.SERVER]: '馃挜',
      [ErrorType.UNKNOWN]: '鈩癸笍',
    };
    return icons[type] || '鈩癸笍';
  }

  /**
   * 澶勭悊鐗规畩鎯呭喌
   */
  private handleSpecialCases(error: AppError): void {
    // 401 璺宠浆鍒扮櫥褰曢〉
    if (error.type === ErrorType.AUTH && this.router) {
      setTimeout(() => {
        void this.router?.navigate(['/login']);
      }, 2000);
    }

    // 鉁?涓ラ噸閿欒璁板綍鏃ュ織骞朵笂鎶n    if ([ErrorType.SERVER, ErrorType.NETWORK].includes(error.type)) {
