  // ==================== 瀛︿範鐢诲儚 ====================

  /** 鑾峰彇瀛︾敓瀛︿範鐢诲儚 */
  getProfile(userId: string): Observable<StudentLearningProfile> {
    return this.http.get<StudentLearningProfile>(`${this.API_BASE}/profile/${userId}`).pipe(
      tap((profile) => this.profileSubject.next(profile)),
      catchError(() => {
        // 闄嶇骇涓篗ock鏁版嵁
        const mockProfile = this.createMockProfile(userId);
        this.profileSubject.next(mockProfile);
        return of(mockProfile);
      })
    );
  }

  /** 鏇存柊瀛︿範鐢诲儚 */
  updateProfile(
    userId: string,
    update: LearningProfileUpdateRequest
  ): Observable<StudentLearningProfile> {
    return this.http
      .patch<StudentLearningProfile>(`${this.API_BASE}/profile/${userId}`, update)
      .pipe(
        tap((profile) => this.profileSubject.next(profile)),
        catchError(() => {
          // 鏈湴鏇存柊
          const current = this.profileSubject.value;
          if (current) {
            const updated = { ...current, ...update, updatedAt: new Date().toISOString() };
            this.profileSubject.next(updated as StudentLearningProfile);
            return of(updated as StudentLearningProfile);
          }
          return of(current!);
        })
      );
  }

  /** 鐢熸垚鐢诲儚鎽樿锛堜緵AI鏁欏笀prompt浣跨敤锛?*/
  generatePersonaSeed(profile: StudentLearningProfile): string {
    const styleMap: Record<LearningStyle, string> = {
      visual: '瑙嗚鍨?,
      auditory: '鍚鍨?,
      reading: '璇诲啓鍨?,
      kinesthetic: '鍔ㄨ鍨?,
    };
    const weakPointsStr = profile.weakPoints
      .slice(0, 3)
      .map((w) => `${w.knowledgePoint}(${Math.round(w.mastery * 100)}%)`)
      .join('銆?);

    return [
      `${profile.displayName}锛?{profile.gradeLevel}锛?{styleMap[profile.learningStyle]}瀛︿範鑰卄,
      `缂栫▼鎬濈淮${profile.abilityDimensions.programmingThinking}/100锛宍,
      `鐙珛瀹屾垚鐜?{profile.abilityDimensions.independentCompletion}%`,
      weakPointsStr ? `钖勫急鐜妭锛?{weakPointsStr}` : '',
      `杩炵画瀛︿範${profile.currentStreakDays}澶ー,
    ]
      .filter(Boolean)
      .join('銆?);
  }

  /** 娉ㄥ叆鎯呯华涓婁笅鏂囧埌鐢诲儚鎽樿 */
  private injectEmotionContext(seed: string): string {
    if (!this.emotionCompanion.companionModeEnabled) return seed;
    const emotion = this.emotionCompanion.currentEmotion;
    if (!emotion || emotion === 'neutral') return seed;
    const emoji = this.emotionCompanion.getEmotionEmoji(emotion);
    const label = this.emotionCompanion.getEmotionLabel(emotion);
