  // ==================== 瀛︿範璇婃柇寮曟搸锛堟湰鍦板垎鏋愶級====================

  /**
   * 鏈湴璇婃柇瀛︾敓瀛︿範闂锛堝綋API涓嶅彲鐢ㄦ椂闄嶇骇浣跨敤锛塡n   * 鍒嗘瀽鐢诲儚鍜岀煡璇嗙姸鎬侊紝鐢熸垚鏁欏寤鸿
   */
  diagnoseLearningIssues(
    profile: StudentLearningProfile,
    knowledgeState: KnowledgeStateItem[]
  ): TeachingSuggestion[] {
    const suggestions: TeachingSuggestion[] = [];

    // 1. 鍓嶇疆鐭ヨ瘑缂哄け妫€娴媆n    this.detectPrerequisiteGaps(knowledgeState).forEach((s) => suggestions.push(s));

    // 2. 姒傚康娣锋穯妫€娴嬶紙鏍规嵁閿欒妯″紡锛塡n    this.detectConceptConfusion(profile).forEach((s) => suggestions.push(s));

    // 3. 瀛︿範楂樺師鏈熸娴媆n    this.detectLearningPlateau(profile).forEach((s) => suggestions.push(s));

    // 4. 鑳藉姏涓嶅潎琛℃娴媆n    this.detectSkillImbalance(profile).forEach((s) => suggestions.push(s));

    // 5. 娉ㄦ剰鍔涗笅闄嶆娴媆n    this.detectAttentionDecline(profile).forEach((s) => suggestions.push(s));

    // 6. AI杩囧害渚濊禆妫€娴媆n    this.detectAIDependence(profile).forEach((s) => suggestions.push(s));

    return suggestions;
  }

  /** 妫€娴嬪墠缃煡璇嗙己澶?*/
  private detectPrerequisiteGaps(knowledgeState: KnowledgeStateItem[]): TeachingSuggestion[] {
    const results: TeachingSuggestion[] = [];
    for (const item of knowledgeState) {
      if (item.status === 'learning' && item.mastery < 0.5) {
        // 妫€鏌ュ墠缃煡璇嗘槸鍚︽帉鎻n        const missingPrereqs = item.prerequisites.filter((prereqId) => {
          const prereq = knowledgeState.find((k) => k.knowledgePoint === prereqId);
          return prereq && prereq.mastery < 0.7;
        });
        if (missingPrereqs.length > 0) {
          results.push({
            id: `diag_prereq_${item.knowledgePoint}_${Date.now()}`,
            diagnosisType: 'prerequisite_missing',
            severity: 'warning',
            title: `鍓嶇疆鐭ヨ瘑缂哄け锛?{item.knowledgePoint}`,
            description: `浣犳鍦ㄥ ${item.knowledgePoint}锛屼絾 ${missingPrereqs.join('銆?)} 杩樻病瀹屽叏鎺屾彙銆俙,
            suggestedAction: `鍏堝珐鍥?${missingPrereqs.join('銆?)} 鐨勫熀纭€鐭ヨ瘑锛屽啀缁х画瀛︿範 ${item.knowledgePoint}`,
            relatedKnowledgePoints: [...missingPrereqs, item.knowledgePoint],
            recommendedCourses: missingPrereqs.map((p) => `review_${p}`),
            createdAt: new Date().toISOString(),
            isRead: false,
          });
        }
      }
    }
    return results;
  }

  /** 妫€娴嬫蹇垫贩娣嗭紙鏍规嵁楂橀閿欒妯″紡锛?*/
  private detectConceptConfusion(profile: StudentLearningProfile): TeachingSuggestion[] {
    const results: TeachingSuggestion[] = [];

    // 鍒嗘瀽閿欒妯″紡锛屾壘鍑洪珮棰戦敊璇被鍨媆n    const errorEntries = Object.entries(profile.errorPatterns || {});
    if (errorEntries.length === 0) return results;

    // 鎸夐敊璇鏁版帓搴忥紝鍙栧墠2涓猏n    const topErrors = errorEntries.sort(([, a], [, b]) => b - a).slice(0, 2);

    const errorLabels: Record<string, string> = {
      indentation_error: '缂╄繘閿欒',
      range_parameter: 'range() 鍙傛暟娣锋穯',
      list_index: '鍒楄〃绱㈠紩瓒婄晫',
      type_error: '绫诲瀷閿欒',
      syntax_error: '璇硶閿欒',
    };

    for (const [errorType, count] of topErrors) {
      if (count >= 3) {
        results.push({
          id: `diag_confusion_${errorType}_${Date.now()}`,
          diagnosisType: 'concept_confusion',
          severity: count >= 10 ? 'critical' : 'info',
          title: `姒傚康娣锋穯锛?{errorLabels[errorType] || errorType}`,
          description: `浣犳渶杩戝嚭鐜颁簡 ${count} 娆?${errorLabels[errorType] || errorType}锛屼綘鍙兘瀵硅繖涓蹇电殑鐞嗚В杩樹笉澶熸墡瀹炪€俙,
          suggestedAction: `寤鸿鍋?${errorLabels[errorType] || errorType} 鐩稿叧鐨勪笓椤圭粌涔燻,
          relatedKnowledgePoints: [errorType],
          recommendedCourses: [`practice_${errorType}`],
          createdAt: new Date().toISOString(),
          isRead: false,
        });
      }
    }
    return results;
  }

  /** 妫€娴嬪涔犻珮鍘熸湡 */
  private detectLearningPlateau(profile: StudentLearningProfile): TeachingSuggestion[] {
    const results: TeachingSuggestion[] = [];

    // 妫€鏌ユ槸鍚︽湁鍦ㄥ鐨勭煡璇嗙偣杩涘害鍋滄粸锛? 3澶╂病鏈夎繘姝ワ級
    const learningSkills = Object.entries(profile.knowledgeMastery || {})
      .filter(([, mastery]) => mastery > 0 && mastery < 1)
      .sort(([, a], [, b]) => a - b);

    if (learningSkills.length > 0) {
      const slowest = learningSkills[0];
      if (slowest[1] < 0.3) {
        results.push({
          id: `diag_plateau_${Date.now()}`,
          diagnosisType: 'learning_plateau',
          severity: 'warning',
          title: `瀛︿範楂樺師鏈燂細${slowest[0]}`,
          description: `${slowest[0]} 鐨勮繘搴︿技涔庢湁浜涘仠婊烇紝鎺屾彙搴?${Math.round(slowest[1] * 100)}%`,
          suggestedAction: '鎹釜鏂瑰紡璇曡瘯锛佹崲涓涔犳柟寮忥紝鎴栬€呬紤鎭竴涓嬪啀鏉ユ寫鎴樸€?,
          relatedKnowledgePoints: [slowest[0]],
          recommendedCourses: [`alt_${slowest[0]}`],
          createdAt: new Date().toISOString(),
          isRead: false,
        });
      }
    }
    return results;
  }

  /** 妫€娴嬭兘鍔涗笉鍧囪　 */
  private detectSkillImbalance(profile: StudentLearningProfile): TeachingSuggestion[] {
    const results: TeachingSuggestion[] = [];
    const dims = profile.abilityDimensions;
    if (!dims) return results;

    const entries = Object.entries(dims) as Array<[string, number]>;
    const values = entries.map(([, v]) => v);
    const avg = values.reduce((a, b) => a + b, 0) / values.length;
    const threshold = 20;

    // 鎵惧嚭鏄庢樉浣庝簬骞冲潎鐨勭淮搴n    const weakDims = entries.filter(([key, val]) => {
      if (key === 'independentCompletion' || key === 'questionQuality') return false;
      return val < avg - threshold;
    });

    const strongDims = entries.filter(([key, val]) => {
      if (key === 'independentCompletion' || key === 'questionQuality') return false;
      return val > avg + threshold;
    });

    if (weakDims.length > 0 && strongDims.length > 0) {
      const dimLabels: Record<string, string> = {
        programmingThinking: '缂栫▼鎬濈淮',
        algorithmAbility: '绠楁硶鑳藉姏',
        debuggingSkill: '璋冭瘯鑳藉姏',
        projectPractice: '椤圭洰瀹炶返',
        stemExperiment: 'STEM瀹為獙',
        codeQuality: '浠ｇ爜瑙勮寖',
      };

      results.push({
        id: `diag_imbalance_${Date.now()}`,
        diagnosisType: 'skill_imbalance',
        severity: 'info',
        title: '鑳藉姏鍙戝睍涓嶅潎琛?,
        description: `浣犵殑 ${dimLabels[strongDims[0][0]] || strongDims[0][0]} 寰堝己锛屼絾 ${dimLabels[weakDims[0][0]] || weakDims[0][0]} 鐩稿杈冨急銆俙,
        suggestedAction: `鍙互澶氳姳鐐规椂闂村湪 ${dimLabels[weakDims[0][0]] || weakDims[0][0]} 涓婄殑缁冧範銆俙,
        relatedKnowledgePoints: weakDims.map(([k]) => k),
        recommendedCourses: [`enhance_${weakDims[0][0]}`],
        createdAt: new Date().toISOString(),
        isRead: false,
      });
    }
    return results;
  }

