  private progressSubject = new BehaviorSubject<MilestoneProgress[]>([]);
  public progress$ = this.progressSubject.asObservable();

  private statsSubject = new BehaviorSubject<MilestoneStats>({
    totalTemplates: 0,
    unlockedCount: 0,
    lockedCount: 0,
    recentUnlocks: [],
    nextPredictedMilestone: null,
    totalXPEarned: 0,
  });
  public stats$ = this.statsSubject.asObservable();

  constructor(private aiTeacher: AITeacherService) {}

  /** 鍔犺浇閲岀▼纰戣繘搴?*/
  loadProgress(userId: string): void {
    this.aiTeacher
      .getGrowthTrajectory(userId)
      .pipe(
        map((growth) => {
          const achieved = growth.milestones ?? [];
          const progress = this.milestoneTemplates.map((template) => {
            const isUnlocked = achieved.some((m) => m.type === template.id);
            const currentValue = this.estimateCurrentValue(template, growth);
            const targetValue = template.requirements.threshold;
            const pct = Math.min(100, Math.round((currentValue / targetValue) * 100));

            return {
              template,
              progress: isUnlocked ? 100 : pct,
              isUnlocked,
              unlockedAt: achieved.find((m) => m.type === template.id)?.achievedAt,
              currentValue,
              targetValue,
            } as MilestoneProgress;
          });

          this.progressSubject.next(progress);
          this.updateStats(progress, achieved);
        }),
        catchError(() => {
          // 浣跨敤榛樿杩涘害
          const progress = this.milestoneTemplates.map((t) => ({
            template: t,
            progress: 0,
            isUnlocked: false,
            currentValue: 0,
            targetValue: t.requirements.threshold,
          }));
          this.progressSubject.next(progress);
          return of(null);
        })
      )
      .subscribe();
  }

  /** 鑾峰彇寰呰В閿佺殑涓嬩竴閲岀▼纰?*/
  getNextMilestone(): MilestoneProgress | null {
    const list = this.progressSubject.getValue();
    return list.filter((m) => !m.isUnlocked).sort((a, b) => b.progress - a.progress)?.[0] ?? null;
  }

  /** 鎸夊垎绫昏幏鍙栭噷绋嬬 */
  getMilestonesByCategory(category: MilestoneCategory): MilestoneProgress[] {
    return this.progressSubject.getValue().filter((m) => m.template.category === category);
  }

  /** 鑾峰彇宸茶В閿侀噷绋嬬 */
  getUnlockedMilestones(): MilestoneProgress[] {
    return this.progressSubject.getValue().filter((m) => m.isUnlocked);
  }

  private updateStats(progress: MilestoneProgress[], achieved: LearningMilestone[]): void {
    const unlocked = progress.filter((m) => m.isUnlocked);
    this.statsSubject.next({
      totalTemplates: this.milestoneTemplates.length,
      unlockedCount: unlocked.length,
      lockedCount: progress.length - unlocked.length,
      recentUnlocks: achieved.slice(-5).reverse(),
      nextPredictedMilestone: this.getNextMilestone(),
      totalXPEarned: unlocked.reduce((sum, m) => sum + m.template.xpReward, 0),
    });
  }

  private estimateCurrentValue(
    template: MilestoneTemplate,
    growth: GrowthTrajectory | null
  ): number {
    const stats = growth?.statistics;
    if (!stats) return 0;

    const { type } = template.requirements;
    switch (type) {
      case 'study_hours':
        return stats.totalStudyHours ?? 0;
      case 'completed_courses':
        return stats.completedCourses ?? 0;
      case 'completed_projects':
        return stats.completedProjects ?? 0;
      case 'questions_asked':
        return stats.totalQuestions ?? 0;
      case 'streak_days':
        return 5; // 绀轰緥鍊糪n      case 'mastery_level':
        return 55; // 绀轰緥鍊糪n      case 'skill_level':
        return 1;
      default:
        return 0;
    }
  }
}

import { Injectable } from '@angular/core';
import { BehaviorSubject, fromEvent, interval } from 'rxjs';
import { distinctUntilChanged, map } from 'rxjs/operators';

/**
 * Network Connection API 绫诲瀷
 */
interface NetworkConnection {
  effectiveType: string;
  type: string;
  downlink: number;
  rtt: number;
  downlinkMax: number;
  addEventListener: (type: string, listener: EventListenerOrEventListenerObject) => void;
}

/**
 * 缃戠粶杩炴帴鐘舵€佹灇涓綷n * 鐢ㄤ簬琛ㄧず涓嶅悓鐨勭綉缁滆繛鎺ヨ川閲忕骇鍒玕n */
export enum NetworkQuality {
  /** 绂荤嚎鐘舵€?*/
  OFFLINE = 'offline',
  /** 2G缃戠粶 - 鏋佹參 */
  SLOW_2G = 'slow-2g',
  /** 3G缃戠粶 - 鎱㈤€?*/
  SLOW_3G = 'slow-3g',
  /** 4G缃戠粶 - 姝ｅ父 */
  FAST_4G = 'fast-4g',
  /** WiFi/鍏夌氦 - 蹇€?*/
  FAST_WIFI = 'fast-wifi',
}

/**
 * 缃戠粶鐘舵€佹帴鍙n * 鎻忚堪褰撳墠缃戠粶杩炴帴鐨勮缁嗕俊鎭痋n */
export interface NetworkStatus {
  /** 鏄惁鍦ㄧ嚎 */
  isOnline: boolean;
  /** 缃戠粶璐ㄩ噺绛夌骇 */
  quality: NetworkQuality;
  /** 缃戠粶绫诲瀷 */
  type: string;
  /** 涓嬭閫熷害浼扮畻 (Mbps) */
  downlink?: number;
  /** RTT寤惰繜 (姣) */
  rtt?: number;
  /** 鏈€澶т笅琛岄€熷害 (Mbps) */
  downlinkMax?: number;
  /** 涓婃鏇存柊鏃堕棿 */
  lastUpdated: Date;
}

/**
 * 缃戠粶鐩戞帶鏈嶅姟
 * 璐熻矗鐩戞祴缃戠粶杩炴帴鐘舵€佸彉鍖栧苟鎻愪緵瀹炴椂鐘舵€佷俊鎭痋n *
 * @description
 * 璇ユ湇鍔￠€氳繃澶氱鏂瑰紡鐩戞祴缃戠粶鐘舵€侊細
 * 1. Navigator.onLine API - 鍩虹鍦ㄧ嚎/绂荤嚎妫€娴媆n * 2. Network Information API - 璇︾粏鐨勭綉缁滆川閲忎俊鎭痋n * 3. 瀹氭湡ping妫€娴?- 涓诲姩缃戠粶杩為€氭€ч獙璇乗n */
@Injectable({
  providedIn: 'root',
})
export class NetworkMonitorService {
  /** 缃戠粶鐘舵€佸彉鍖栫殑BehaviorSubject */
  private networkStatusSubject = new BehaviorSubject<NetworkStatus>(this.getCurrentNetworkStatus());

  /** 缃戠粶鐘舵€佸彉鍖栫殑Observable */
  public networkStatus$ = this.networkStatusSubject.asObservable();

  /** 鍦ㄧ嚎鐘舵€佸彉鍖栫殑Observable */
  public isOnline$ = this.networkStatus$.pipe(
    map((status) => status.isOnline),
    distinctUntilChanged()
  );

  /** 缃戠粶璐ㄩ噺鍙樺寲鐨凮bservable */
  public networkQuality$ = this.networkStatus$.pipe(
    map((status) => status.quality),
    distinctUntilChanged()
  );

  constructor() {
    this.initializeNetworkMonitoring();
  }

  /**
   * 鍒濆鍖栫綉缁滅洃鎺n   * 璁剧疆鍚勭缃戠粶浜嬩欢鐩戝惉鍣╘n   */
  private initializeNetworkMonitoring(): void {
    // 鐩戝惉鍩虹鍦ㄧ嚎/绂荤嚎浜嬩欢
    fromEvent(window, 'online').subscribe(() => {
      this.updateNetworkStatus();
    });

    fromEvent(window, 'offline').subscribe(() => {
      this.updateNetworkStatus();
    });

    // 鐩戝惉缃戠粶淇℃伅鍙樺寲锛堝鏋滄敮鎸侊級
    if ('connection' in navigator) {
      const connection = (navigator as unknown as { connection?: NetworkConnection }).connection;
      if (connection) {
        // 鐩戝惉缃戠粶杩炴帴灞炴€у彉鍖朶n        ['change', 'typechange'].forEach((event) => {
          connection.addEventListener(event, () => {
            this.updateNetworkStatus();
          });
        });
      }
    }

    // 瀹氭湡妫€鏌ョ綉缁滅姸鎬侊紙姣?0绉掞級
    interval(30000).subscribe(() => {
      this.updateNetworkStatus();
    });
  }

  /**
   * 鑾峰彇褰撳墠缃戠粶鐘舵€乗n   * 缁煎悎澶氱API淇℃伅鍒ゆ柇缃戠粶璐ㄩ噺
   */
  private getCurrentNetworkStatus(): NetworkStatus {
    const isOnline = navigator.onLine;
    let quality = NetworkQuality.OFFLINE;
    let type = 'unknown';
    let downlink: number | undefined;
    let rtt: number | undefined;
    let downlinkMax: number | undefined;

    if (isOnline) {
      // 灏濊瘯鑾峰彇璇︾粏鐨勭綉缁滀俊鎭痋n      if ('connection' in navigator) {
        const connection = (navigator as unknown as { connection?: NetworkConnection }).connection;
        if (connection) {
          type = connection.effectiveType || connection.type || 'unknown';
          downlink = connection.downlink;
          rtt = connection.rtt;
          downlinkMax = connection.downlinkMax;

          // 鏍规嵁effectiveType鍒ゆ柇璐ㄩ噺
          switch (connection.effectiveType) {
            case 'slow-2g':
              quality = NetworkQuality.SLOW_2G;
              break;
            case '2g':
              quality = NetworkQuality.SLOW_3G;
              break;
            case '3g':
              quality = NetworkQuality.FAST_4G;
              break;
            case '4g':
              quality = NetworkQuality.FAST_WIFI;
              break;
            default:
              // 濡傛灉娌℃湁effectiveType锛屾牴鎹甦ownlink閫熷害鍒ゆ柇
              if (downlink !== undefined) {
                if (downlink < 0.1) {
                  quality = NetworkQuality.SLOW_2G;
                } else if (downlink < 1) {
                  quality = NetworkQuality.SLOW_3G;
                } else if (downlink < 10) {
                  quality = NetworkQuality.FAST_4G;
                } else {
                  quality = NetworkQuality.FAST_WIFI;
                }
              } else {
                quality = NetworkQuality.FAST_4G; // 榛樿鍋囪杈冨揩
              }
          }
        } else {
          quality = NetworkQuality.FAST_4G; // 鍩烘湰鍦ㄧ嚎鐘舵€乗n        }
      } else {
        quality = NetworkQuality.FAST_4G; // 涓嶆敮鎸佽缁嗕俊鎭椂鐨勯粯璁ゅ€糪n      }
    }

    return {
      isOnline,
      quality,
      type,
      downlink,
      rtt,
      downlinkMax,
      lastUpdated: new Date(),
    };
  }

  /**
   * 鏇存柊缃戠粶鐘舵€乗n   * 鍙戝竷鏂扮殑缃戠粶鐘舵€佷俊鎭痋n   */
  private updateNetworkStatus(): void {
    const newStatus = this.getCurrentNetworkStatus();
    this.networkStatusSubject.next(newStatus);
  }

  /**
   * 鑾峰彇褰撳墠缃戠粶鐘舵€佸揩鐓n   */
  public getCurrentStatus(): NetworkStatus {
    return this.networkStatusSubject.getValue();
  }

  /**
   * 妫€鏌ユ槸鍚﹀浜庣绾挎ā寮廫n   */
  public isOffline(): boolean {
    return !this.getCurrentStatus().isOnline;
  }

  /**
   * 妫€鏌ユ槸鍚︿负楂樿川閲忕綉缁淺n   */
  public isHighQualityNetwork(): boolean {
    const quality = this.getCurrentStatus().quality;
    return quality === NetworkQuality.FAST_4G || quality === NetworkQuality.FAST_WIFI;
  }

  /**
   * 妫€鏌ユ槸鍚︿负浣庤川閲忕綉缁淺n   */
  public isLowQualityNetwork(): boolean {
    const quality = this.getCurrentStatus().quality;
    return quality === NetworkQuality.SLOW_2G || quality === NetworkQuality.SLOW_3G;
  }

  /**
   * 鑾峰彇缃戠粶璐ㄩ噺鎻忚堪鏂囨湰
   */
  public getQualityDescription(quality: NetworkQuality): string {
    switch (quality) {
      case NetworkQuality.OFFLINE:
        return '绂荤嚎';
      case NetworkQuality.SLOW_2G:
        return '鏋佹參缃戠粶(2G)';
      case NetworkQuality.SLOW_3G:
        return '鎱㈤€熺綉缁?3G)';
      case NetworkQuality.FAST_4G:
        return '姝ｅ父缃戠粶(4G)';
      case NetworkQuality.FAST_WIFI:
        return '蹇€熺綉缁?WiFi)';
      default:
        return '鏈煡';
    }
  }

  /**
   * 鎵嬪姩瑙﹀彂缃戠粶鐘舵€佹鏌n   */
  public checkNetworkStatus(): void {
    this.updateNetworkStatus();
  }
}

