/**
 * 绂荤嚎鏁版嵁瀛樺偍鏈嶅姟
 * 浣跨敤IndexedDB瀛樺偍绂荤嚎鏁版嵁锛屾彁渚涙暟鎹寔涔呭寲鍜屽悓姝ュ姛鑳絓n *
 * @description
 * 璇ユ湇鍔¤礋璐ｏ細
 * 1. 绠＄悊IndexedDB鏁版嵁搴撹繛鎺n * 2. 鎻愪緵鏁版嵁鐨勫鍒犳敼鏌ユ搷浣淺n * 3. 缁存姢绂荤嚎鎿嶄綔闃熷垪
 * 4. 澶勭悊鏁版嵁鍚屾閫昏緫
 */
@Injectable({
  providedIn: 'root',
})
export class OfflineStorageService {
  /** 鏁版嵁搴撳悕绉?*/
  private readonly DB_NAME = 'iMatuProject_OfflineDB';
  /** 鏁版嵁搴撶増鏈?鈥?v3: 鏂板 courses(璇剧▼鍐呭), progress(瀛︿範杩涘害), assets(璧勬簮鏂囦欢) */
  private readonly DB_VERSION = 3;
  /** 鏁版嵁搴撳疄渚?*/
  private db: IDBDatabase | null = null;
  /** 鏄惁杩愯鍦?Electron 鐜 */
  private readonly isElectron: boolean;
  /** 澶ф枃浠跺垎鐗囧ぇ灏?(1MB) */
  private readonly CHUNK_SIZE = 1024 * 1024;

  /** 鍚屾閰嶇疆 */
  private syncConfig: OfflineSyncConfig = {
    autoSync: true,
    syncInterval: 30000,
    maxRetryAttempts: 3,
    minimumNetworkQuality: 'fast-3g',
    batchSize: 50,
  };

  /** 瀛樺偍缁熻淇℃伅 */
  private statsSubject = new BehaviorSubject<OfflineStorageStats>({
    totalSize: 0,
    itemCounts: {},
    pendingOperations: 0,
  });

  /** 瀛樺偍缁熻Observable */
  public stats$ = this.statsSubject.asObservable();

  constructor(@Inject(PLATFORM_ID) private platformId: object) {
    this.isElectron = !!(window as unknown as { electronAPI?: unknown }).electronAPI;
    if (isPlatformBrowser(platformId)) {
      this.initializeDatabase()
        .then(() => this.updateStats())
        .catch(() => {});
    }
  }

  /**
   * 鍒濆鍖朓ndexedDB鏁版嵁搴揬n   */
  private async initializeDatabase(): Promise<void> {
    return new Promise((resolve, reject) => {
      const request = indexedDB.open(this.DB_NAME, this.DB_VERSION);

      request.onerror = () => {
        reject(request.error);
      };

      request.onsuccess = () => {
        this.db = request.result;
        resolve();
      };

      request.onupgradeneeded = (event) => {
        const db = (event.target as IDBOpenDBRequest).result;

        // 鍒涘缓瀵硅薄瀛樺偍
        if (!db.objectStoreNames.contains('userData')) {
          const userStore = db.createObjectStore('userData', { keyPath: 'id' });
          userStore.createIndex('username', 'username', { unique: true });
          userStore.createIndex('email', 'email', { unique: true });
        }

        if (!db.objectStoreNames.contains('courseData')) {
          const courseStore = db.createObjectStore('courseData', { keyPath: 'id' });
          courseStore.createIndex('teacherId', 'teacherId');
          courseStore.createIndex('status', 'status');
        }

        if (!db.objectStoreNames.contains('taskData')) {
          const taskStore = db.createObjectStore('taskData', { keyPath: 'id' });
          taskStore.createIndex('assigneeId', 'assigneeId');
          taskStore.createIndex('status', 'status');
          taskStore.createIndex('dueDate', 'dueDate');
        }

        if (!db.objectStoreNames.contains('settings')) {
          db.createObjectStore('settings', { keyPath: 'key' });
        }

        if (!db.objectStoreNames.contains('cache')) {
          const cacheStore = db.createObjectStore('cache', { keyPath: 'key' });
          cacheStore.createIndex('expiresAt', 'expiresAt');
        }

        if (!db.objectStoreNames.contains('syncQueue')) {
          const queueStore = db.createObjectStore('syncQueue', { keyPath: 'id' });
          queueStore.createIndex('status', 'status');
          queueStore.createIndex('tableName', 'tableName');
          queueStore.createIndex('createdAt', 'createdAt');
        }

        // v2: 澶ф枃浠跺垎鐗囧瓨鍌?(Electron 绂荤嚎瀹為獙鏁版嵁)
        if (!db.objectStoreNames.contains('fileChunks')) {
          const chunkStore = db.createObjectStore('fileChunks', { keyPath: 'id' });
          chunkStore.createIndex('fileId', 'fileId');
          chunkStore.createIndex('chunkIndex', 'chunkIndex');
        }

        // v3: 璇剧▼鍐呭绂荤嚎缂撳瓨
        if (!db.objectStoreNames.contains('courses')) {
          const courseStore = db.createObjectStore('courses', { keyPath: 'id' });
          courseStore.createIndex('courseId', 'courseId', { unique: true });
          courseStore.createIndex('downloadedAt', 'downloadedAt');
          courseStore.createIndex('expiresAt', 'expiresAt');
        }

        // v3: 瀛︿範杩涘害绂荤嚎瀛樺偍
        if (!db.objectStoreNames.contains('progress')) {
          const progressStore = db.createObjectStore('progress', { keyPath: 'id' });
          progressStore.createIndex('userId', 'userId');
          progressStore.createIndex('courseId', 'courseId');
          progressStore.createIndex('synced', 'synced');
          progressStore.createIndex('updatedAt', 'updatedAt');
        }

        // v3: 闊抽/鍥剧墖绛夎祫婧愭枃浠?blob 瀛樺偍
        if (!db.objectStoreNames.contains('assets')) {
          const assetStore = db.createObjectStore('assets', { keyPath: 'id' });
          assetStore.createIndex('resourceUrl', 'resourceUrl', { unique: true });
          assetStore.createIndex('mimeType', 'mimeType');
          assetStore.createIndex('expiresAt', 'expiresAt');
        }
      };
    });
  }

  /**
   * 鑾峰彇鏁版嵁搴撲簨鍔n   */
  private getTransaction(
    storeNames: string[],
    mode: IDBTransactionMode = 'readonly'
  ): IDBTransaction {
    if (!this.db) {
      throw new Error('鏁版嵁搴撴湭鍒濆鍖?);
    }
    return this.db.transaction(storeNames, mode);
  }

  /**
   * 鑾峰彇瀵硅薄瀛樺偍
   */
  private getObjectStore(storeName: string, mode: IDBTransactionMode = 'readonly'): IDBObjectStore {
    const transaction = this.getTransaction([storeName], mode);
    return transaction.objectStore(storeName);
  }

  /**
   * 瀛樺偍鏁版嵁
   */
  public async setData<T>(key: OfflineStorageKey, data: T): Promise<void> {
    if (!this.db) {
      throw new Error('鏁版嵁搴撴湭鍒濆鍖?);
    }

    return new Promise((resolve, reject) => {
      const store = this.getObjectStore(key, 'readwrite');
      const request = store.put(data);

      request.onsuccess = () => {
        void this.updateStats();
        resolve();
      };

      request.onerror = () => {
        reject(request.error);
      };
    });
  }

  /**
   * 鑾峰彇鏁版嵁
   */
  public async getData<T>(key: OfflineStorageKey, id: string): Promise<T | undefined> {
    if (!this.db) {
      throw new Error('鏁版嵁搴撴湭鍒濆鍖?);
    }

    return new Promise((resolve, reject) => {
      const store = this.getObjectStore(key);
      const request = store.get(id);

      request.onsuccess = () => {
        resolve(request.result as T);
      };

      request.onerror = () => {
        reject(request.error);
      };
    });
  }

  /**
   * 鑾峰彇鎵€鏈夋暟鎹甛n   */
  public async getAllData<T>(key: OfflineStorageKey): Promise<T[]> {
    if (!this.db) {
      throw new Error('鏁版嵁搴撴湭鍒濆鍖?);
    }

    return new Promise((resolve, reject) => {
      const store = this.getObjectStore(key);
      const request = store.getAll();

      request.onsuccess = () => {
        resolve(request.result || []);
      };

      request.onerror = () => {
        reject(request.error);
      };
    });
  }

  /**
   * 鍒犻櫎鏁版嵁
   */
  public async deleteData(key: OfflineStorageKey, id: string): Promise<void> {
    if (!this.db) {
      throw new Error('鏁版嵁搴撴湭鍒濆鍖?);
    }

    return new Promise((resolve, reject) => {
      const store = this.getObjectStore(key, 'readwrite');
      const request = store.delete(id);

      request.onsuccess = () => {
        void this.updateStats();
        resolve();
      };

      request.onerror = () => {
        reject(request.error);
      };
    });
  }

  /**
   * 娓呯┖鎸囧畾瀛樺偍
   */
  public async clearStore(key: OfflineStorageKey): Promise<void> {
    if (!this.db) {
      throw new Error('鏁版嵁搴撴湭鍒濆鍖?);
    }

    return new Promise((resolve, reject) => {
      const store = this.getObjectStore(key, 'readwrite');
      const request = store.clear();

      request.onsuccess = () => {
        void this.updateStats();
        resolve();
      };

      request.onerror = () => {
        reject(request.error);
      };
    });
  }

  /**
   * 娣诲姞绂荤嚎鎿嶄綔鍒伴槦鍒梊n   */
  public async addOperation(
    operation: Omit<OfflineOperation, 'id' | 'createdAt' | 'updatedAt' | 'retryCount'>
  ): Promise<string> {
    const operationWithDefaults: OfflineOperation = {
      ...operation,
      id: this.generateId(),
      createdAt: new Date(),
      updatedAt: new Date(),
      retryCount: 0,
      status: OfflineOperationStatus.PENDING,
    };

    await this.setData(OfflineStorageKey.SYNC_QUEUE, operationWithDefaults);
    return operationWithDefaults.id;
  }

  /**
   * 鏇存柊鎿嶄綔鐘舵€乗n   */
  public async updateOperationStatus(
    id: string,
    status: OfflineOperationStatus,
    errorMessage?: string
  ): Promise<void> {
    const operation = await this.getData<OfflineOperation>(OfflineStorageKey.SYNC_QUEUE, id);
    if (operation) {
      operation.status = status;
      operation.updatedAt = new Date();
      if (errorMessage) {
        operation.errorMessage = errorMessage;
      }
      if (status === OfflineOperationStatus.FAILED) {
        operation.retryCount++;
      }
      await this.setData(OfflineStorageKey.SYNC_QUEUE, operation);
    }
  }

  /**
   * 鑾峰彇寰呭鐞嗙殑鎿嶄綔
   */
  public async getPendingOperations(
    limit: number = this.syncConfig.batchSize
  ): Promise<OfflineOperation[]> {
    if (!this.db) {
      throw new Error('鏁版嵁搴撴湭鍒濆鍖?);
    }

    return new Promise((resolve, reject) => {
      const store = this.getObjectStore(OfflineStorageKey.SYNC_QUEUE);
      const index = store.index('status');
      const request = index.getAll(OfflineOperationStatus.PENDING, limit);

      request.onsuccess = () => {
        resolve(request.result || []);
      };

      request.onerror = () => {
        reject(request.error);
      };
    });
  }

  /**
   * 鏇存柊瀛樺偍缁熻淇℃伅
   */
  private async updateStats(): Promise<void> {
    if (!this.db) return;

    try {
      const itemCounts: Record<string, number> = {};
      let totalSize = 0;
      let pendingOperations = 0;

      // 缁熻鍚勫瓨鍌ㄧ殑鏁版嵁閲廫n      for (const key of Object.values(OfflineStorageKey)) {
        const count = await this.getStoreCount(key);
        itemCounts[key] = count;

        // 绠€鍗曚及绠楀ぇ灏忥紙瀹為檯搴旂敤涓彲鑳介渶瑕佹洿绮剧‘鐨勮绠楋級
        totalSize += count * 1024; // 鍋囪姣忎釜璁板綍绾?KB
      }

      // 缁熻寰呭鐞嗘搷浣滄暟
      pendingOperations = await this.getPendingOperationCount();

      this.statsSubject.next({
        totalSize,
        itemCounts,
        pendingOperations,
      });
    } catch {
      /* 缁熻鏇存柊澶辫触涓嶉樆濉?*/
    }
  }

  /**
   * 鑾峰彇瀛樺偍涓殑璁板綍鏁癨n   */
  private async getStoreCount(storeName: string): Promise<number> {
    if (!this.db) return 0;

    return new Promise((resolve, reject) => {
      const store = this.getObjectStore(storeName);
      const request = store.count();

      request.onsuccess = () => {
        resolve(request.result);
      };

      request.onerror = () => {
        reject(request.error);
      };
    });
  }

  /**
   * 鑾峰彇寰呭鐞嗘搷浣滄暟
   */
  private async getPendingOperationCount(): Promise<number> {
    if (!this.db) return 0;

    return new Promise((resolve, reject) => {
      const store = this.getObjectStore(OfflineStorageKey.SYNC_QUEUE);
      const index = store.index('status');
      const request = index.count(OfflineOperationStatus.PENDING);

      request.onsuccess = () => {
        resolve(request.result);
      };

      request.onerror = () => {
        reject(request.error);
      };
    });
  }

  /**
   * 鐢熸垚鍞竴ID
   */
  private generateId(): string {
    return Date.now().toString(36) + Math.random().toString(36).substr(2);
  }

  /**
   * 鑾峰彇褰撳墠鍚屾閰嶇疆
   */
  public getSyncConfig(): OfflineSyncConfig {
    return { ...this.syncConfig };
  }

  /**
   * 鏇存柊鍚屾閰嶇疆
   */
  public updateSyncConfig(config: Partial<OfflineSyncConfig>): void {
    this.syncConfig = { ...this.syncConfig, ...config };
  }

  /**
   * 娓呯悊杩囨湡缂撳瓨
   */
  public async cleanupExpiredCache(): Promise<void> {
    if (!this.db) return;

    const now = new Date();
    const store = this.getObjectStore(OfflineStorageKey.CACHE, 'readwrite');
    const index = store.index('expiresAt');

    const expiredItems: Array<{ key: IDBValidKey }> = [];

    return new Promise((resolve, reject) => {
      const request = index.openCursor(IDBKeyRange.upperBound(now));

      request.onsuccess = (event: Event) => {
        const cursor = (event.target as IDBRequest<IDBCursorWithValue>).result;
        if (cursor) {
          expiredItems.push(cursor.value as { key: IDBValidKey });
          cursor.continue();
        } else {
          const deletePromises = expiredItems.map(
            (item) =>
              new Promise<void>((delResolve, delReject) => {
                const deleteReq = store.delete(item.key);
                deleteReq.onsuccess = () => delResolve();
                deleteReq.onerror = () => delReject(deleteReq.error);
              })
          );

          Promise.all(deletePromises)
            .then(() => {
              void this.updateStats();
              resolve();
            })
            .catch(reject);
        }
      };

      request.onerror = () => reject(request.error);
    });
  }

  // ==================== 澶ф枃浠跺垎鐗囧瓨鍌?(Electron 绂荤嚎妯″紡) ====================

  /**
   * 鍒嗙墖瀛樺偍澶ф枃浠讹紙瀹為獙鏁版嵁銆佽绋嬭棰戠瓑锛塡n   * @param fileId 鏂囦欢鍞竴鏍囪瘑
   * @param data 鏂囦欢浜岃繘鍒舵暟鎹甛n   * @param metadata 鏂囦欢鍏冩暟鎹甛n   */
  public async storeLargeFile(
    fileId: string,
    data: ArrayBuffer,
    metadata?: Record<string, unknown>
  ): Promise<void> {
    if (!this.db) throw new Error('鏁版嵁搴撴湭鍒濆鍖?);

    const totalChunks = Math.ceil(data.byteLength / this.CHUNK_SIZE);

    for (let i = 0; i < totalChunks; i++) {
      const chunk = data.slice(i * this.CHUNK_SIZE, (i + 1) * this.CHUNK_SIZE);
      await this.storeChunk(fileId, i, chunk);
    }

    // 瀛樺偍鍏冩暟鎹甛n    await this.setData(OfflineStorageKey.CACHE, {
      key: `file_meta_${fileId}`,
      fileId,
      totalChunks,
      totalSize: data.byteLength,
      metadata,
      storedAt: new Date().toISOString(),
    } as unknown as Record<string, unknown>);
  }

  /**
   * 璇诲彇鍒嗙墖澶ф枃浠禱n   */
  public async loadLargeFile(fileId: string): Promise<ArrayBuffer | null> {
    if (!this.db) return null;

    const meta = await this.getData<{
      key: string;
      fileId: string;
      totalChunks: number;
      totalSize: number;
    }>(OfflineStorageKey.CACHE, `file_meta_${fileId}`);

    if (!meta) return null;

    const chunks: ArrayBuffer[] = [];
    for (let i = 0; i < meta.totalChunks; i++) {
      const chunk = await this.getChunk(fileId, i);
      if (!chunk) return null;
      chunks.push(chunk);
    }

    // 鍚堝苟鍒嗙墖
    const result = new Uint8Array(meta.totalSize);
    let offset = 0;
    for (const chunk of chunks) {
      result.set(new Uint8Array(chunk), offset);
      offset += chunk.byteLength;
    }
    return result.buffer;
  }

  /**
   * 鍒犻櫎澶ф枃浠跺強鍏跺垎鐗嘰n   */
  public async deleteLargeFile(fileId: string): Promise<void> {
    if (!this.db) return;

    const meta = await this.getData<{ key: string; totalChunks: number }>(
      OfflineStorageKey.CACHE,
      `file_meta_${fileId}`
    );

    const deletePromises: Promise<void>[] = [];

    if (meta) {
      for (let i = 0; i < meta.totalChunks; i++) {
        deletePromises.push(this.deleteChunk(fileId, i));
      }
    }

    deletePromises.push(this.deleteData(OfflineStorageKey.CACHE, `file_meta_${fileId}`));

    await Promise.all(deletePromises);
  }

  /** 鑾峰彇 Electron 鐜鐘舵€?*/
  public get isElectronEnv(): boolean {
    return this.isElectron;
  }

  private storeChunk(fileId: string, chunkIndex: number, data: ArrayBuffer): Promise<void> {
    return new Promise((resolve, reject) => {
      const store = this.getObjectStore('fileChunks', 'readwrite');
      const req = store.put({ id: `${fileId}_${chunkIndex}`, fileId, chunkIndex, data });
      req.onsuccess = () => resolve();
      req.onerror = () => reject(req.error);
    });
  }

  private getChunk(fileId: string, chunkIndex: number): Promise<ArrayBuffer | null> {
    return new Promise((resolve, reject) => {
      const store = this.getObjectStore('fileChunks', 'readonly');
      const req = store.get(`${fileId}_${chunkIndex}`);
      req.onsuccess = () => {
        const result = req.result as { data?: ArrayBuffer } | undefined;
        resolve(result?.data ?? null);
      };
      req.onerror = () => reject(req.error);
    });
  }

  private deleteChunk(fileId: string, chunkIndex: number): Promise<void> {
    return new Promise((resolve, reject) => {
      const store = this.getObjectStore('fileChunks', 'readwrite');
      const req = store.delete(`${fileId}_${chunkIndex}`);
      req.onsuccess = () => resolve();
      req.onerror = () => reject(req.error);
    });
  }
}

/**
 * 缁熶竴浠锋牸鏈嶅姟
 *
 * 绠＄悊鎵€鏈変环鏍肩浉鍏虫暟鎹細Token濂楅銆佽闃呰鍒掋€佽绋嬩环鏍肩瓑
 * 鎻愪緵缁熶竴鐨勪环鏍艰幏鍙栥€佽绠楀拰鏍煎紡鍖栨帴鍙n */

import { HttpClient } from '@angular/common/http';
import { Injectable } from '@angular/core';
import { BehaviorSubject, combineLatest, Observable, of } from 'rxjs';
import { catchError, map, tap } from 'rxjs/operators';

import { TokenPackage } from '../../models/token.models';
import {
  BillingCycle,
  CalculatePriceRequest,
  CalculatePriceResponse,
  formatPrice,
  GetPricesRequest,
  GetPricesResponse,
  PriceGroup,
  PriceType,
  PricingConfig,
  ProductTier,
  UnifiedPriceItem,
} from '../models/pricing.models';
import { SubscriptionPlan } from '../models/subscription.models';

@Injectable({
  providedIn: 'root',
})
export class PricingService {
  /** 浠锋牸閰嶇疆缂撳瓨 */
  private pricingConfig$ = new BehaviorSubject<PricingConfig | null>(null);

  /** 鎵€鏈変环鏍奸」鐨勭紦瀛?*/
  private allPrices$ = new BehaviorSubject<UnifiedPriceItem[]>([]);

  /** 鍒嗙粍浠锋牸鐨勭紦瀛?*/
  private groupedPrices$ = new BehaviorSubject<PriceGroup[]>([]);

  /** 榛樿浠锋牸閰嶇疆 */
  private defaultConfig: PricingConfig = {
    version: '1.0.0',
    currency: {
      default: 'CNY',
      supported: ['CNY', 'USD', 'EUR'],
    },
    groups: [],
  };

  constructor(private http: HttpClient) {
    // 鍒濆鍖栨椂鍔犺浇榛樿閰嶇疆
    this.loadDefaultPrices();
  }

  // ==================== 鍏叡API鏂规硶 ====================

  /**
   * 鑾峰彇鎵€鏈変环鏍奸」
   */
  getAllPrices(request?: GetPricesRequest): Observable<GetPricesResponse> {
    return this.allPrices$.pipe(
      map((items) => this.filterAndSortPrices(items, request)),
      map((filteredItems) => this.groupPrices(filteredItems)),
      map((groupedItems) => ({
        config: this.pricingConfig$.value ?? this.defaultConfig,
        items: this.allPrices$.value,
        groupedItems,
        metadata: {
          totalCount: this.allPrices$.value.length,
          filteredCount: groupedItems.reduce((sum, group) => sum + group.items.length, 0),
          currency: this.defaultConfig.currency.default,
        },
      }))
    );
  }

  /**
   * 鑾峰彇鐗瑰畾绫诲瀷鐨勪环鏍奸」
   */
  getPricesByType(type: PriceType, request?: GetPricesRequest): Observable<UnifiedPriceItem[]> {
    return this.getAllPrices({
      ...request,
      types: [type],
    }).pipe(map((response) => response.items.filter((item) => item.type === type)));
  }

  /**
   * 鑾峰彇鍒嗙粍浠锋牸
   */
  getGroupedPrices(): Observable<PriceGroup[]> {
    return this.groupedPrices$.asObservable();
  }

  /**
   * 鑾峰彇浠锋牸閰嶇疆
   */
  getPricingConfig(): Observable<PricingConfig> {
    return this.pricingConfig$.pipe(map((config) => config ?? this.defaultConfig));
  }

  /**
   * 鏍规嵁ID鑾峰彇浠锋牸椤筡n   */
  getPriceItemById(id: string): Observable<UnifiedPriceItem | null> {
    return this.allPrices$.pipe(map((items) => items.find((item) => item.id === id) ?? null));
  }

  /**
   * 璁＄畻浠锋牸
   */
  calculatePrice(request: CalculatePriceRequest): Observable<CalculatePriceResponse> {
    return this.getPriceItemById(request.itemId).pipe(
      map((item) => {
        if (!item) {
          throw new Error(`鏈壘鍒颁环鏍奸」: ${request.itemId}`);
        }

        const quantity = request.quantity ?? 1;
        const subtotal = item.price.current * quantity;

        // 绠€鍗曟姌鎵ｈ绠楋紙瀹為檯椤圭洰涓彲鑳芥洿澶嶆潅锛塡n        const discountRate = item.price.discount ?? 0;
        const discountAmount = Math.round(subtotal * discountRate);
        const finalPrice = subtotal - discountAmount;

        return {
          originalPrice: subtotal,
          discountAmount,
          finalPrice,
          currency: item.price.currency,
          breakdown: {
            itemPrice: item.price.current,
            quantity,
            subtotal,
            discount: discountAmount,
            tax: 0,
            serviceFee: 0,
          },
          appliedPromotions: discountRate > 0 ? ['item_discount'] : [],
        };
      })
    );
  }

  /**
   * 鏍煎紡鍖栦环鏍兼樉绀篭n   */
  formatPrice(priceCents: number, currency?: string): string {
    return formatPrice(priceCents, currency);
  }

  /**
   * 鑾峰彇浠锋牸姣旇緝
   */
  comparePrices(itemIdA: string, itemIdB: string): Observable<unknown> {
    return combineLatest([this.getPriceItemById(itemIdA), this.getPriceItemById(itemIdB)]).pipe(
      map(([itemA, itemB]) => {
        if (!itemA || !itemB) {
          throw new Error('姣旇緝鐨勪环鏍奸」涓嶅瓨鍦?);
        }

        const priceA = itemA.price.current;
        const priceB = itemB.price.current;
        const priceDifference = priceB - priceA;
        const priceDifferencePercentage = priceA > 0 ? (priceDifference / priceA) * 100 : 0;

        // 绠€鍗曠殑鎬т环姣旇绠楋紙鏍规嵁鍔熻兘鍜屼环鏍硷級
        const featuresA = itemA.features?.length ?? 0;
        const featuresB = itemB.features?.length ?? 0;
        const valueScoreA = priceA > 0 ? featuresA / priceA : Infinity;
        const valueScoreB = priceB > 0 ? featuresB / priceB : Infinity;

        return {
          itemA,
          itemB,
          priceDifference,
          priceDifferencePercentage,
          valueScore: {
            a: valueScoreA,
            b: valueScoreB,
            winner: valueScoreA > valueScoreB ? 'a' : valueScoreB > valueScoreA ? 'b' : 'tie',
          },
        };
      })
    );
  }

