import { Injectable } from '@angular/core';
import { MatSnackBar } from '@angular/material/snack-bar';
import { SwUpdate, VersionReadyEvent } from '@angular/service-worker';
import { filter, fromEvent, interval, map, Observable, startWith, switchMap } from 'rxjs';

import { AppStateService } from './app-state.service';

/** Electron API 鎺ュ彛 */
interface ElectronAPI {
  healthCheck(): Promise<{ success: boolean; version?: string }>;
}

/** 瀹夎鎻愮ず浜嬩欢 */
interface BeforeInstallPromptEvent extends Event {
  prompt(): Promise<{ outcome: 'accepted' | 'dismissed' }>;
}

/** Service Worker 鍚庡彴鍚屾 */
interface ServiceWorkerSyncRegistration {
  sync: {
    register(tag: string): Promise<void>;
  };
}

/** Navigator Network Information */
interface NetworkConnection {
  effectiveType: string;
  type: string;
  downlink: number;
  rtt: number;
  downlinkMax: number;
}

@Injectable({
  providedIn: 'root',
})
export class PwaService {
  /** 鏄惁鍦?Electron 鐜涓繍琛岋紙Electron 涓嬪簲绂佺敤 PWA Service Worker锛?*/
  private readonly isElectron: boolean;

  constructor(
    private swUpdate: SwUpdate,
    private snackBar: MatSnackBar,
    private appState: AppStateService
  ) {
    this.isElectron = !!(
      typeof window !== 'undefined' &&
      (window as unknown as { electronAPI?: ElectronAPI }).electronAPI
    );
    if (!this.isElectron) {
      this.initPwa();
    }
  }

  /**
   * 鍒濆鍖朠WA鍔熻兘
   */
  private initPwa(): void {
    // 妫€鏌ervice Worker鏇存柊
    this.checkForUpdates();

    // 瀹氭湡妫€鏌ユ洿鏂?(姣忓皬鏃?
    interval(60 * 60 * 1000)
      .pipe(
        startWith(0),
        switchMap(() => this.swUpdate.checkForUpdate())
      )
      .subscribe();
  }

  /**
   * 妫€鏌ュ簲鐢ㄦ洿鏂癨n   */
  private checkForUpdates(): void {
    if (!this.swUpdate.isEnabled) {
      console.warn('Service Worker 鏈惎鐢?);
      return;
    }

    // 鐩戝惉鏇存柊鍙敤浜嬩欢
    this.swUpdate.versionUpdates
      .pipe(filter((evt): evt is VersionReadyEvent => evt.type === 'VERSION_READY'))
      .subscribe((evt) => {
        const currentVersion = evt.currentVersion.hash.substring(0, 7);
        const newVersion = evt.latestVersion.hash.substring(0, 7);
        this.showUpdateNotification(currentVersion, newVersion);
      });

    // 鐩戝惉鏇存柊浜嬩欢
    this.swUpdate.versionUpdates
      .pipe(filter((event) => event.type === 'VERSION_READY'))
      .subscribe((event) => {
        console.warn('鏂扮増鏈凡鍑嗗灏辩华:', event);
        this.showUpdateSuccess();
      });
  }

  /**
   * 鏄剧ず鏇存柊鎻愮ず
   */
