  public async precacheCriticalResources(): Promise<void> {
    if (!('serviceWorker' in navigator)) {
      return;
    }

    try {
      const registration = await navigator.serviceWorker.getRegistration();
      if (registration?.active) {
        // 鍙戦€佹秷鎭粰Service Worker棰勭紦瀛樿祫婧怽n        registration.active.postMessage({
          type: 'PRECACHE',
          resources: ['/', '/dashboard'],
        });
      }
    } catch (error) {
      console.error('棰勭紦瀛樺け璐?', error);
    }
  }

  /**
   * 妫€鏌ョ綉缁滆繛鎺ョ姸鎬乗n   */
  public getNetworkStatus(): Observable<'online' | 'offline' | 'slow'> {
    return new Observable((observer) => {
      const checkStatus = (): void => {
        if (!navigator.onLine) {
          observer.next('offline');
        } else {
          // 浣跨敤navigator.connection妫€娴嬬綉缁滆川閲?濡傛灉鏀寔)
          const connection = (navigator as unknown as { connection?: NetworkConnection })
            .connection;
          if (connection?.effectiveType) {
            const slowTypes = ['slow-2g', '2g'];
            observer.next(slowTypes.includes(connection.effectiveType) ? 'slow' : 'online');
          } else {
            observer.next('online');
          }
        }
      };

      checkStatus();

      const handleOnline = (): void => checkStatus();
      const handleOffline = (): void => checkStatus();

      window.addEventListener('online', handleOnline);
      window.addEventListener('offline', handleOffline);

      return () => {
        window.removeEventListener('online', handleOnline);
        window.removeEventListener('offline', handleOffline);
      };
    });
  }

  /**
   * 娣诲姞绂荤嚎鐩戝惉鍣╘n   */
  public addOfflineListener(callback: (isOffline: boolean) => void): () => void {
    const handleOnline = (): void => callback(false);
    const handleOffline = (): void => callback(true);

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    // 绔嬪嵆妫€鏌ヤ竴娆n    callback(!navigator.onLine);

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }

  /**
   * 浼扮畻绂荤嚎缂撳瓨澶у皬
   */
  public async estimateCacheSize(): Promise<{ size: number; count: number }> {
    try {
      if ('caches' in window) {
        const cacheNames = await caches.keys();
        let totalSize = 0;
        let count = 0;

        for (const cacheName of cacheNames) {
          const cache = await caches.open(cacheName);
          const keys = await cache.keys();
          count += keys.length;

          for (const request of keys) {
            const response = await cache.match(request);
            if (response) {
              const blob = await response.blob();
              totalSize += blob.size;
            }
          }
        }

        return {
          size: totalSize,
          count,
        };
      }
      return { size: 0, count: 0 };
    } catch (error) {
      console.error('浼扮畻缂撳瓨澶у皬澶辫触:', error);
      return { size: 0, count: 0 };
    }
  }

