  /**
   * 娉ㄥ唽鍚庡彴鍚屾浠诲姟
   */
  public async registerBackgroundSync(tag: string): Promise<boolean> {
    try {
      const registration = await navigator.serviceWorker.ready;
      // 浣跨敤绫诲瀷鏂█閬垮厤 TypeScript 閿欒
      const syncRegistration = registration as unknown as ServiceWorkerSyncRegistration;
      if (syncRegistration.sync) {
        await syncRegistration.sync.register(tag);
        return true;
      }
      console.warn('鍚庡彴鍚屾 API 涓嶅彲鐢?);
      return false;
    } catch (error) {
      console.error('娉ㄥ唽鍚庡彴鍚屾澶辫触:', error);
      return false;
    }
  }
