   */
  getTimeStats(startDate: string, endDate: string): Observable<TokenTimeStats[]> {
    if (USE_MOCK_DATA) {
      // 鐢熸垚杩囧幓7澶╃殑妯℃嫙鏁版嵁
      const mockTimeStats: TokenTimeStats[] = [];
      const start = new Date(startDate);
      const end = new Date(endDate);

      for (let d = new Date(start); d <= end; d.setDate(d.getDate() + 1)) {
        const dateStr = d.toISOString().split('T')[0];
        const consumed = Math.floor(Math.random() * 50) + 10; // 10-60涔嬮棿鐨勯殢鏈烘秷璐筡n        const purchased = Math.random() > 0.8 ? Math.floor(Math.random() * 200) + 100 : 0; // 20%姒傜巼鏈夊厖鍊糪n        const netChange = purchased - consumed;

        mockTimeStats.push({
          date: dateStr,
          consumed,
          purchased,
          netChange,
        });
      }

      return of(mockTimeStats).pipe(delay(300));
    }
    const params = {
      startDate,
      endDate,
    };

    return this.http
      .get<TokenTimeStats[]>(`${this.API_BASE_URL}/stats/time`, { params })
      .pipe(catchError((error) => this.handleError(error)));
  }

