/**
 * Vircadia 妯″瀷鍔犺浇鍣ㄦ湇鍔n *
 * 璐熻矗浠?KiCad 妯″瀷搴撳姞杞界數瀛愬厓浠?3D 妯″瀷鍒?Vircadia 鍦烘櫙
 * 鏀寔 LOD 鍒囨崲銆佹潗璐ㄧ鐞嗐€佸疄渚嬪寲娓叉煋绛夊姛鑳絓n *
 * @author iMatu Development Team
 * @version 1.0.0
 */

import { Injectable } from '@angular/core';
import * as THREE from 'three';
import { GLTFLoader } from 'three/examples/jsm/loaders/GLTFLoader';

import { GameObject } from '../../models/vircadia.models';

import { VircadiaSdkService } from './vircadia-sdk.service';

/**
 * 鐢靛瓙鍏冧欢妯″瀷淇℃伅
 */
export interface ComponentModelInfo {
  /** 鍏冧欢 ID */
  componentId: string;
  /** 鍏冧欢鍚嶇О */
  componentName: string;
  /** 绫诲埆 */
  category: string;
  /** 灏佽绫诲瀷 */
  packageType: string;
  /** LOD 绾у埆 */
  lodLevel: 'high' | 'medium' | 'low';
  /** 妯″瀷 URL */
  modelUrl: string;
  /** 鏂囦欢澶у皬 (MB) */
  fileSizeMB: number;
  /** 涓夎褰㈡暟閲?*/
  triangleCount: number;
}

/**
 * 妯″瀷搴撳垎绫籠n */
export interface ComponentLibrary {
  [category: string]: ComponentModelInfo[];
}

/**
 * LOD 閰嶇疆
 */
export interface LODConfig {
  /** 杩戣窛绂婚槇鍊?(绫? */
  nearThreshold: number;
  /** 杩滆窛绂婚槇鍊?(绫? */
  farThreshold: number;
  /** 褰撳墠 LOD 绾у埆 */
  currentLevel: 'high' | 'medium' | 'low';
}

/**
 * 妯″瀷搴撶储寮?JSON 鐨勬暟鎹粨鏋刓n */
interface ModelIndexEntry {
  id: string;
  component_name: string;
  category: string;
  package_type: string;
  source_url: string;
  file_size_bytes: number;
}

@Injectable({
  providedIn: 'root',
})
export class VircadiaModelLoaderService {
  private gltfLoader: GLTFLoader;
  private loadedModels: Map<string, THREE.Group> = new Map();
  private modelCache: Map<string, THREE.Group> = new Map();

  // LOD 閰嶇疆
  private defaultLODConfig: LODConfig = {
    nearThreshold: 5.0, // < 5m 浣跨敤楂樻ā
    farThreshold: 15.0, // > 15m 浣跨敤浣庢ā
    currentLevel: 'medium', // 榛樿浣跨敤涓ā
  };

  // 妯″瀷搴撶储寮昞n  private libraryIndex: ComponentLibrary | null = null;

  constructor(private vircadiaSdk: VircadiaSdkService) {
    this.gltfLoader = new GLTFLoader();
    void this.loadLibraryIndex();
  }

  /**
   * 鍔犺浇妯″瀷搴撶储寮昞n   */
  private async loadLibraryIndex(): Promise<void> {
    try {
      const response = await fetch('assets/models/kicad_model_index.json');
      const data: { models: ModelIndexEntry[] } = (await response.json()) as {
        models: ModelIndexEntry[];
      };

      this.libraryIndex = this.buildLibraryIndex(data.models);
      console.warn(
        '[ModelLoader] 妯″瀷搴撶储寮曞姞杞芥垚鍔?',
        Object.keys(this.libraryIndex).length,
        '涓被鍒?
      );
    } catch {
      /* 绱㈠紩鍔犺浇澶辫触浣跨敤榛樿鍊?*/
    }
  }

  /**
   * 鏋勫缓妯″瀷搴撶储寮昞n   */
  private buildLibraryIndex(models: ModelIndexEntry[]): ComponentLibrary {
    const library: ComponentLibrary = {};

    for (const model of models) {
      const category = model.category;

      if (!library[category]) {
        library[category] = [];
      }

      library[category].push({
        componentId: model.id,
        componentName: model.component_name,
        category,
        packageType: model.package_type,
        lodLevel: 'medium' as const,
        modelUrl: model.source_url.replace('.step', '.glb'),
        fileSizeMB: model.file_size_bytes / (1024 * 1024),
        triangleCount: Math.max(1, Math.round(model.file_size_bytes / 300)), // 浠庢枃浠跺ぇ灏忎及绠椾笁瑙掑舰鏁伴噺
      });
    }

    return library;
  }

  /**
   * 鍔犺浇鍏冧欢妯″瀷
   *
   * @param componentId 鍏冧欢 ID
   * @param lodLevel LOD 绾у埆 (鍙€?
   * @returns 鍔犺浇鐨?GameObject
   */
  async loadComponentModel(
    componentId: string,
    lodLevel: 'high' | 'medium' | 'low' = 'medium'
  ): Promise<GameObject | null> {
    try {
      // 鏌ユ壘妯″瀷淇℃伅
      const modelInfo = this.findModelInfo(componentId);
      if (!modelInfo) {
        return null;
      }

      // 妫€鏌ョ紦瀛榎n      const cacheKey = `${componentId}_${lodLevel}`;
      const cachedModel = this.modelCache.get(cacheKey);

      let modelGroup: THREE.Group;

      if (cachedModel) {
        modelGroup = cachedModel.clone();
      } else {
        // 鍔犺浇鏂版ā鍨媆n        modelGroup = await this.loadGLBModel(modelInfo.modelUrl);

        if (!modelGroup) {
          throw new Error('妯″瀷鍔犺浇澶辫触');
        }

        // 娣诲姞鍒扮紦瀛榎n        this.modelCache.set(cacheKey, modelGroup);
      }

      // 鍒涘缓 Vircadia Entity
      const entity = this.createVircadiaEntity(modelGroup, modelInfo);

      // 瀛樺偍寮曠敤
      this.loadedModels.set(entity.id, modelGroup);

      return entity;
    } catch (error) {
      return null;
    }
  }

  /**
   * 鍔犺浇 GLB 妯″瀷
   */
  private async loadGLBModel(url: string): Promise<THREE.Group> {
    return new Promise((resolve, reject) => {
      this.gltfLoader.load(
        url,
        (gltf) => {
          const group = new THREE.Group();

          // 娣诲姞鎵€鏈夌綉鏍糪n          gltf.scene.children.forEach((child) => {
            if (child instanceof THREE.Mesh) {
              group.add(child.clone());
            }
          });

          // 浼樺寲锛氬悎骞跺嚑浣曚綋浠ュ噺灏戠粯鍒惰皟鐢╘n          this.mergeGeometries(group);

          resolve(group);
        },
        (progress) => {
          if (progress.total > 0) {
            const percent = (progress.loaded / progress.total) * 100;
            console.warn(`[ModelLoader] 鍔犺浇杩涘害锛?{percent.toFixed(1)}%`);
          }
        },
        (error) => {
          reject(error);
        }
      );
    });
  }

  /**
   * 鍚堝苟鍑犱綍浣撲紭鍖栨覆鏌揬n   */
  private mergeGeometries(group: THREE.Group): void {
    // 浣跨敤 Three.js 鐨?Geometry 鍚堝苟鏉ュ噺灏?draw calls锛屾彁楂樻覆鏌撴€ц兘
    const geometries: THREE.BufferGeometry[] = [];
    const materials: THREE.Material[] = [];

    group.traverse((child) => {
      if (child instanceof THREE.Mesh) {
        const geometry = child.geometry as THREE.BufferGeometry | undefined;
        if (geometry) {
          // 灏?geometry 杞崲涓轰笘鐣屽潗鏍嘰n          geometry.applyMatrix4(child.matrixWorld);
          geometries.push(geometry);
          const mesh = child as THREE.Mesh;
          const mat = mesh.material;
          if (Array.isArray(mat)) {
            for (const m of mat) {
              materials.push(m);
            }
          } else {
            materials.push(mat);
          }
        }
      }
    });

    if (geometries.length > 1) {
      // 娓呴櫎鍘熸湁瀛愬璞n      while (group.children.length > 0) {
        group.remove(group.children[0]);
      }

      // 鍒涘缓涓€涓悎骞跺悗鐨?Mesh锛屼娇鐢ㄧ涓€涓潗璐╘n      if (materials.length > 0) {
        const mergedGeometry = this.mergeBufferGeometries(geometries);
        if (mergedGeometry) {
          const mergedMesh = new THREE.Mesh(mergedGeometry, materials[0]);
          group.add(mergedMesh);
        }
      }
    }
  }

  /**
   * 鍚堝苟 BufferGeometry 鏁扮粍
   */
  private mergeBufferGeometries(geometries: THREE.BufferGeometry[]): THREE.BufferGeometry | null {
    if (geometries.length === 0) return null;
    if (geometries.length === 1) return geometries[0];

    // 鎵嬪姩鍚堝苟 BufferGeometry: 鍚堝苟 position 绛?attributes
    const result = new THREE.BufferGeometry();
    const attributes = ['position', 'normal', 'uv', 'color', 'tangent'];

    for (const attrName of attributes) {
      const buffers: Float32Array[] = [];
      let hasAttr = false;

      for (const geo of geometries) {
        const attr = geo.getAttribute(attrName);
        if (attr) {
          hasAttr = true;
          buffers.push(new Float32Array(attr.array as unknown as ArrayBuffer));
        }
      }

      if (hasAttr && buffers.length > 0) {
        const totalSize = buffers.reduce((sum, buf) => sum + buf.length, 0);
        const merged = new Float32Array(totalSize);
        let offset = 0;
        for (const buf of buffers) {
          merged.set(buf, offset);
          offset += buf.length;
        }
        // 浣跨敤绗竴涓?geometry 鐨?itemSize
        const firstGeo = geometries.find((g) => g.getAttribute(attrName));
        if (firstGeo) {
          const firstAttr = firstGeo.getAttribute(attrName);
          if (firstAttr) {
            result.setAttribute(attrName, new THREE.BufferAttribute(merged, firstAttr.itemSize));
          }
        }
      }
    }

    // 鍚堝苟 index锛堝鏈夛級
    let vertexOffset = 0;
    const indexBuffers: number[][] = [];
    for (const geo of geometries) {
      const idx = geo.getIndex();
      if (idx) {
        const adjusted = Array.from(idx.array).map((v: number) => v + vertexOffset);
        indexBuffers.push(adjusted);
      }
      vertexOffset += geo.getAttribute('position')?.count ?? 0;
    }

    if (indexBuffers.length > 0) {
      const totalIndices = indexBuffers.reduce((sum, buf) => sum + buf.length, 0);
      const mergedIndices = new Uint32Array(totalIndices);
      let offset = 0;
      for (const buf of indexBuffers) {
        mergedIndices.set(buf, offset);
        offset += buf.length;
      }
      result.setIndex(new THREE.BufferAttribute(mergedIndices, 1));
    }

    return result;
  }

  /**
   * 鍒涘缓 Vircadia 瀹炰綋
   */
  private createVircadiaEntity(modelGroup: THREE.Group, modelInfo: ComponentModelInfo): GameObject {
    // 浣跨敤 Three.js 鍒涘缓瀹炰綋鐨勫崰浣嶇
    // 瀹為檯搴旇璋冪敤 Vircadia SDK 鐨?createEntity 鏂规硶

    const entity: GameObject = {
      id: `entity_${modelInfo.componentId}_${Date.now()}`,
      name: modelInfo.componentName,
      type: 'mesh',
      position: { x: 0, y: 0, z: 0 },
      rotation: { x: 0, y: 0, z: 0, w: 1 },
      scale: { x: 1, y: 1, z: 1 },
      visible: true,
      interactable: true,
      metadata: {
        componentId: modelInfo.componentId,
        category: modelInfo.category,
        packageType: modelInfo.packageType,
        lodLevel: modelInfo.lodLevel,
        modelUrl: modelInfo.modelUrl,
        triangleCount: modelInfo.triangleCount,
      },
    };

    return entity;
  }

  /**
   * 鏌ユ壘妯″瀷淇℃伅
   */
  private findModelInfo(componentId: string): ComponentModelInfo | null {
    if (!this.libraryIndex) {
      return null;
    }

    for (const category of Object.keys(this.libraryIndex)) {
      const models = this.libraryIndex[category];
      const model = models.find((m) => m.componentId === componentId);

      if (model) {
        return model;
      }
    }

    return null;
  }

  /**
   * 鑾峰彇鏌愮被鍒殑鎵€鏈夋ā鍨媆n   */
  getModelsByCategory(category: string): ComponentModelInfo[] {
    if (!this.libraryIndex) {
      return [];
    }

    return this.libraryIndex[category] || [];
  }

  /**
   * 鑾峰彇鎵€鏈夌被鍒玕n   */
  getAllCategories(): string[] {
    if (!this.libraryIndex) {
      return [];
    }

    return Object.keys(this.libraryIndex);
  }

  /**
   * 鍔ㄦ€?LOD 鍒囨崲
   *
   * @param entityId 瀹炰綋 ID
   * @param cameraDistance 鐩告満璺濈
   */
  updateLOD(entityId: string, cameraDistance: number): void {
    const model = this.loadedModels.get(entityId);
    if (!model) {
      return;
    }

    const config = this.defaultLODConfig;
    let targetLOD: 'high' | 'medium' | 'low';

    if (cameraDistance < config.nearThreshold) {
      targetLOD = 'high';
    } else if (cameraDistance > config.farThreshold) {
      targetLOD = 'low';
    } else {
      targetLOD = 'medium';
    }

    // 濡傛灉 LOD 闇€瑕佸垏鎹n    if (config.currentLevel !== targetLOD) {
      console.warn(
        `[ModelLoader] LOD 鍒囨崲锛?{config.currentLevel} -> ${targetLOD} (璺濈:${cameraDistance.toFixed(1)}m)`
      );
      config.currentLevel = targetLOD;
    }
  }

  /**
   * 鎵归噺鍔犺浇鍏冧欢搴揬n   */
  async loadComponentLibrary(): Promise<ComponentLibrary> {
    if (!this.libraryIndex) {
      throw new Error('妯″瀷搴撶储寮曟湭鍔犺浇');
    }

    // 棰勫姞杞藉父鐢ㄦā鍨媆n    const commonCategories = ['resistor', 'capacitor', 'led'];

    for (const category of commonCategories) {
      const models = this.getModelsByCategory(category);

      // 姣忕被鍙鍔犺浇鍓?5 涓父鐢ㄦā鍨媆n      for (let i = 0; i < Math.min(models.length, 5); i++) {
        try {
          await this.loadComponentModel(models[i].componentId, 'medium');
        } catch {
          /* 鍗曚釜妯″瀷棰勫姞杞藉け璐ヨ烦杩?*/
        }
      }
    }

    return this.libraryIndex;
  }

  /**
   * 娓呴櫎缂撳瓨
   */
  clearCache(): void {
    this.modelCache.clear();
  }

  /**
   * 绉婚櫎宸插姞杞界殑妯″瀷
   */
  removeModel(entityId: string): void {
    const model = this.loadedModels.get(entityId);

    if (model) {
      // 娓呯悊 Three.js 璧勬簮
      model.traverse((child) => {
        if (child instanceof THREE.Mesh) {
          const meshGeometry = child.geometry as THREE.BufferGeometry;
          meshGeometry.dispose();
          if (Array.isArray(child.material)) {
            child.material.forEach((m) => {
              (m as THREE.Material).dispose();
            });
          } else {
            (child.material as THREE.Material).dispose();
          }
        }
      });

      this.loadedModels.delete(entityId);
    }
  }
}

/**
 * WebSocket Notification Service
 *
 * WebSocket 瀹炴椂閫氱煡鎺ㄩ€佹湇鍔n * 鏀寔杩炴帴绠＄悊銆佸績璺虫娴嬨€佽嚜鍔ㄩ噸杩炵瓑鍔熻兘
 *
 * @author iMatu Development Team
 * @version 1.0.0
 */

import { Injectable, OnDestroy } from '@angular/core';
import { BehaviorSubject, Observable, Subject } from 'rxjs';
import { filter, map } from 'rxjs/operators';

import { environment } from '../../../environments/environment';

/**
 * WebSocket 娑堟伅绫诲瀷
 */
export enum WsMessageType {
  /** 閫氱煡娑堟伅 */
  NOTIFICATION = 'notification',
  /** 绯荤粺娑堟伅 */
  SYSTEM = 'system',
  /** 蹇冭烦鍝嶅簲 */
  PONG = 'pong',
  /** 閿欒娑堟伅 */
  ERROR = 'error',
}

/**
 * WebSocket 娑堟伅缁撴瀯
 */
export interface WsMessage<T = unknown> {
  /** 娑堟伅绫诲瀷 */
  type: WsMessageType;

  /** 娑堟伅鍐呭 */
  data: T;

  /** 鍙戦€佹椂闂?*/
  timestamp: string;

  /** 娑堟伅 ID */
  messageId?: string;
}

/**
 * 閫氱煡绫诲瀷鐨勬秷鎭暟鎹甛n */
export interface NotificationMessageData {
  /** 閫氱煡 ID */
  notificationId: number;

  /** 鏍囬 */
  title: string;

  /** 鍐呭鎽樿 */
  summary: string;

  /** 浼樺厛绾?*/
  priority: 'low' | 'medium' | 'high' | 'urgent';

  /** 璺宠浆閾炬帴 */
  link?: string;
}

/**
 * 杩炴帴鐘舵€乗n */
export enum ConnectionStatus {
  /** 鏈繛鎺?*/
  DISCONNECTED = 'disconnected',
  /** 杩炴帴涓?*/
  CONNECTING = 'connecting',
  /** 宸茶繛鎺?*/
  CONNECTED = 'connected',
  /** 閲嶈繛涓?*/
  RECONNECTING = 'reconnecting',
}

/** 閲嶈繛鐘舵€?*/
export interface WsReconnectState {
  attempting: boolean;
  attempt: number;
  maxAttempts: number;
  nextDelay: number;
}

@Injectable({
  providedIn: 'root',
})
export class WebSocketNotificationService implements OnDestroy {
  private ws: WebSocket | null = null;
  private readonly WS_URL = `${environment.wsUrl}/ws/notifications`;

  // 娑堟伅鎺ユ敹鍣╘n  private messageSubject = new Subject<WsMessage>();
  public messages$ = this.messageSubject.asObservable();

  // 杩炴帴鐘舵€乗n  private statusSubject = new BehaviorSubject<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
  public connectionStatus$ = this.statusSubject.asObservable();

  // 閫氱煡娑堟伅娴乗n  public notifications$ = this.messages$.pipe(
    filter((msg) => msg.type === WsMessageType.NOTIFICATION),
    map((msg) => msg.data as NotificationMessageData)
  );

  // 蹇冭烦瀹氭椂鍣╘n  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  private heartbeatTimer: any = null;
  private readonly HEARTBEAT_INTERVAL = 30000; // 30 绉抃n  private pongTimeoutMs = 10000;
  private pongTimeoutTimer: ReturnType<typeof setTimeout> | null = null;
  private lastPongTime: number = 0;

  // 閲嶈繛閰嶇疆
  private reconnectAttempts = 0;
  private maxReconnectAttempts = 5;
  private baseDelay = 2000;
  private maxDelay = 30000;
  private jitterMax = 1000;
  private reconnectTimer: ReturnType<typeof setTimeout> | null = null;

  // 閲嶈繛鐘舵€佹祦
  private reconnectStateSubject = new BehaviorSubject<WsReconnectState>({
    attempting: false,
    attempt: 0,
    maxAttempts: this.maxReconnectAttempts,
    nextDelay: 0,
  });
  readonly reconnectState$ = this.reconnectStateSubject.asObservable();

  // 鏄惁鍚敤 (寮€鍙戞椂鍙鐢?
  private enabled = true;

  private destroy$ = new Subject<void>();

  constructor() {}

  /**
   * 杩炴帴鍒?WebSocket 鏈嶅姟鍣╘n   */
  connect(): void {
    if (!this.enabled || typeof WebSocket === 'undefined') {
      console.warn('WebSocket 涓嶆敮鎸佹垨鏈惎鐢?);
      return;
    }

    if (
      this.ws &&
      (this.ws.readyState === WebSocket.CONNECTING || this.ws.readyState === WebSocket.OPEN)
    ) {
      return;
    }

    this.statusSubject.next(ConnectionStatus.CONNECTING);

    try {
      this.ws = new WebSocket(this.WS_URL);

      this.ws.onopen = () => {
        this.statusSubject.next(ConnectionStatus.CONNECTED);
        this.reconnectAttempts = 0;
        this.lastPongTime = Date.now();
        this.updateReconnectState(false, 0);
        this.startHeartbeat();
        this.startPongTimeout();
      };

      this.ws.onmessage = (event) => {
        try {
          // eslint-disable-next-line @typescript-eslint/no-unsafe-argument
          const message = JSON.parse(event.data) as WsMessage;

          if (message.type === WsMessageType.PONG) {
            this.lastPongTime = Date.now();
          } else if (message.type === WsMessageType.ERROR) {
            console.error('WebSocket 閿欒:', message.data);
          }

          this.messageSubject.next(message);
        } catch (error) {
          console.error('瑙ｆ瀽 WebSocket 娑堟伅澶辫触:', error);
        }
      };

      this.ws.onerror = (error) => {
        console.error('WebSocket 閿欒:', error);
      };

      this.ws.onclose = (event) => {
        this.statusSubject.next(ConnectionStatus.DISCONNECTED);
        this.stopHeartbeat();
        this.stopPongTimeout();

        // 灏濊瘯閲嶈繛锛坈ode 1000=姝ｅ父鍏抽棴涓嶉噸杩烇級
        if (event.code !== 1000 && this.reconnectAttempts < this.maxReconnectAttempts) {
          this.scheduleReconnect();
        }
      };
    } catch (error) {
      console.error('鍒涘缓 WebSocket 杩炴帴澶辫触:', error);
      this.statusSubject.next(ConnectionStatus.DISCONNECTED);
    }
  }

  /**
   * 鏂紑杩炴帴
   */
  disconnect(): void {
    this.stopHeartbeat();
    this.stopPongTimeout();
    this.clearReconnectTimer();

    if (this.ws) {
      this.ws.close(1000, '鐢ㄦ埛涓诲姩鏂紑');
      this.ws = null;
    }

    this.reconnectAttempts = 0;
    this.reconnectStateSubject.next({
      attempting: false,
      attempt: 0,
      maxAttempts: this.maxReconnectAttempts,
      nextDelay: 0,
    });
    this.statusSubject.next(ConnectionStatus.DISCONNECTED);
  }

  /**
   * 鍙戦€佹秷鎭痋n   */
  send<T>(message: WsMessage<T>): void {
    if (this.ws && this.ws.readyState === WebSocket.OPEN) {
      this.ws.send(JSON.stringify(message));
    } else {
      console.warn('WebSocket 鏈繛鎺ワ紝鏃犳硶鍙戦€佹秷鎭?);
    }
  }

  /**
   * 寮€濮嬪績璺砛n   */
  private startHeartbeat(): void {
    this.stopHeartbeat();

    this.heartbeatTimer = setInterval(() => {
      if (this.ws && this.ws.readyState === WebSocket.OPEN) {
        this.send({
          type: WsMessageType.PONG,
          data: {},
          timestamp: new Date().toISOString(),
        });
      }
    }, this.HEARTBEAT_INTERVAL);
  }

  /**
   * 鍋滄蹇冭烦
   */
  private stopHeartbeat(): void {
    if (this.heartbeatTimer) {
      // eslint-disable-next-line @typescript-eslint/no-unsafe-argument
      clearInterval(this.heartbeatTimer);
      this.heartbeatTimer = null;
    }
  }

  /**
   * 璁＄畻鎸囨暟閫€閬垮欢杩燂紙甯︽姈鍔級
   */
  private calculateBackoff(attempt: number): number {
    const exponentialDelay = Math.min(this.maxDelay, this.baseDelay * Math.pow(2, attempt - 1));
    const jitter = Math.random() * this.jitterMax;
    return Math.floor(exponentialDelay + jitter);
  }

  /**
   * 瀹夋帓閲嶈繛
   */
  private scheduleReconnect(): void {
    if (this.reconnectAttempts >= this.maxReconnectAttempts) {
      console.error('WebSocket 閲嶈繛娆℃暟宸茶揪涓婇檺');
      return;
    }

    this.reconnectAttempts++;
    const delay = this.calculateBackoff(this.reconnectAttempts);

    this.statusSubject.next(ConnectionStatus.RECONNECTING);
    this.updateReconnectState(true, delay);

    this.clearReconnectTimer();
    this.reconnectTimer = setTimeout(() => {
      // eslint-disable-next-line no-console
      console.log(`WebSocket 灏濊瘯绗?${this.reconnectAttempts} 娆￠噸杩瀈);
      this.connect();
    }, delay);
  }

  /**
   * 鏇存柊閲嶈繛鐘舵€乗n   */
  private updateReconnectState(attempting: boolean, nextDelay: number): void {
    this.reconnectStateSubject.next({
      attempting,
      attempt: this.reconnectAttempts,
      maxAttempts: this.maxReconnectAttempts,
      nextDelay,
    });
  }

  /**
   * 娓呴櫎閲嶈繛瀹氭椂鍣╘n   */
  private clearReconnectTimer(): void {
    if (this.reconnectTimer) {
      clearTimeout(this.reconnectTimer);
      this.reconnectTimer = null;
    }
  }

  /**
   * 鍚姩 pong 瓒呮椂妫€娴媆n   */
  private startPongTimeout(): void {
    this.stopPongTimeout();

    this.pongTimeoutTimer = setInterval(
      () => {
        if (!this.isConnected()) {
          return;
        }

        const elapsed = Date.now() - this.lastPongTime;
        if (elapsed > this.pongTimeoutMs) {
          this.forceReconnect();
        }
      },
      Math.min(this.pongTimeoutMs, 5000)
    );
  }

  /**
   * 鍋滄 pong 瓒呮椂妫€娴媆n   */
  private stopPongTimeout(): void {
    if (this.pongTimeoutTimer) {
      clearInterval(this.pongTimeoutTimer);
      this.pongTimeoutTimer = null;
    }
  }

  /**
   * 寮哄埗閲嶈繛
   */
  private forceReconnect(): void {
    if (this.ws) {
      this.ws.onclose = null;
      this.ws.close(4001, 'Heartbeat timeout');
      this.ws = null;
    }

    this.statusSubject.next(ConnectionStatus.DISCONNECTED);
    this.stopHeartbeat();
    this.stopPongTimeout();

    if (this.reconnectAttempts < this.maxReconnectAttempts) {
      this.scheduleReconnect();
    }
  }

  /**
   * 鑾峰彇杩炴帴鐘舵€乗n   */
  isConnected(): boolean {
    return this.ws?.readyState === WebSocket.OPEN;
  }

  /**
   * 鐩戝惉鐗瑰畾绫诲瀷鐨勯€氱煡
   */
  onNotificationType(type: WsMessageType): Observable<WsMessage> {
    return this.messages$.pipe(filter((msg) => msg.type === type));
  }

  /**
   * 鍚敤鏈嶅姟
   */
  enable(): void {
    this.enabled = true;
  }

  /**
   * 绂佺敤鏈嶅姟
   */
  disable(): void {
    this.enabled = false;
    this.disconnect();
  }

  ngOnDestroy(): void {
    this.destroy$.next();
    this.destroy$.complete();
    this.clearReconnectTimer();
    this.disconnect();
  }
}

