  // 鍒犻櫎鍒涙剰鎯虫硶
  deleteIdea(ideaId: number): void {
    if (!confirm('纭畾瑕佸垹闄よ繖涓垱鎰忔兂娉曞悧锛?)) return;

    try {
      void this.creativityService.deleteIdea(ideaId);
