        _exportedAt: new Date().toISOString(),
      };

      if (this.electronService.isElectron) {
        // 妗岄潰绔細浣跨敤 Electron 鏂囦欢淇濆瓨瀵硅瘽妗嗭紝淇濆瓨涓?.imato 鏍煎紡
        this.electronService.showSaveDialog().subscribe((result) => {
          if (result.success && result.filePath) {
            const filePath = result.filePath.endsWith('.imato')
              ? result.filePath
              : result.filePath + '.imato';
            this.electronService
              .writeFile(filePath, JSON.stringify(exportData, null, 2))
              .subscribe((writeResult) => {
                if (writeResult.success) {
                  this.snackBar.open('宸蹭繚瀛樹负 .imato 鏂囦欢', '鍏抽棴', { duration: 3000 });
                } else {
