  /** 鍔犺浇鏈湴椤圭洰鍒楄〃 */
  loadLocalProjects(): void {
    const dir = this.currentProjectPath || '鍒涙剰椤圭洰';
    this.electronService.listDirectory(dir).subscribe({
      next: (result) => {
        if (result.success && result.entries) {
          // 浠呮樉绀?.imato 鏂囦欢鍜岀洰褰昞n          this.localProjects = result.entries.filter(
            (e) => e.isDirectory || e.name.endsWith('.imato')
          );
