  /** 鍒犻櫎鏈湴椤圭洰 */
  deleteLocalProject(entry: DirectoryEntry): void {
    if (!confirm(`纭畾瑕佸垹闄?${entry.name} 鍚楋紵`)) return;

    this.electronService.deleteFile(entry.path).subscribe({
      next: (result) => {
        if (result.success) {
          this.snackBar.open(`宸插垹闄? ${entry.name}`, '鍏抽棴', { duration: 2000 });
          this.loadLocalProjects();
        } else {
          this.snackBar.open('鍒犻櫎澶辫触', '鍏抽棴', { duration: 3000 });
        }
      },
      error: () => {
        this.snackBar.open('鍒犻櫎澶辫触', '鍏抽棴', { duration: 3000 });
      },
    });
