  /** 鑾峰彇鏈湴椤圭洰鍒楄〃鏄剧ず鐘舵€?*/
  isLocalProjectEmpty(): boolean {
    return this.localProjects.length === 0;
  }

  // 鑾峰彇璇勫垎棰滆壊
  getScoreColor(score: number): string {
    if (score >= 8) return 'success';
    if (score >= 6) return 'warning';
    return 'error';
  }

  // 鑾峰彇璇勫垎鎻忚堪
  getScoreDescription(score: number): string {
    if (score >= 8) return '浼樼';
    if (score >= 6) return '鑹ソ';
    if (score >= 4) return '涓€鑸?;
    return '闇€瑕佹敼杩?;
  }

  // 鏍煎紡鍖栨椂闂翠负鍙嬪ソ鏄剧ず
  formatTime(dateString: string | undefined): string {
    if (!dateString) return '鏈煡鏃堕棿';
    const date = new Date(dateString);
    const now = new Date();
    const diffMs = now.getTime() - date.getTime();
    const diffDays = Math.floor(diffMs / (1000 * 60 * 60 * 24));

    if (diffDays === 0) {
      return '浠婂ぉ';
    } else if (diffDays === 1) {
      return '鏄ㄥぉ';
    } else if (diffDays < 7) {
      return `${diffDays}澶╁墠`;
    } else {
      return date.toLocaleDateString();
    }
  }

  // 鑾峰彇鍒嗙被鏍囩
  getCategoryLabel(category: string | undefined): string {
    if (!category) return '鏈煡';
    const categoryObj = this.categories.find((c) => c.value === category);
    return categoryObj ? categoryObj.label : category;
  }

  getIdeaContent(idea: CreativeIdeaResponse | null): string {
    if (!idea) return '';

    if (typeof idea.ai_generated_content === 'string') {
      return idea.ai_generated_content;
    } else if (typeof idea.description === 'string') {
      return idea.description;
    } else if (idea.ai_generated_content && typeof idea.ai_generated_content === 'object') {
      return JSON.stringify(idea.ai_generated_content);
    }

    return '';
  }

  // 妫€鏌ヨ〃鍗曟湁鏁堟€n  isFormValid(): boolean {
    return (
      this.ideaForm.valid &&
      (this.ideaForm.get('templateId')?.value || this.ideaForm.get('customPrompt')?.value)
    );
  }
}

import { Injectable, OnDestroy } from '@angular/core';

import { ExamService } from './exam.service';

/**
 * 鍓嶇闃蹭綔寮婃湇鍔n *
 * 瀹炵幇瀹㈡埛绔槻浣滃紛妫€娴嬶細
 * - 灞忓箷/鏍囩椤靛垏鎹㈡娴媆n * - 澶嶅埗绮樿创绂佺敤
 * - 鍏ㄥ睆妯″紡妫€娴媆n * - 瀹氭椂蹇冭烦涓婃姤
 */
@Injectable({
  providedIn: 'root',
})
export class AntiCheatService implements OnDestroy {
  private screenSwitchCount = 0;
  private attemptId: number | null = null;
  private heartbeatInterval: ReturnType<typeof setInterval> | null = null;
  private fullscreenMode = false;
  private pasteBlocked = false;

  // 浜嬩欢澶勭悊鍣ㄥ紩鐢紙鐢ㄤ簬鍙栨秷鐩戝惉锛塡n  private onVisibilityChange = (): void => this.handleVisibilityChange();
  private onBlur = (): void => this.handleBlur();
  private onFocus = (): void => this.handleFocus();
  private onPaste = (e: ClipboardEvent): void => this.handlePaste(e);
  private onCopy = (e: ClipboardEvent): void => this.handleCopy(e);
  private onBeforeUnload = (e: BeforeUnloadEvent): void => this.handleBeforeUnload(e);

  constructor(private examService: ExamService) {}

  /**
   * 寮€濮嬮槻浣滃紛鐩戞帶
   */
  startMonitoring(
    attemptId: number,
    options?: {
      restrictPaste?: boolean;
      restrictCopy?: boolean;
      fullscreenRequired?: boolean;
    }
  ): void {
    this.attemptId = attemptId;
    this.screenSwitchCount = 0;

    // 娉ㄥ唽浜嬩欢鐩戝惉
    document.addEventListener('visibilitychange', this.onVisibilityChange);

    if (options?.fullscreenRequired) {
      this.requestFullscreen();
    }

    if (options?.restrictPaste !== false) {
      document.addEventListener('paste', this.onPaste as EventListener, true);
      this.pasteBlocked = true;
    }

    if (options?.restrictCopy !== false) {
      document.addEventListener('copy', this.onCopy as EventListener, true);
    }

    // 绐楀彛 blur/focus 妫€娴嬶紙澶囩敤锛塡n    window.addEventListener('blur', this.onBlur);
    window.addEventListener('focus', this.onFocus);

    // 椤甸潰鍏抽棴鎻愰啋
    window.addEventListener('beforeunload', this.onBeforeUnload);

    // 鍚姩蹇冭烦锛堟瘡 30 绉掞級
    this.heartbeatInterval = setInterval(() => this.sendHeartbeat(), 30000);
  }

  /**
   * 鍋滄闃蹭綔寮婄洃鎺n   */
  stopMonitoring(): void {
    document.removeEventListener('visibilitychange', this.onVisibilityChange);
    document.removeEventListener('paste', this.onPaste as EventListener, true);
    document.removeEventListener('copy', this.onCopy as EventListener, true);
    window.removeEventListener('blur', this.onBlur);
    window.removeEventListener('focus', this.onFocus);
    window.removeEventListener('beforeunload', this.onBeforeUnload);

    if (this.heartbeatInterval) {
      clearInterval(this.heartbeatInterval);
      this.heartbeatInterval = null;
    }

    this.exitFullscreen();
    this.attemptId = null;
  }

  private handleVisibilityChange(): void {
    if (document.hidden) {
      this.screenSwitchCount++;
      // 涓婃姤鏍囩椤靛垏鎹簨浠禱n      this.reportEvent('tab_switch', { switch_count: this.screenSwitchCount });
    }
  }

  private handleBlur(): void {
    this.screenSwitchCount++;
    this.reportEvent('screen_switch', { switch_count: this.screenSwitchCount });
  }

  private handleFocus(): void {
    // 鐒︾偣鍥炴潵鏃舵鏌ュ叏灞忕姸鎬乗n    this.checkFullscreen();
  }

  private handlePaste(e: ClipboardEvent): void {
    e.preventDefault();
    const content = e.clipboardData?.getData('text') ?? '';
    this.reportEvent('copy_paste', { action: 'paste', content_length: content.length });
  }

  private handleCopy(e: ClipboardEvent): void {
    e.preventDefault();
  }

  private handleBeforeUnload(e: BeforeUnloadEvent): void {
    // 涓婃姤椤甸潰鍏抽棴
    this.reportEvent('screen_switch', { action: 'page_close' });
    e.preventDefault();
    e.returnValue = '';
  }

  private requestFullscreen(): void {
    const elem = document.documentElement;
    if (elem.requestFullscreen) {
      elem
        .requestFullscreen()
        .then(() => {
          this.fullscreenMode = true;
        })
        .catch(() => {
          this.reportEvent('screen_switch', { action: 'fullscreen_failed' });
        });
    }
  }

  private exitFullscreen(): void {
    if (document.fullscreenElement && document.exitFullscreen) {
      document.exitFullscreen().catch(() => {});
    }
  }

  private checkFullscreen(): void {
    if (this.fullscreenMode && !document.fullscreenElement) {
      this.reportEvent('screen_switch', { action: 'exited_fullscreen' });
      this.requestFullscreen();
    }
  }

  private sendHeartbeat(): void {
    if (this.attemptId) {
      this.examService
        .reportCheatEvent(this.attemptId, 'heartbeat', {
          screen_switches: this.screenSwitchCount,
          timestamp: Date.now(),
        })
        .subscribe({
          error: (err) => console.warn('[AntiCheat] Heartbeat failed:', err),
        });
    }
  }

  private reportEvent(cheatType: string, details: Record<string, any>): void {
    if (this.attemptId) {
      this.examService.reportCheatEvent(this.attemptId, cheatType, details).subscribe({
        error: (err) => console.warn('[AntiCheat] Report failed:', err),
      });
    }
  }

  ngOnDestroy(): void {
    this.stopMonitoring();
  }
}

import { CommonModule, DecimalPipe, NgClass } from '@angular/common';
import { HttpClient } from '@angular/common/http';
import { Component, ElementRef, OnDestroy, OnInit, ViewChild } from '@angular/core';
import { FormsModule } from '@angular/forms';
import { MatButtonModule } from '@angular/material/button';
import { MatCardModule } from '@angular/material/card';
import { MatDialog } from '@angular/material/dialog';
import { MatIconModule } from '@angular/material/icon';
import { MatProgressSpinnerModule } from '@angular/material/progress-spinner';
import { MatSlideToggleModule } from '@angular/material/slide-toggle';
import { MatSnackBar } from '@angular/material/snack-bar';
import { ActivatedRoute, Router } from '@angular/router';
import { Subject } from 'rxjs';

import { CircuitShortcutRegistrar } from '../../../core/services/circuit-shortcut-registrar.service';
import { ElectronService } from '../../../core/services/electron.service';

import { CircuitShortcutHelpDialogComponent } from './circuit-shortcut-help-dialog.component';

interface CircuitElement {
  element_id: string;
  element_type: string;
  voltage: number;
  current: number;
  power: number;
  node1: string;
  node2: string;
  parameter_value: number;
}

interface CircuitState {
  session_id: string;
  elements: CircuitElement[];
  total_power: number;
  total_current: number;
  simulation_time: number;
  timestamp: string;
}

interface DeviceState {
  device_id: string;
  device_type: string;
  voltage: number;
  current: number;
  temperature: number;
  is_connected: boolean;
  custom_properties?: Record<string, unknown>;
  timestamp: string;
}

interface SessionInfo {
  session_id: string;
  host_user_id: number;
  participant_count: number;
  created_at: string;
  is_active: boolean;
}

// Unity WebGL 绫诲瀷瀹氫箟
interface UnityInstanceType {
  SendMessage(objectName: string, methodName: string, value?: string): void;
  Quit(): void;
}

interface UnityConfigType {
  dataUrl: string;
  frameworkUrl: string;
  codeUrl: string;
  streamingAssetsUrl: string;
  companyName: string;
  productName: string;
  productVersion: string;
  showBanner: boolean;
}

interface WindowWithUnity extends Window {
  createUnityInstance?: (
    canvas: HTMLCanvasElement,
    config: UnityConfigType,
    onProgress?: (progress: number) => void
  ) => Promise<UnityInstanceType>;
  sendToUnity?: (objectName: string, methodName: string, value: string) => void;
  receiveFromUnity?: (message: string) => void;
}

@Component({
  selector: 'app-digital-twin-lab',
  templateUrl: './digital-twin-lab.component.html',
  styleUrls: ['./digital-twin-lab.component.scss'],
  imports: [
    MatIconModule,
    MatCardModule,
    MatSlideToggleModule,
    MatButtonModule,
    MatProgressSpinnerModule,
    FormsModule,
    CommonModule,
    DecimalPipe,
    NgClass,
  ],
})
export class DigitalTwinLabComponent implements OnInit, OnDestroy {
  @ViewChild('unityContainer') unityContainer!: ElementRef;

  sessionId!: string;
  sessionInfo!: SessionInfo;
  isLoading = true;
  errorMessage = '';

  // Unity WebGL 鐩稿叧
  unityInstance: UnityInstanceType | null = null;
  isUnityLoaded = false;

  // 缃戠粶鐘舵€乗n  isConnected = false;
  participantCount = 1;

  // 鐢佃矾鐘舵€乗n  circuitState: CircuitState | null = null;
  deviceStates: Map<string, DeviceState> = new Map();

  // 鎺у埗闈㈡澘鐘舵€乗n  isSimulationRunning = false;
  isDeviceSyncEnabled = true;
  isFullscreen = false;

  private destroy$ = new Subject<void>();
  private webSocket!: WebSocket;
  private baseUrl = '/api/v1'; // 浠ｇ悊鍒板悗绔痋n
  constructor(
    private route: ActivatedRoute,
    private router: Router,
    private http: HttpClient,
    private snackBar: MatSnackBar,
    private dialog: MatDialog,
    private electronService: ElectronService,
    private shortcutRegistrar: CircuitShortcutRegistrar
  ) {}

  ngOnInit(): void {
    this.sessionId = this.route.snapshot.paramMap.get('id') ?? '';
    this.loadSession();
    this.initializeWebSocket();
    this.setupKeyboardShortcuts();
  }

  ngOnDestroy(): void {
    this.destroy$.next();
    this.destroy$.complete();
    this.shortcutRegistrar.unregister();
    this.cleanupConnections();
  }

  loadSessionPublic(): void {
    this.loadSession();
  }

  private loadSession(): void {
    this.http
      .get<SessionInfo>(`${this.baseUrl}/digital-twin/sessions/${this.sessionId}`)
      .subscribe({
        next: (session) => {
          this.sessionInfo = session;
          this.isLoading = false;
          this.loadUnityContent();
          this.snackBar.open('鏁板瓧瀛敓瀹為獙瀹ゅ凡鍔犺浇', '鍏抽棴', { duration: 2000 });
        },
        error: (_error) => {
          this.errorMessage = '鍔犺浇浼氳瘽澶辫触';
          this.isLoading = false;
          this.snackBar.open('浼氳瘽鍔犺浇澶辫触', '鍏抽棴', { duration: 3000 });
        },
      });
  }

  private loadUnityContent(): void {
    // 鍔ㄦ€佸姞杞経nity WebGL鏋勫缓
    const script = document.createElement('script');
    script.src = `/digital-twin/builds/lab/index.html`;
    script.onload = () => {
      this.initializeUnityPlayer();
    };
    script.onerror = () => {
      this.snackBar.open('Unity鍐呭鍔犺浇澶辫触', '鍏抽棴', { duration: 3000 });
    };
    document.head.appendChild(script);
  }

  private initializeUnityPlayer(): void {
    // Unity WebGL 鍒濆鍖栭厤缃甛n    const unityConfig: UnityConfigType = {
      dataUrl: '/digital-twin/builds/lab/Build/lab.data',
      frameworkUrl: '/digital-twin/builds/lab/Build/lab.framework.js',
      codeUrl: '/digital-twin/builds/lab/Build/lab.wasm',
      streamingAssetsUrl: 'StreamingAssets',
      companyName: 'iMatu',
      productName: 'Digital Twin Lab',
      productVersion: '1.0',
      showBanner: false,
    };

    // 鍒涘缓 Unity 瀹炰緥
    const win = window as WindowWithUnity;
    if (win.createUnityInstance) {
      win
        .createUnityInstance(
          this.unityContainer.nativeElement as HTMLCanvasElement,
          unityConfig,
          (_progress: number) => {
            // 寮€鍙戠幆澧冧笅璁板綍 Unity 鍔犺浇杩涘害
            if (typeof ngDevMode === 'undefined' || ngDevMode) {
              // 寮€鍙戞ā寮忔棩蹇楀凡绂佺敤
            }
          }
        )
        .then((instance: UnityInstanceType) => {
          this.unityInstance = instance;
          this.isUnityLoaded = true;
          this.setupUnityCommunication();
          this.snackBar.open('Unity 瀹為獙瀹ゅ凡灏辩华', '鍏抽棴', { duration: 2000 });
        })
        .catch((_error: unknown) => {
          this.snackBar.open('Unity 鍚姩澶辫触', '鍏抽棴', { duration: 3000 });
        });
    }
  }

  private setupUnityCommunication(): void {
    // 璁剧疆涓?Unity 鐨勫弻鍚戦€氫俊
    const win = window as WindowWithUnity;

    win.sendToUnity = (objectName: string, methodName: string, value: string) => {
      this.unityInstance?.SendMessage(objectName, methodName, value);
    };

    // 鎺ユ敹鏉ヨ嚜 Unity 鐨勬秷鎭痋n    win.receiveFromUnity = (message: string) => {
      this.handleUnityMessage(message);
    };
  }

  private handleUnityMessage(message: string): void {
    try {
      const data = JSON.parse(message) as {
        type: string;
        state?: CircuitState | DeviceState;
        action?: string;
      };

      switch (data.type) {
        case 'circuit_state_update':
          if (data.state) {
            this.sendCircuitStateToBackend(data.state as CircuitState);
          }
          break;

        case 'device_state_update':
          if (data.state) {
            this.sendDeviceStateToBackend(data.state as DeviceState);
          }
          break;

        case 'simulation_control':
          if (data.action) {
            this.handleSimulationControl(data.action);
          }
          break;

        default:
      }
    } catch (_error) {
      // 閿欒宸查潤榛樺鐞哱n    }
  }

  private handleSimulationControl(action: string): void {
    switch (action) {
      case 'start':
        this.isSimulationRunning = true;
        break;
      case 'stop':
        this.isSimulationRunning = false;
        break;
      case 'reset':
        this.resetCircuit();
        break;
      default:
    }
  }

  private initializeWebSocket(): void {
    const wsUrl = `ws://${window.location.host}/api/v1/digital-twin/ws/session/${this.sessionId}?user_id=user_${Math.random()}`;

    try {
      this.webSocket = new WebSocket(wsUrl);

      this.webSocket.onopen = () => {
        this.isConnected = true;

        this.snackBar.open('瀹炴椂杩炴帴宸插缓绔?, '鍏抽棴', { duration: 2000 });
      };

      this.webSocket.onmessage = (event: MessageEvent<string>) => {
        this.handleWebSocketMessage(event.data);
      };

      this.webSocket.onclose = () => {
        this.isConnected = false;

        // 灏濊瘯閲嶈繛
        setTimeout(() => this.initializeWebSocket(), 5000);
      };

      this.webSocket.onerror = (_error) => {
        this.snackBar.open('杩炴帴鍑虹幇閿欒', '鍏抽棴', { duration: 3000 });
      };
    } catch (_error) {
      this.snackBar.open('鏃犳硶寤虹珛瀹炴椂杩炴帴', '鍏抽棴', { duration: 3000 });
    }
  }

  private handleWebSocketMessage(data: string): void {
    try {
      // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment
      const message = JSON.parse(data) as {
        type: string;
        state?: CircuitState | DeviceState;
        device_id?: string;
        message?: string;
      };

      switch (message.type) {
        case 'circuit_state_broadcast':
          if (message.state) {
            this.updateCircuitState(message.state as CircuitState);
          }
          break;

        case 'device_state_broadcast':
          if (message.device_id && message.state) {
            this.updateDeviceState(message.device_id, message.state as DeviceState);
          }
          break;

        case 'sync_response':
          this.handleSyncResponse(message);
          break;

        case 'error':
          if (message.message) {
            this.snackBar.open(`閿欒锛?{message.message}`, '鍏抽棴', { duration: 3000 });
          }
          break;

        default:
      }
    } catch (_error) {
      // 閿欒宸查潤榛樺鐞哱n    }
  }

  private updateCircuitState(state: CircuitState): void {
    this.circuitState = state;

    // 鍚屾鍒?Unity
    if (this.isUnityLoaded) {
      const win = window as WindowWithUnity;
      win.sendToUnity?.('CircuitManager', 'UpdateCircuitState', JSON.stringify(state));
    }

    // 鏇存柊UI鏄剧ず
    this.participantCount = state.elements?.length || 0;
  }

  private updateDeviceState(deviceId: string, state: DeviceState): void {
    this.deviceStates.set(deviceId, state);

    // 鍚屾鍒?Unity
    if (this.isUnityLoaded) {
      const message = { deviceId, state };
      const win = window as WindowWithUnity;
      win.sendToUnity?.('DeviceManager', 'UpdateDeviceState', JSON.stringify(message));
    }
  }

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  private handleSyncResponse(message: any): void {
    const typedMessage = message as { circuit_state?: CircuitState; device_states?: DeviceState[] };

    if (typedMessage.circuit_state) {
      this.updateCircuitState(typedMessage.circuit_state);
    }

    if (typedMessage.device_states) {
      typedMessage.device_states.forEach((deviceState: DeviceState) => {
        this.deviceStates.set(deviceState.device_id, deviceState);
      });
    }

    this.snackBar.open('鐘舵€佸悓姝ュ畬鎴?, '鍏抽棴', { duration: 2000 });
  }

  // 鍙戦€佺數璺姸鎬佸埌鍚庣
  private sendCircuitStateToBackend(state: CircuitState): void {
    if (!this.isConnected) return;

    const message = {
      type: 'circuit_state_update',
      session_id: this.sessionId,
      state,
      sender: 'frontend',
    };

    this.webSocket.send(JSON.stringify(message));
  }

  // 鍙戦€佽澶囩姸鎬佸埌鍚庣
  private sendDeviceStateToBackend(state: DeviceState): void {
    if (!this.isConnected) return;

    const message = {
      type: 'device_state_update',
      session_id: this.sessionId,
      state,
    };

    this.webSocket.send(JSON.stringify(message));
  }

  // 浠跨湡鎺у埗
  toggleSimulation(): void {
    this.isSimulationRunning = !this.isSimulationRunning;

    if (this.isUnityLoaded) {
      const win = window as WindowWithUnity;
      win.sendToUnity?.(
        'SimulationController',
        'ToggleSimulation',
        this.isSimulationRunning.toString()
      );
    }

    const action = this.isSimulationRunning ? '寮€濮? : '鍋滄';
    this.snackBar.open(`浠跨湡宸?{action}`, '鍏抽棴', { duration: 2000 });
  }

  // 璁惧鍚屾鎺у埗
  toggleDeviceSync(): void {
    this.isDeviceSyncEnabled = !this.isDeviceSyncEnabled;

    if (this.isUnityLoaded) {
      const win = window as WindowWithUnity;
      win.sendToUnity?.('IoTManager', 'ToggleDeviceSync', this.isDeviceSyncEnabled.toString());
    }

    const status = this.isDeviceSyncEnabled ? '鍚敤' : '绂佺敤';
    this.snackBar.open(`璁惧鍚屾宸?{status}`, '鍏抽棴', { duration: 2000 });
  }

  // 閲嶇疆鐢佃矾
  resetCircuit(): void {
    if (this.isUnityLoaded) {
      const win = window as WindowWithUnity;
      win.sendToUnity?.('CircuitManager', 'ResetCircuit', '');
      this.snackBar.open('鐢佃矾宸查噸缃?, '鍏抽棴', { duration: 2000 });
    }
  }

  // 娣诲姞鍏冧欢
  addElement(elementType: string): void {
    if (this.isUnityLoaded) {
      const win = window as WindowWithUnity;
      win.sendToUnity?.('CircuitManager', 'AddElement', elementType);
      this.snackBar.open(`宸叉坊鍔?{elementType}鍏冧欢`, '鍏抽棴', { duration: 2000 });
    }
  }

  // 鑾峰彇浼氳瘽淇℃伅
  getSessionDetails(): void {
    this.http
      .get<{
        participant_count: number;
      }>(`${this.baseUrl}/digital-twin/sessions/${this.sessionId}/participants`)
      .subscribe({
        next: (data) => {
          this.participantCount = data.participant_count;
          // 鏄剧ず璇︾粏淇℃伅瀵硅瘽妗哱n          this.showSessionDialog(data);
        },
        error: (_error) => {
          // 闈欓粯澶勭悊閿欒
        },
      });
  }

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  private showSessionDialog(_data: any): void {
    // 杩欓噷鍙互鍒涘缓涓€涓?Material Dialog 缁勪欢鏄剧ず浼氳瘽璇︽儏
  }

  // 杩斿洖涓婚〉
  goBack(): void {
    void this.router.navigate(['/dashboard']);
  }

  // 鍏ㄥ睆鍒囨崲
  toggleFullscreen(): void {
    if (!document.fullscreenElement) {
      // eslint-disable-next-line @typescript-eslint/no-unsafe-call, @typescript-eslint/no-unsafe-member-access
      this.unityContainer.nativeElement.requestFullscreen();
    } else {
      void document.exitFullscreen();
    }
  }

  // 寮瑰嚭鐙珛瀹為獙绐楀彛锛圥RD F-09 妗岄潰绔€傞厤锛氬绐楀彛妯″紡锛塡n  openInNewWindow(): void {
    if (!this.electronService.isElectron) {
      // 娴忚鍣ㄧ闄嶇骇锛氭柊鏍囩椤垫墦寮€
      window.open(`/digital-twin-lab/${this.sessionId}`, '_blank');
      return;
    }

    // Electron 绔細閫氳繃 IPC 璇锋眰涓昏繘绋嬪垱寤烘柊绐楀彛
    this.electronService.sendAppEvent({
      type: 'open-new-window' as never,
      url: `/digital-twin-lab/${this.sessionId}`,
      title: `鏁板瓧瀛敓瀹為獙 - ${this.sessionId}`,
      width: 1280,
      height: 800,
    } as never);

    this.snackBar.open('瀹為獙绐楀彛宸插脊鍑?, '鍏抽棴', { duration: 2000 });
  }

  // 鑾峰彇骞冲潎鐢靛帇
  getAverageVoltage(): number {
    if (this.deviceStates.size === 0) return 0;

    let sum = 0;
    let count = 0;
    this.deviceStates.forEach((state) => {
      if (state.is_connected) {
        sum += state.voltage;
        count++;
      }
    });

    return count > 0 ? sum / count : 0;
  }

  // 鑾峰彇鍓峃涓厓浠禱n  getTopElements(count: number): CircuitElement[] {
    if (!this.circuitState?.elements) return [];

    // 鎸夊姛鐜囨帓搴忥紝杩斿洖鍓峜ount涓猏n    return [...this.circuitState.elements]
      .sort((a, b) => Math.abs(b.power) - Math.abs(a.power))
      .slice(0, count);
  }

  /** 璁剧疆閿洏蹇嵎閿?*/
  private setupKeyboardShortcuts(): void {
    // 寤舵椂娉ㄥ唽锛岀‘淇?DOM 娓叉煋瀹屾垚
    setTimeout(() => {
      const element = document.querySelector('.digital-twin-lab') as HTMLElement;
      if (!element) return;

      // 璁剧疆 tabindex 浠ユ帴鏀堕敭鐩樹簨浠禱n      element.tabIndex = -1;
      element.focus();

      this.shortcutRegistrar.register(element, (action) => {
        this.handleShortcutAction(action);
      });
    }, 500);
  }

  /** 澶勭悊蹇嵎閿姩浣?*/
  private handleShortcutAction(action: string): void {
    switch (action) {
      case 'rotate':
        if (this.isUnityLoaded) {
          const win = window as WindowWithUnity;
          win.sendToUnity?.('CircuitManager', 'RotateSelected', '');
          this.snackBar.open('鏃嬭浆閫変腑鍏冧欢', '鍏抽棴', { duration: 1000 });
        }
        break;

      case 'delete':
        if (this.isUnityLoaded) {
          const win = window as WindowWithUnity;
          win.sendToUnity?.('CircuitManager', 'DeleteSelected', '');
          this.snackBar.open('鍒犻櫎閫変腑鍏冧欢', '鍏抽棴', { duration: 1000 });
        }
        break;

      case 'undo':
        if (this.isUnityLoaded) {
          const win = window as WindowWithUnity;
          win.sendToUnity?.('CircuitManager', 'Undo', '');
          this.snackBar.open('鎾ら攢', '鍏抽棴', { duration: 1000 });
        }
        break;

      case 'redo':
        if (this.isUnityLoaded) {
          const win = window as WindowWithUnity;
          win.sendToUnity?.('CircuitManager', 'Redo', '');
          this.snackBar.open('閲嶅仛', '鍏抽棴', { duration: 1000 });
        }
        break;

      case 'cancel':
        if (this.isUnityLoaded) {
          const win = window as WindowWithUnity;
          win.sendToUnity?.('CircuitManager', 'CancelSelection', '');
        }
        break;

      case 'selectAll':
        if (this.isUnityLoaded) {
          const win = window as WindowWithUnity;
          win.sendToUnity?.('CircuitManager', 'SelectAll', '');
          this.snackBar.open('宸插叏閫?, '鍏抽棴', { duration: 1000 });
        }
        break;

      case 'copy':
      case 'paste':
        if (this.isUnityLoaded) {
          const win = window as WindowWithUnity;
          win.sendToUnity?.('ClipboardManager', action === 'copy' ? 'Copy' : 'Paste', '');
        }
        break;

      case 'save':
        this.snackBar.open('鐢佃矾宸蹭繚瀛?, '鍏抽棴', { duration: 2000 });
        if (this.isUnityLoaded) {
          const win = window as WindowWithUnity;
          win.sendToUnity?.('CircuitManager', 'SaveCircuit', '');
        }
        break;

      case 'new':
        this.resetCircuit();
        this.snackBar.open('宸叉柊寤虹數璺?, '鍏抽棴', { duration: 2000 });
        break;

      case 'zoomIn':
        this.adjustZoom(1.2);
        break;

      case 'zoomOut':
        this.adjustZoom(0.8);
        break;

      case 'resetZoom':
        this.adjustZoom(1);
        break;

      case 'help':
        this.showShortcutHelp();
        break;
    }
  }

  /** 璋冩暣 Unity 瑙嗗浘缂╂斁 */
  private adjustZoom(factor: number): void {
    if (this.isUnityLoaded) {
      const win = window as WindowWithUnity;
      win.sendToUnity?.('CameraController', 'AdjustZoom', factor.toString());
    }
  }

  /** 鏄剧ず蹇嵎閿府鍔╅潰鏉?*/
  private showShortcutHelp(): void {
    const groups = this.shortcutRegistrar.getGroupedShortcuts();
    this.dialog.open(CircuitShortcutHelpDialogComponent, {
      data: groups,
      width: '480px',
      autoFocus: false,
    });
  }

  private cleanupConnections(): void {
    if (this.webSocket) {
      this.webSocket.close();
    }

    if (this.unityInstance) {
      this.unityInstance.Quit();
    }
  }
}

/**
 * 澶氭爣绛鹃〉缂栬緫鍣ㄧ粍浠禱n *
 * 妗岄潰绔壒鎬э細鏀寔澶氫釜鏂囦欢鏍囩椤靛悓鏃剁紪杈慭n * - 鍩轰簬 Monaco Editor 鐨勫鏍囩椤电紪杈慭n * - 鏍囩椤靛垏鎹?(Ctrl+Tab / Ctrl+Shift+Tab)
 * - 鏍囩椤靛叧闂?(Ctrl+W)
 * - 鏂板缓鏍囩椤?(Ctrl+N)
 * - 鏂囦欢淇濆瓨 (Ctrl+S / Ctrl+Shift+S)
 * - 杩愯浠ｇ爜 (Ctrl+Enter / F5)
 */
import { CommonModule } from '@angular/common';
import {
  ChangeDetectionStrategy,
  ChangeDetectorRef,
  Component,
  EventEmitter,
  Input,
  OnDestroy,
  Output,
} from '@angular/core';
import { FormsModule } from '@angular/forms';
import { MatButtonModule } from '@angular/material/button';
import { MatIconModule } from '@angular/material/icon';
import { MatMenuModule } from '@angular/material/menu';
import { MatTooltipModule } from '@angular/material/tooltip';
import { MonacoEditorModule } from 'ngx-monaco-editor-v2';

/** Electron API 妗ユ帴鎺ュ彛 */
interface ElectronFileResult {
  success: boolean;
  content?: string;
  filePath?: string;
  error?: string;
}

interface ElectronDialogResult {
  success: boolean;
  filePath?: string;
  error?: string;
}

interface ElectronAPI {
  showSaveDialog: (opts?: Record<string, unknown>) => Promise<ElectronDialogResult>;
  showOpenDialog: () => Promise<ElectronDialogResult & { filePaths?: string[] }>;
  readFile: (filePath: string) => Promise<ElectronFileResult>;
  writeFile: (filePath: string, content: string) => Promise<ElectronFileResult>;
  getFileInfo: (filePath: string) => Promise<{ success: boolean; size?: number; error?: string }>;
}

function getElectronAPI(): ElectronAPI | null {
  const api = (window as unknown as { electronAPI?: ElectronAPI }).electronAPI;
  return api ?? null;
}

/** 缂栬緫鍣ㄦ爣绛鹃〉 */
export interface EditorTab {
  /** 鍞竴鏍囪瘑 */
  id: string;
  /** 鏄剧ず鍚嶇О */
  title: string;
  /** 鏂囦欢璺緞锛堟湰鍦版枃浠舵墠鏈夛級 */
  filePath?: string;
  /** 鏂囦欢鍐呭 */
  content: string;
  /** 缂栫▼璇█ */
  language: string;
  /** 鏄惁宸蹭慨鏀癸紙鏈繚瀛橈級 */
  isDirty: boolean;
  /** 鍥炬爣鍚嶇О */
  icon?: string;
}

/** 浠ｇ爜杩愯缁撴灉 */
export interface TabRunResult {
  tabId: string;
  success: boolean;
  output: string;
  error?: string;
  executionTime?: number;
}

@Component({
  selector: 'app-tabbed-editor',
  standalone: true,
  imports: [
    CommonModule,
    FormsModule,
    MatButtonModule,
    MatIconModule,
    MatMenuModule,
    MatTooltipModule,
    MonacoEditorModule,
  ],
  templateUrl: './tabbed-editor.component.html',
  styleUrls: ['./tabbed-editor.component.scss'],
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class TabbedEditorComponent implements OnDestroy {
  /** 鏍囩椤靛垪琛?*/
  @Input() tabs: EditorTab[] = [];

  /** 褰撳墠婵€娲荤殑鏍囩椤?ID */
  @Input() activeTabId: string | null = null;

  /** 鏄惁姝ｅ湪杩愯浠ｇ爜 */
  @Input() isRunning = false;

  /** 杩愯缁撴灉 */
  @Input() lastRunResult: TabRunResult | null = null;

  /** 鏍囩椤靛垏鎹簨浠?*/
  @Output() tabChange = new EventEmitter<string>();

  /** 鏍囩椤靛叧闂簨浠?*/
  @Output() tabClose = new EventEmitter<string>();

  /** 鍐呭鍙樻洿浜嬩欢 */
  @Output() contentChange = new EventEmitter<{ tabId: string; content: string }>();

  /** 淇濆瓨璇锋眰浜嬩欢 */
  @Output() saveRequest = new EventEmitter<string>();

  /** 杩愯浠ｇ爜浜嬩欢 */
  @Output() runRequest = new EventEmitter<string>();

  /** 鏂板缓鏍囩椤佃姹備簨浠?*/
  @Output() newTabRequest = new EventEmitter<void>();

  /** 鎵撳紑鏂囦欢璇锋眰浜嬩欢 */
  @Output() openFileRequest = new EventEmitter<void>();

  /** 閫氳繃 Electron IPC 鎵撳紑鏂囦欢鍚庡彂鍑虹殑浜嬩欢 */
  @Output() fileOpened = new EventEmitter<EditorTab>();

  /** 閫氳繃 Electron IPC 淇濆瓨鏂囦欢鍚庡彂鍑虹殑浜嬩欢 */
  @Output() fileSaved = new EventEmitter<{ tabId: string; filePath: string }>();

  /** 涓婚鍒囨崲浜嬩欢 */
  @Output() themeChange = new EventEmitter<'vs-dark' | 'vs' | 'hc-black'>();

  /** 鏄惁鏄剧ず杈撳嚭闈㈡澘 */
  showOutput = false;

  /** 褰撳墠缂栬緫鍣ㄤ富棰?*/
  @Input() editorTheme: 'vs-dark' | 'vs' | 'hc-black' = 'vs-dark';

  /** 閿洏蹇嵎閿洃鍚櫒寮曠敤 */
  private keydownHandler: ((e: KeyboardEvent) => void) | null = null;

  /** Electron API 瀹炰緥锛堜粎鍦?Electron 鐜鍙敤锛?*/
  private readonly electronApi = getElectronAPI();

  /** 鏄惁杩愯鍦?Electron 鐜 */
  get isElectron(): boolean {
    return this.electronApi !== null;
  }

  constructor(private cdr: ChangeDetectorRef) {
    this.registerKeyboardShortcuts();
  }

  /** 鑾峰彇 Monaco 缂栬緫鍣ㄩ€夐」 */
  getEditorOptions(language: string): Record<string, unknown> {
    return {
      theme: this.editorTheme,
      language,
      fontSize: 14,
      minimap: { enabled: false },
      automaticLayout: true,
      scrollBeyondLastLine: false,
      tabSize: 4,
      insertSpaces: true,
      bracketPairColorization: { enabled: true },
      padding: { top: 8 },
      smoothScrolling: true,
      cursorBlinking: 'smooth',
      renderWhitespace: 'selection',
      suggest: { showWords: true, showSnippets: true },
      quickSuggestions: true,
    };
  }

  /** 鍒囨崲鍒版寚瀹氭爣绛鹃〉 */
  selectTab(tabId: string): void {
    if (tabId !== this.activeTabId) {
      this.activeTabId = tabId;
      this.tabChange.emit(tabId);
    }
  }

  /** 鍏抽棴鏍囩椤?*/
  closeTab(tabId: string, event: MouseEvent): void {
    event.stopPropagation();
    this.tabClose.emit(tabId);
  }

  /** 澶勭悊缂栬緫鍣ㄥ唴瀹瑰彉鏇?*/
  onContentChange(tabId: string, content: string): void {
    this.contentChange.emit({ tabId, content });
  }

  /** 璇锋眰淇濆瓨褰撳墠鏍囩椤?*/
  requestSave(tabId: string): void {
    // 浼樺厛閫氳繃 Electron IPC 淇濆瓨鏂囦欢
    if (this.electronApi && tabId) {
      void this.saveActiveTabToFile(tabId);
      return;
    }
    this.saveRequest.emit(tabId);
  }

  /** 杩愯褰撳墠鏍囩椤电殑浠ｇ爜 */
  runActiveTab(): void {
    if (this.activeTabId) {
      this.showOutput = true;
      this.runRequest.emit(this.activeTabId);
    }
  }

  /** 鑾峰彇褰撳墠婵€娲荤殑鏍囩椤?*/
  getActiveTab(): EditorTab | undefined {
    return this.tabs.find((t) => t.id === this.activeTabId);
  }

  /** 閫氳繃 Electron IPC 灏嗗綋鍓嶆爣绛鹃〉淇濆瓨鍒版湰鍦版枃浠?*/
  private async saveActiveTabToFile(tabId: string): Promise<void> {
    const api = this.electronApi;
    if (!api) return;

    const tab = this.tabs.find((t) => t.id === tabId);
    if (!tab) return;

    try {
      // 宸叉湁鏂囦欢璺緞鍒欑洿鎺ヤ繚瀛橈紝鍚﹀垯寮瑰嚭淇濆瓨瀵硅瘽妗哱n      if (tab.filePath) {
        const result = await api.writeFile(tab.filePath, tab.content);
        if (result.success) {
          this.fileSaved.emit({ tabId, filePath: tab.filePath });
        }
      } else {
        const ext = this.getFileExtension(tab.language);
        const dialogResult = await api.showSaveDialog({
          title: '淇濆瓨鏂囦欢',
          defaultPath: `${tab.title}${ext}`,
          filters: [
            {
              name: '浠ｇ爜鏂囦欢',
              extensions: ['py', 'js', 'ts', 'cpp', 'java', 'html', 'css', 'json'],
            },
            { name: '鎵€鏈夋枃浠?, extensions: ['*'] },
          ],
        });

        if (dialogResult.success && dialogResult.filePath) {
          await api.writeFile(dialogResult.filePath, tab.content);
          this.fileSaved.emit({ tabId, filePath: dialogResult.filePath });
        }
      }
    } catch (error) {
      console.error('[Editor] 淇濆瓨鏂囦欢澶辫触:', error);
    }
  }

  /** 閫氳繃 Electron IPC 浠庢湰鍦版墦寮€鏂囦欢 */
  async openFileFromDisk(): Promise<void> {
    const api = this.electronApi;
    if (!api) {
      this.openFileRequest.emit();
      return;
    }

    try {
      const dialogResult = await api.showOpenDialog();
      if (!dialogResult.success || !dialogResult.filePath) return;

      const fileResult = await api.readFile(dialogResult.filePath);
      if (!fileResult.success || fileResult.content === undefined) return;

      const fileName = dialogResult.filePath.split(/[/\\]/).pop() ?? 'untitled';
      const language = this.guessLanguage(fileName);

      const tab: EditorTab = {
        id: `file_${Date.now()}`,
        title: fileName,
        filePath: dialogResult.filePath,
        content: fileResult.content,
        language,
        isDirty: false,
      };

      this.fileOpened.emit(tab);
    } catch (error) {
      console.error('[Editor] 鎵撳紑鏂囦欢澶辫触:', error);
    }
  }

  /** 鏍规嵁鏂囦欢鍚嶇寽娴嬬紪绋嬭瑷€ */
  private guessLanguage(fileName: string): string {
    const extMap: Record<string, string> = {
      py: 'python',
      js: 'javascript',
      ts: 'typescript',
      cpp: 'cpp',
      java: 'java',
      html: 'html',
      css: 'css',
      json: 'json',
      md: 'markdown',
    };
    const ext = fileName.split('.').pop()?.toLowerCase() ?? '';
    return extMap[ext] ?? 'plaintext';
  }

  /** 鏍规嵁璇█鑾峰彇榛樿鏂囦欢鎵╁睍鍚?*/
  private getFileExtension(language: string): string {
    const extMap: Record<string, string> = {
      python: '.py',
      javascript: '.js',
      typescript: '.ts',
      cpp: '.cpp',
      java: '.java',
      html: '.html',
      css: '.css',
      json: '.json',
      markdown: '.md',
    };
    return extMap[language] ?? '.txt';
  }

  /** 鑾峰彇璇█鏍囩鏄犲皠 */
  getLanguageLabel(lang: string): string {
    const labels: Record<string, string> = {
      python: 'Python',
      javascript: 'JavaScript',
      typescript: 'TypeScript',
      cpp: 'C++',
      java: 'Java',
      html: 'HTML',
      css: 'CSS',
      json: 'JSON',
      markdown: 'Markdown',
    };
    return labels[lang] ?? lang;
  }

  /** 娉ㄥ唽妗岄潰绔敭鐩樺揩鎹烽敭 */
  private registerKeyboardShortcuts(): void {
    this.keydownHandler = (event: KeyboardEvent) => {
      const isCtrlOrCmd = event.ctrlKey || event.metaKey;

      // Ctrl+S / Ctrl+Shift+S 鈫?淇濆瓨
      if (isCtrlOrCmd && event.key === 's') {
        event.preventDefault();
        if (this.activeTabId) {
          this.requestSave(this.activeTabId);
        }
        return;
      }

      // Ctrl+W 鈫?鍏抽棴褰撳墠鏍囩椤礬n      if (isCtrlOrCmd && event.key === 'w') {
        event.preventDefault();
        if (this.activeTabId) {
          this.tabClose.emit(this.activeTabId);
        }
        return;
      }

      // Ctrl+N 鈫?鏂板缓鏍囩椤礬n      if (isCtrlOrCmd && event.key === 'n') {
        event.preventDefault();
        this.newTabRequest.emit();
        return;
      }

      // Ctrl+O 鈫?鎵撳紑鏂囦欢锛圗lectron 浼樺厛锛塡n      if (isCtrlOrCmd && event.key === 'o') {
        event.preventDefault();
        void this.openFileFromDisk();
        return;
      }

      // Ctrl+Enter 鈫?杩愯浠ｇ爜
      if (isCtrlOrCmd && event.key === 'Enter') {
        event.preventDefault();
        this.runActiveTab();
        return;
      }

      // F5 鈫?杩愯浠ｇ爜
      if (event.key === 'F5') {
        event.preventDefault();
        this.runActiveTab();
        return;
      }

      // Ctrl+Tab 鈫?涓嬩竴涓爣绛鹃〉
      if (isCtrlOrCmd && event.key === 'Tab' && !event.shiftKey) {
        event.preventDefault();
        this.switchToNextTab();
        return;
      }

      // Ctrl+Shift+Tab 鈫?涓婁竴涓爣绛鹃〉
      if (isCtrlOrCmd && event.key === 'Tab' && event.shiftKey) {
        event.preventDefault();
        this.switchToPrevTab();
        return;
      }
    };

    document.addEventListener('keydown', this.keydownHandler);
  }

  toggleTheme(): void {
    const themes: Array<'vs-dark' | 'vs' | 'hc-black'> = ['vs-dark', 'vs', 'hc-black'];
    const idx = themes.indexOf(this.editorTheme);
    this.editorTheme = themes[(idx + 1) % themes.length];
    this.themeChange.emit(this.editorTheme);
  }

  /** 鍒囨崲鍒颁笅涓€涓爣绛鹃〉 */
  private switchToNextTab(): void {
    if (this.tabs.length <= 1) return;
    const idx = this.tabs.findIndex((t) => t.id === this.activeTabId);
    const nextIdx = (idx + 1) % this.tabs.length;
    this.selectTab(this.tabs[nextIdx].id);
    this.cdr.markForCheck();
  }

  /** 鍒囨崲鍒颁笂涓€涓爣绛鹃〉 */
  private switchToPrevTab(): void {
    if (this.tabs.length <= 1) return;
    const idx = this.tabs.findIndex((t) => t.id === this.activeTabId);
    const prevIdx = (idx - 1 + this.tabs.length) % this.tabs.length;
    this.selectTab(this.tabs[prevIdx].id);
    this.cdr.markForCheck();
  }

  ngOnDestroy(): void {
    if (this.keydownHandler) {
      document.removeEventListener('keydown', this.keydownHandler);
      this.keydownHandler = null;
    }
  }
}

