export class LearningReportsComponent implements OnInit, OnDestroy {
  private destroy$ = new Subject<void>();

  reports: LearningReport[] = [];
  selectedReport: LearningReport | null = null;
  activeTab = 0;
  profile: StudentLearningProfile | null = null;
  exporting = false;
  error = false;

  currentUser: User | null = null;

  constructor(
    private learningReportsService: LearningReportsService,
    private aiTeacherService: AITeacherService,
    private authService: AuthService,
    private snackBar: MatSnackBar,
    private cdr: ChangeDetectorRef
  ) {}

  ngOnInit(): void {
    this.authService.currentUser$.pipe(takeUntil(this.destroy$)).subscribe((user) => {
      this.currentUser = user;
    });
    this.aiTeacherService.profile$.pipe(takeUntil(this.destroy$)).subscribe((p) => {
      this.profile = p;
    });
    this.loadReports();
  }

  private loadReports(): void {
    this.error = false;
    // 瀛︾敓瑙嗚锛氫笉浼燾hildId锛岃幏鍙栨墍鏈夊彲鐢ㄦ姤鍛奬n    this.learningReportsService
      .getReports({})
      .pipe(takeUntil(this.destroy$))
      .subscribe({
        next: (response) => {
          this.reports = response.data;
          this.selectedReport = this.reports[0] ?? null;
          this.cdr.markForCheck();
        },
        error: () => {
          this.error = true;
          this.cdr.markForCheck();
        },
      });
  }

  onTabChange(index: number): void {
    this.selectedReport = this.reports[index] ?? null;
  }

  exportAsPdf(): void {
    if (!this.selectedReport) return;
    this.exporting = true;

    this.learningReportsService
      .exportReport(this.selectedReport.id, 'pdf')
      .pipe(takeUntil(this.destroy$))
      .subscribe({
        next: (blob) => {
          const url = window.URL.createObjectURL(blob);
          const a = document.createElement('a');
          a.href = url;
          a.download = `瀛︿範鎶ュ憡_${this.selectedReport!.period}.pdf`;
          document.body.appendChild(a);
          a.click();
          document.body.removeChild(a);
          window.URL.revokeObjectURL(url);
          this.exporting = false;
          this.snackBar.open('鉁?PDF瀵煎嚭鎴愬姛', '鍏抽棴', { duration: 3000 });
          this.cdr.markForCheck();
        },
        error: () => {
          // 鏈嶅姟绔鍑哄け璐ワ紝鍥為€€鍒板鎴风鎵撳嵃
          this.exporting = false;
          this.printReport();
          this.cdr.markForCheck();
        },
      });
  }

  /** 瀹㈡埛绔墦鍗?淇濆瓨PDF */
  printReport(): void {
    if (!this.selectedReport) return;
    this.snackBar.open('姝ｅ湪鎵撳紑鎵撳嵃瀵硅瘽妗?..', '鍏抽棴', { duration: 2000 });
    window.print();
  }

  getScoreColor(score: number): string {
    if (score >= 90) return 'primary';
    if (score >= 75) return 'accent';
    return 'warn';
  }

  formatHours(minutes: number): string {
    const h = Math.floor(minutes / 60);
    const m = minutes % 60;
    return m > 0 ? `${h}灏忔椂${m}鍒哷 : `${h}灏忔椂`;
  }

  ngOnDestroy(): void {
    this.destroy$.next();
    this.destroy$.complete();
  }
}

