export class UserProfileComponent implements OnInit, OnDestroy {
  /**
   * 鐢ㄦ埛涓汉璧勬枡
   */
  userProfile: UserProfile | null = null;

  /**
   * 鐢ㄦ埛鍋忓ソ璁剧疆
   */
  userPreferences: UserPreferences = {};

  /**
   * 閫氱煡璁剧疆
   */
  emailNotify = true;
  smsNotify = false;
  pushNotify = true;
  showEmail = false;
  showPhone = false;

  /**
   * 缂栬緫妯″紡
   */
  isEditing = false;

  /**
   * 鍔犺浇鐘舵€乗n   */
  loading = false;

  /**
   * 淇濆瓨涓姸鎬乗n   */
  saving = false;

  /**
   * 閿欒淇℃伅
   */
  error: string | null = null;

  /**
   * 琛ㄥ崟鏁版嵁
   */
  formData: UpdateUserProfileRequest = {};

  /**
   * 缁勪欢閿€姣侀€氱煡
   */
  private destroy$ = new Subject<void>();

  constructor(
    private userProfileService: UserProfileService,
    private snackBar: MatSnackBar,
    private router: Router,
    private dialog: MatDialog
  ) {}

  ngOnInit(): void {
    this.loadUserProfile();
    this.loadUserPreferences();
  }

  ngOnDestroy(): void {
    this.destroy$.next();
    this.destroy$.complete();
  }

  /**
   * 鍔犺浇鐢ㄦ埛涓汉璧勬枡
   */
  loadUserProfile(): void {
    this.loading = true;
    this.error = null;

    this.userProfileService
      .getUserProfile()
      .pipe(
        takeUntil(this.destroy$),
        timeout(10000),
        catchError((err: Error) => {
          if (err instanceof TimeoutError) {
            console.error('鍔犺浇鐢ㄦ埛璧勬枡瓒呮椂');
            return throwError(() => new Error('鍔犺浇瓒呮椂锛岃妫€鏌ョ綉缁滆繛鎺ュ悗閲嶈瘯'));
          }
          return throwError(() => err);
        })
      )
      .subscribe({
        next: (profile) => {
          this.userProfile = profile;
          this.formData = {
            username: profile.username,
            realName: profile.realName,
            phone: profile.phone,
            avatar: profile.avatar,
          };
          this.loading = false;
        },
        error: (error) => {
          this.error = (error as Error).message || '鍔犺浇鐢ㄦ埛璧勬枡澶辫触';
          this.loading = false;
          console.error('鍔犺浇鐢ㄦ埛璧勬枡澶辫触:', error);
        },
      });
  }

  /**
   * 鍔犺浇鐢ㄦ埛鍋忓ソ璁剧疆
   */
  loadUserPreferences(): void {
    this.userProfileService
      .getUserPreferences()
      .pipe(
        takeUntil(this.destroy$),
        timeout(10000),
        catchError((err: Error) => {
          if (err instanceof TimeoutError) {
            console.error('鍔犺浇鐢ㄦ埛鍋忓ソ璁剧疆瓒呮椂');
            return throwError(() => new Error('鍔犺浇瓒呮椂锛屼娇鐢ㄩ粯璁よ缃?));
          }
          return throwError(() => err);
        })
      )
      .subscribe({
        next: (preferences) => {
          this.userPreferences = preferences;
          // 鍚屾閫氱煡鍜岄殣绉佽缃埌鐙珛鍙橀噺
          this.emailNotify = preferences.notifications?.email ?? true;
          this.smsNotify = preferences.notifications?.sms ?? false;
          this.pushNotify = preferences.notifications?.push ?? true;
          this.showEmail = preferences.privacy?.showEmail ?? false;
          this.showPhone = preferences.privacy?.showPhone ?? false;
        },
        error: (error) => {
          console.error('鍔犺浇鐢ㄦ埛鍋忓ソ璁剧疆澶辫触:', error);
          // 浣跨敤榛樿璁剧疆
          this.userPreferences = {
            theme: 'light',
            language: 'zh-CN',
            notifications: {
              email: true,
              sms: false,
              push: true,
            },
            privacy: {
              showEmail: false,
              showPhone: false,
            },
          };
          this.emailNotify = true;
          this.smsNotify = false;
          this.pushNotify = true;
          this.showEmail = false;
          this.showPhone = false;
        },
      });
  }

  /**
   * 杩涘叆缂栬緫妯″紡
   */
  enterEditMode(): void {
    this.isEditing = true;
    this.error = null;

    // 閲嶇疆琛ㄥ崟鏁版嵁涓哄綋鍓嶇敤鎴蜂俊鎭痋n    if (this.userProfile) {
      this.formData = {
        username: this.userProfile.username,
        realName: this.userProfile.realName,
        phone: this.userProfile.phone,
        avatar: this.userProfile.avatar,
      };
    }
  }

  /**
   * 淇濆瓨涓汉璧勬枡
   */
  saveProfile(): void {
    if (!this.formData.username?.trim()) {
      this.error = '鐢ㄦ埛鍚嶄笉鑳戒负绌?;
      return;
    }

    this.saving = true;
    this.error = null;

    this.userProfileService
      .updateUserProfile(this.formData)
      .pipe(takeUntil(this.destroy$))
      .subscribe({
        next: (updatedProfile) => {
          this.userProfile = updatedProfile;
          this.isEditing = false;
          this.saving = false;
          this.snackBar.open('涓汉璧勬枡淇濆瓨鎴愬姛', '鍏抽棴', { duration: 3000 });
        },
        error: (error) => {
          this.error = (error as Error).message;
          this.saving = false;
          console.error('淇濆瓨涓汉璧勬枡澶辫触:', error);
        },
      });
  }

  /**
   * 鍙栨秷缂栬緫
   */
  cancelEdit(): void {
    this.isEditing = false;
    this.error = null;

    // 閲嶇疆琛ㄥ崟鏁版嵁
    if (this.userProfile) {
      this.formData = {
        username: this.userProfile.username,
        realName: this.userProfile.realName,
        phone: this.userProfile.phone,
        avatar: this.userProfile.avatar,
      };
    }
  }

  /**
   * 涓婁紶澶村儚
   * @param event 鏂囦欢閫夋嫨浜嬩欢
   */
  uploadAvatar(event: Event): void {
    const input = event.target as HTMLInputElement;

    if (input.files?.[0]) {
      const file = input.files[0];

      // 楠岃瘉鏂囦欢绫诲瀷
      if (!file.type.startsWith('image/')) {
        this.error = '璇烽€夋嫨鍥剧墖鏂囦欢';
        return;
      }

      // 楠岃瘉鏂囦欢澶у皬锛堟渶澶?5MB锛塡n      if (file.size > 5 * 1024 * 1024) {
        this.error = '鍥剧墖鏂囦欢澶у皬涓嶈兘瓒呰繃 5MB';
        return;
      }

      // 鎵撳紑瑁佸壀瀵硅瘽妗哱n      const dialogRef = this.dialog.open(AvatarCropDialogComponent, {
        data: {
          imageFile: file,
          aspectRatio: 1, // 姝ｆ柟褰㈣鍓猏n          canvasRotation: 0,
        },
        disableClose: true,
        panelClass: 'crop-dialog-panel',
      });

      dialogRef.afterClosed().subscribe((result: CropDialogResult) => {
        if (result?.croppedImageFile) {
          // 涓婁紶瑁佸壀鍚庣殑鍥剧墖
          this.saving = true;
          this.error = null;

          this.userProfileService
            .uploadAvatarWithCrop(result.croppedImageFile)
            .pipe(takeUntil(this.destroy$))
            .subscribe({
              next: (response) => {
                this.formData.avatar = response.avatarUrl;

                // 鍚屾椂鏇存柊鐢ㄦ埛璧勬枡
                return this.userProfileService
                  .updateUserProfile({ avatar: response.avatarUrl })
                  .pipe(takeUntil(this.destroy$));
              },
              complete: () => {
                if (this.userProfile) {
                  this.userProfile = { ...this.userProfile, avatar: this.formData.avatar };
                }
                this.saving = false;
                this.snackBar.open('澶村儚鏇存柊鎴愬姛', '鍏抽棴', { duration: 3000 });
              },
              error: (error: any) => {
                this.error = (error as Error).message || '涓婁紶澶辫触';
                this.saving = false;
                console.error('涓婁紶澶村儚澶辫触:', error);
              },
            });
        }
      });
    }
  }

  /**
   * 淇濆瓨鍋忓ソ璁剧疆
   */
  savePreferences(): void {
    this.saving = true;

    // 浠庣嫭绔嬪彉閲忓悓姝ュ埌鐢ㄦ埛鍋忓ソ璁剧疆
    this.userPreferences = {
      ...this.userPreferences,
      notifications: {
        email: this.emailNotify,
        sms: this.smsNotify,
        push: this.pushNotify,
      },
      privacy: {
        showEmail: this.showEmail,
        showPhone: this.showPhone,
      },
    };

    this.userProfileService
      .updateUserPreferences(this.userPreferences)
      .pipe(takeUntil(this.destroy$))
      .subscribe({
        next: () => {
          this.saving = false;
          this.snackBar.open('鍋忓ソ璁剧疆淇濆瓨鎴愬姛', '鍏抽棴', { duration: 3000 });
        },
