  /**
   * 閿欒澶勭悊
   * @param error HTTP 閿欒鍝嶅簲
   */
  private handleError = (error: unknown): Observable<never> => {
    const httpError = error as { error?: ErrorEvent | { message?: string }; status?: number };
    let errorMessage = '鎿嶄綔澶辫触';

    if (httpError.error instanceof ErrorEvent) {
      errorMessage = `瀹㈡埛绔敊璇? ${httpError.error.message}`;
    } else {
      if (httpError.status === 400) {
        errorMessage = httpError.error?.message ?? '璇锋眰鍙傛暟閿欒';
      } else if (httpError.status === 401) {
        errorMessage = '鏈巿鏉冿紝璇烽噸鏂扮櫥褰?;
      } else if (httpError.status === 403) {
        errorMessage = '鏃犳潈鏌ョ湅姝ゆ姤鍛?;
      } else if (httpError.status === 404) {
        errorMessage = '瀛︿範鎶ュ憡涓嶅瓨鍦?;
      } else if (httpError.status === 422) {
        errorMessage = httpError.error?.message ?? '鏁版嵁楠岃瘉澶辫触';
      } else if (httpError.status === 500) {
        errorMessage = '鏈嶅姟鍣ㄩ敊璇紝璇风◢鍚庨噸璇?;
      } else {
        errorMessage = httpError.error?.message ?? `閿欒鐮? ${httpError.status}`;
      }
    }

    console.error('LearningReportsService Error:', error);
    return throwError(() => new Error(errorMessage));
  };
