    // 璁㈤槄璁よ瘉鏈嶅姟涓殑鐢ㄦ埛鐘舵€乗n    this.authService.currentUser$.subscribe((user) => {
      this.currentUserSubject.next(user);
    });
  }

  /**
   * 鑾峰彇褰撳墠鐢ㄦ埛淇℃伅
