/**
 * 鐢ㄦ埛涓汉璧勬枡鏈嶅姟
 *
 * 鎻愪緵鐢ㄦ埛涓汉璧勬枡鐩稿叧鐨?HTTP 璇锋眰鏈嶅姟锛屽寘鎷細
 * - 鐢ㄦ埛淇℃伅鑾峰彇
 * - 鐢ㄦ埛淇℃伅鏇存柊
 * - 瀵嗙爜淇敼
 * - 鐢ㄦ埛鍋忓ソ璁剧疆
 *
 * @author iMatu Development Team
 * @version 1.0.0
 */

import { HttpClient } from '@angular/common/http';
import { Injectable } from '@angular/core';
import { delay, Observable, of, throwError } from 'rxjs';
import { catchError } from 'rxjs/operators';

import { UserProfile, UserType, UserTypeGroup } from '../../core/models/group.models';

/**
 * 鏄惁浣跨敤妯℃嫙鏁版嵁
 */
const USE_MOCK_DATA = true;

/**
 * 鐢ㄦ埛涓汉璧勬枡鏇存柊璇锋眰
 */
export interface UpdateUserProfileRequest {
  /** 鐢ㄦ埛鍚?*/
  username?: string;
  /** 鐪熷疄濮撳悕 */
  realName?: string;
  /** 鎵嬫満鍙?*/
  phone?: string;
  /** 澶村儚 URL */
  avatar?: string;
  /** 涓汉绠€浠?*/
  bio?: string;
}

/**
 * 淇敼瀵嗙爜璇锋眰
 */
export interface ChangePasswordRequest {
  /** 褰撳墠瀵嗙爜 */
  currentPassword: string;
  /** 鏂板瘑鐮?*/
  newPassword: string;
  /** 纭鏂板瘑鐮?*/
  confirmPassword: string;
}

/**
 * 鐢ㄦ埛鍋忓ソ璁剧疆
 */
export interface UserPreferences {
  /** 涓婚璁剧疆: light | dark | auto */
  theme?: string;
  /** 璇█璁剧疆: zh-CN | en-US */
  language?: string;
  /** 閫氱煡璁剧疆 */
  notifications?: {
    email?: boolean;
    sms?: boolean;
    push?: boolean;
  };
  /** 闅愮璁剧疆 */
  privacy?: {
    showEmail?: boolean;
    showPhone?: boolean;
  };
}

/**
 * 鐢ㄦ埛涓汉璧勬枡鏈嶅姟
 */
@Injectable({
  providedIn: 'root',
})
export class UserProfileService {
  private readonly API_BASE_URL = '/api/user/profile';

  constructor(private http: HttpClient) {}

  /**
   * 鑾峰彇褰撳墠鐢ㄦ埛涓汉璧勬枡
   */
  getUserProfile(): Observable<UserProfile> {
    if (USE_MOCK_DATA) {
      const mockProfile: UserProfile = {
        id: 'user001',
        username: 'parent_demo',
        email: 'parent@imato.com',
        realName: '寮犲闀?,
        phone: '138****8888',
        avatar: '/assets/images/default-avatar.png',
        createdAt: new Date('2024-01-15T10:00:00'),
        updatedAt: new Date('2025-03-18T16:30:00'),
        userType: UserType.STUDENT,
        userTypeGroup: UserTypeGroup.PERSONAL,
      };
      return of(mockProfile).pipe(delay(400));
    }
    return this.http
      .get<UserProfile>(`${this.API_BASE_URL}`)
      .pipe(catchError(this.handleError.bind(this)));
  }

  /**
   * 鏇存柊鐢ㄦ埛涓汉璧勬枡
   * @param profileData 鏇存柊鐨勮祫鏂欐暟鎹甛n   */
  updateUserProfile(profileData: UpdateUserProfileRequest): Observable<UserProfile> {
    if (USE_MOCK_DATA) {
      const updatedProfile: UserProfile = {
        id: 'user001',
        username: profileData.username ?? 'parent_demo',
        email: 'parent@imato.com',
        realName: profileData.realName ?? '寮犲闀?,
        phone: profileData.phone ?? '138****8888',
        avatar: profileData.avatar ?? '/assets/images/default-avatar.png',
        createdAt: new Date('2024-01-15T10:00:00'),
        updatedAt: new Date(),
        userType: UserType.STUDENT,
        userTypeGroup: UserTypeGroup.PERSONAL,
      };
      return of(updatedProfile).pipe(delay(600));
    }
    return this.http
      .put<UserProfile>(`${this.API_BASE_URL}`, profileData)
      .pipe(catchError(this.handleError.bind(this)));
  }

  /**
   * 淇敼鐢ㄦ埛瀵嗙爜
   * @param passwordData 瀵嗙爜鏁版嵁
   */
  changePassword(passwordData: ChangePasswordRequest): Observable<{ message: string }> {
    if (USE_MOCK_DATA) {
      if (passwordData.newPassword !== passwordData.confirmPassword) {
        return throwError(() => new Error('涓ゆ杈撳叆鐨勫瘑鐮佷笉涓€鑷?));
      }
      if (passwordData.currentPassword === passwordData.newPassword) {
        return throwError(() => new Error('鏂板瘑鐮佷笉鑳戒笌褰撳墠瀵嗙爜鐩稿悓'));
      }
      return of({ message: '瀵嗙爜淇敼鎴愬姛锛岃閲嶆柊鐧诲綍' }).pipe(delay(800));
    }
    return this.http
      .post<{ message: string }>(`${this.API_BASE_URL}/change-password`, passwordData)
      .pipe(catchError(this.handleError.bind(this)));
  }

  /**
   * 涓婁紶鐢ㄦ埛澶村儚
   * @param file 鍥剧墖鏂囦欢
   */
  uploadAvatar(file: File): Observable<{ avatarUrl: string }> {
    if (USE_MOCK_DATA) {
      const mockAvatarUrl = `/assets/uploaded-avatar-${Date.now()}.png`;
      return of({ avatarUrl: mockAvatarUrl }).pipe(delay(1000));
    }
    const formData = new FormData();
    formData.append('avatar', file);

    return this.http
      .post<{ avatarUrl: string }>(`${this.API_BASE_URL}/avatar`, formData)
      .pipe(catchError(this.handleError.bind(this)));
  }

  /**
   * 涓婁紶瑁佸壀鍚庣殑澶村儚
   * @param file 瑁佸壀鍚庣殑鍥剧墖鏂囦欢
   * @param cropData 瑁佸壀鍙傛暟 (鍙€?
   */
  uploadAvatarWithCrop(
    file: File,
    cropData?: Record<string, unknown>
  ): Observable<{ avatarUrl: string }> {
    if (USE_MOCK_DATA) {
      const mockAvatarUrl = `/assets/uploaded-avatar-cropped-${Date.now()}.png`;
      return of({ avatarUrl: mockAvatarUrl }).pipe(delay(1500));
    }

    const formData = new FormData();
    formData.append('avatar', file);

    if (cropData) {
      formData.append('crop_data', JSON.stringify(cropData));
    }

    return this.http
      .post<{ avatarUrl: string }>(`${this.API_BASE_URL}/avatar/crop`, formData)
      .pipe(catchError(this.handleError.bind(this)));
  }

  /**
   * 鑾峰彇澶村儚涓婁紶 URL(鐢ㄤ簬鐩存帴涓婁紶鍒?CDN)
   */
  getAvatarUploadUrl(): Observable<{ uploadUrl: string; fields?: Record<string, unknown> }> {
    if (USE_MOCK_DATA) {
      return of({
        uploadUrl: `https://cdn.imato.com/avatars/upload/${Date.now()}`,
        fields: {},
      }).pipe(delay(500));
    }

    return this.http
      .get<{
        uploadUrl: string;
        fields?: Record<string, unknown>;
      }>(`${this.API_BASE_URL}/avatar/upload-url`)
      .pipe(catchError(this.handleError.bind(this)));
  }

  /**
   * 鑾峰彇鐢ㄦ埛鍋忓ソ璁剧疆
   */
  getUserPreferences(): Observable<UserPreferences> {
    if (USE_MOCK_DATA) {
      const mockPreferences: UserPreferences = {
        theme: 'light',
        language: 'zh-CN',
        notifications: {
          email: true,
          sms: false,
          push: true,
        },
        privacy: {
          showEmail: false,
          showPhone: false,
        },
      };
      return of(mockPreferences).pipe(delay(100));
    }
    return this.http
      .get<UserPreferences>(`${this.API_BASE_URL}/preferences`)
      .pipe(catchError(this.handleError.bind(this)));
  }

  /**
   * 鏇存柊鐢ㄦ埛鍋忓ソ璁剧疆
   * @param preferences 鍋忓ソ璁剧疆
   */
  updateUserPreferences(preferences: UserPreferences): Observable<UserPreferences> {
    if (USE_MOCK_DATA) {
      return of(preferences).pipe(delay(500));
    }
    return this.http
      .put<UserPreferences>(`${this.API_BASE_URL}/preferences`, preferences)
      .pipe(catchError(this.handleError.bind(this)));
  }

  /**
   * 閿欒澶勭悊
   * @param error HTTP 閿欒鍝嶅簲
   */
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  private handleError(error: any): Observable<never> {
    let errorMessage = '鎿嶄綔澶辫触';

    // eslint-disable-next-line @typescript-eslint/no-unsafe-member-access
    if (error.error instanceof ErrorEvent) {
      // 瀹㈡埛绔敊璇痋n      // eslint-disable-next-line @typescript-eslint/no-unsafe-member-access
      errorMessage = `瀹㈡埛绔敊璇細${error.error.message}`;
    } else {
      // 鏈嶅姟绔敊璇痋n      // eslint-disable-next-line @typescript-eslint/no-unsafe-member-access
      if (error.status === 400) {
        // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment, @typescript-eslint/no-unsafe-member-access
        errorMessage = error.error?.message || '璇锋眰鍙傛暟閿欒';
        // eslint-disable-next-line @typescript-eslint/no-unsafe-member-access
      } else if (error.status === 401) {
        errorMessage = '鏈巿鏉冿紝璇烽噸鏂扮櫥褰?;
        // eslint-disable-next-line @typescript-eslint/no-unsafe-member-access
      } else if (error.status === 403) {
        errorMessage = '鏃犳潈鎵ц姝ゆ搷浣?;
        // eslint-disable-next-line @typescript-eslint/no-unsafe-member-access
      } else if (error.status === 404) {
        errorMessage = '鐢ㄦ埛璧勬枡涓嶅瓨鍦?;
        // eslint-disable-next-line @typescript-eslint/no-unsafe-member-access
      } else if (error.status === 409) {
        // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment, @typescript-eslint/no-unsafe-member-access
        errorMessage = error.error?.message || '鏁版嵁鍐茬獊';
        // eslint-disable-next-line @typescript-eslint/no-unsafe-member-access
      } else if (error.status === 500) {
        errorMessage = '鏈嶅姟鍣ㄩ敊璇紝璇风◢鍚庨噸璇?;
      } else {
        // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment, @typescript-eslint/no-unsafe-member-access
        errorMessage = error.error?.message || `閿欒鐮侊細${error.status}`;
      }
    }

    console.error('UserProfileService Error:', error);
    return throwError(() => new Error(errorMessage));
  }
}
